    def setup_error_logging(self):
        """Richtet ein dauerhaftes, größenbegrenztes Anwendungsprotokoll ein."""
        self.logger = logging.getLogger(
            f"film_browser.{id(self)}"
        )
        self.logger.setLevel(logging.INFO)
        self.logger.propagate = False
        for handler in list(self.logger.handlers):
            self.logger.removeHandler(handler)
            try:
                handler.close()
            except OSError:
                pass

        handler = RotatingFileHandler(
            self.error_log_file,
            maxBytes=5 * 1024 * 1024,
            backupCount=5,
            encoding="utf-8",
        )
        handler.setFormatter(
            logging.Formatter(
                "%(asctime)s | %(levelname)s | %(threadName)s | %(message)s"
            )
        )
        self.logger.addHandler(handler)
        self.logger.info(
            "%s %s gestartet | Python %s | PID %s",
            APP_NAME,
            APP_VERSION,
            sys.version.split()[0],
            os.getpid(),
        )

    def install_exception_hooks(self):
        """Protokolliert unbehandelte Fehler im Haupt- und in Neben-Threads."""
        self._original_sys_excepthook = sys.excepthook
        self._original_threading_excepthook = getattr(
            threading, "excepthook", None
        )

        def main_hook(exc_type, exc_value, exc_traceback):
            if issubclass(exc_type, KeyboardInterrupt):
                self._original_sys_excepthook(
                    exc_type, exc_value, exc_traceback
                )
                return
            self.logger.critical(
                "Unbehandelter Fehler im Hauptthread\n%s",
                "".join(
                    __import__("traceback").format_exception(
                        exc_type, exc_value, exc_traceback
                    )
                ).rstrip(),
            )

        def thread_hook(args):
            if args.exc_type is SystemExit:
                return
            self.logger.critical(
                "Unbehandelter Fehler im Thread %s\n%s",
                getattr(args.thread, "name", "unbekannt"),
                "".join(
                    __import__("traceback").format_exception(
                        args.exc_type,
                        args.exc_value,
                        args.exc_traceback,
                    )
                ).rstrip(),
            )

        sys.excepthook = main_hook
        if hasattr(threading, "excepthook"):
            threading.excepthook = thread_hook

    def log_error(self, context, exc=None, *, level=logging.ERROR, details=None):
        """Schreibt einen Fehler mit Kontext und optionalem Traceback."""
        message = str(context)
        if details:
            message += f" | {details}"
        if exc is None:
            self.logger.log(level, message)
            return
        self.logger.log(
            level,
            "%s | %s: %s",
            message,
            type(exc).__name__,
            exc,
            exc_info=(type(exc), exc, exc.__traceback__),
        )

    def log_current_exception(self, context, *, level=logging.ERROR):
        """Protokolliert den gerade behandelten Fehler eines except-Blocks."""
        exc = sys.exc_info()[1]
        self.log_error(context, exc, level=level)

    @staticmethod
    def protect_private_file(path):
        """Setzt für sensible Benutzerdateien nach Möglichkeit Modus 0600."""
        try:
            Path(path).chmod(0o600)
        except OSError:
            pass

    @staticmethod
    def sanitize_url_for_log(url):
        """Entfernt Zugangsdaten aus URLs, bevor sie protokolliert werden."""
        try:
            parsed = urllib.parse.urlsplit(str(url))
            query = urllib.parse.parse_qsl(
                parsed.query, keep_blank_values=True
            )
            hidden = {
                "api_key", "apikey", "token", "access_token",
                "read_token", "key",
            }
            safe_query = [
                (name, "***" if name.lower() in hidden else value)
                for name, value in query
            ]
            return urllib.parse.urlunsplit(
                (
                    parsed.scheme,
                    parsed.netloc,
                    parsed.path,
                    urllib.parse.urlencode(safe_query),
                    parsed.fragment,
                )
            )
        except (TypeError, ValueError):
            return "<ungültige URL>"

    def package_resource_candidates(self, relative_path):
        """Liefert Ressourcenpfade für Skript, DEB und AppImage."""
        relative_path = Path(relative_path)
        candidates = [
            self.program_dir / relative_path,
            self.program_dir / "assets" / relative_path,
            self.program_dir / "resources" / relative_path,
        ]

        appdir_text = os.environ.get("APPDIR", "").strip()
        if appdir_text:
            appdir = Path(appdir_text).expanduser()
            candidates.extend([
                appdir / "usr" / "share" / APP_SLUG / relative_path,
                appdir / "usr" / "share" / "icons" / "hicolor"
                / "256x256" / "apps" / relative_path.name,
            ])

        candidates.extend([
            Path("/usr/share") / APP_SLUG / relative_path,
            Path("/usr/local/share") / APP_SLUG / relative_path,
            Path("/usr/share/icons/hicolor/256x256/apps")
            / relative_path.name,
            Path("/usr/local/share/icons/hicolor/256x256/apps")
            / relative_path.name,
            Path("/usr/share/pixmaps") / relative_path.name,
        ])

        result = []
        seen = set()
        for candidate in candidates:
            text = str(candidate)
            if text not in seen:
                seen.add(text)
                result.append(candidate)
        return result

    def embedded_program_icon_pixbuf(self, size=None):
        """Lädt das im Quellcode eingebettete Carbor-Icon."""
        try:
            raw = base64.b64decode(APP_ICON_PNG_BASE64)
            loader = GdkPixbuf.PixbufLoader.new_with_type("png")
            loader.write(raw)
            loader.close()
            pixbuf = loader.get_pixbuf()
            if pixbuf is not None and size:
                pixbuf = pixbuf.scale_simple(
                    int(size), int(size), GdkPixbuf.InterpType.BILINEAR
                )
            return pixbuf
        except (ValueError, TypeError, GLib.Error):
            return None

    def program_icon_pixbuf(self, size=None):
        """Liefert das Paketicon oder den eingebetteten Fallback."""
        if self.program_icon_path and self.program_icon_path.exists():
            try:
                if size:
                    return GdkPixbuf.Pixbuf.new_from_file_at_scale(
                        str(self.program_icon_path), int(size), int(size), True
                    )
                return GdkPixbuf.Pixbuf.new_from_file(
                    str(self.program_icon_path)
                )
            except (OSError, GLib.Error):
                pass
        return self.embedded_program_icon_pixbuf(size)

    def set_program_icon(self):
        """Lädt das Carbor-Symbol für Fenster, Panel und Paketstarter."""
        candidates = self.package_resource_candidates(f"{APP_SLUG}.png")
        # Alte Entwicklungsnamen bleiben als Fallback lesbar.
        candidates.extend([
            self.program_dir / "Carbor-Icon.png",
            self.program_dir / "Film-Browser-Icon.png",
            self.program_dir / "film-browser.png",
            self.program_dir / "film_browser.png",
            self.program_dir / "icon.png",
        ])

        for icon_path in candidates:
            if not icon_path.is_file():
                continue
            try:
                self.set_icon_from_file(str(icon_path))
                Gtk.Window.set_default_icon_from_file(str(icon_path))
                self.program_icon_path = icon_path
                return
            except (GLib.Error, OSError):
                continue

        # Selbst bei einer einzeln kopierten Python-Datei bleibt das Icon
        # sichtbar, weil eine kompakte PNG-Fassung im Quellcode eingebettet ist.
        embedded = self.embedded_program_icon_pixbuf()
        if embedded is not None:
            try:
                self.set_icon(embedded)
                Gtk.Window.set_default_icon(embedded)
                return
            except (AttributeError, TypeError):
                pass

        # Nach einer DEB-/AppImage-Installation kann GTK das Symbol zusätzlich
        # über den Icon-Theme-Namen finden.
        try:
            Gtk.Window.set_default_icon_name(APP_SLUG)
            self.set_icon_name(APP_SLUG)
        except (AttributeError, TypeError):
            self.set_icon_name("video-x-generic")


    # ------------------------------------------------------------------
    # Konfiguration und Index
    # ------------------------------------------------------------------

    def migrate_legacy_index(self):
        """Übernimmt den alten Index einmalig aus ~/.cache in den Datenordner."""
        if self.index_file.exists() or not self.legacy_index_file.exists():
            return
        try:
            shutil.copy2(self.legacy_index_file, self.index_file)
            self.protect_private_file(self.index_file)
        except OSError:
            pass

    def migrate_legacy_defective_media_file(self):
        """Übernimmt eine alte Defektliste aus dem früheren Programmordner."""
        if self.defective_media_file.exists():
            return
        if not self.legacy_defective_media_file.is_file():
            return
        try:
            shutil.copy2(
                self.legacy_defective_media_file,
                self.defective_media_file,
            )
            self.protect_private_file(self.defective_media_file)
        except OSError as exc:
            self.log_error(
                "Alte Defektliste konnte nicht übernommen werden",
                exc,
                details=str(self.legacy_defective_media_file),
            )

