    def default_playlist_export_name(self, name, extension):
        """Erzeugt nur für einen bewussten Export einen sicheren Dateinamen."""
        safe_name = re.sub(r'[\\/:*?"<>|]+', "_", str(name).strip()).strip(". ")
        return f"{safe_name or 'Playlist'}.{extension}"

    def export_playlist(self, name, target, export_format):
        """Exportiert eine interne Playlist auf ausdrücklichen Benutzerwunsch."""
        paths = [Path(path) for path in self.playlists.get(name, [])]
        try:
            target = Path(target)
            target.parent.mkdir(parents=True, exist_ok=True)
            temp = target.with_suffix(target.suffix + ".tmp")
            if export_format == "xspf":
                namespace = "http://xspf.org/ns/0/"
                ET.register_namespace("", namespace)
                root = ET.Element(f"{{{namespace}}}playlist", {"version": "1"})
                ET.SubElement(root, f"{{{namespace}}}title").text = name
                track_list = ET.SubElement(root, f"{{{namespace}}}trackList")
                for path in paths:
                    track = ET.SubElement(track_list, f"{{{namespace}}}track")
                    ET.SubElement(track, f"{{{namespace}}}location").text = path.resolve().as_uri()
                    ET.SubElement(track, f"{{{namespace}}}title").text = self.pretty_title(path)
                ET.ElementTree(root).write(temp, encoding="utf-8", xml_declaration=True)
            elif export_format == "m3u8":
                lines = ["#EXTM3U"]
                for path in paths:
                    duration = int(float(self.technical_for_path(path).get("duration_seconds") or -1))
                    lines.append(f"#EXTINF:{duration},{self.pretty_title(path)}")
                    lines.append(str(path))
                temp.write_text("\n".join(lines) + "\n", encoding="utf-8")
            else:
                raise ValueError(f"Unbekanntes Exportformat: {export_format}")
            temp.replace(target)
            self.logger.info("Playlist exportiert | %s | %s | %s", name, export_format, target)
            return True
        except (OSError, ValueError, TypeError) as exc:
            self.log_error("Playlist konnte nicht exportiert werden", exc, details=f"{name} | {target}")
            self.show_error(f"Playlist konnte nicht exportiert werden:\n{exc}")
            return False

    def on_playlist_export_clicked(self, _button):
        name = self.current_playlist_name()
        if not name:
            self.show_error("Bitte zuerst eine Playlist auswählen.")
            return
        dialog = Gtk.FileChooserDialog(
            title="Playlist exportieren",
            transient_for=self,
            action=Gtk.FileChooserAction.SAVE,
        )
        dialog.add_buttons(Gtk.STOCK_CANCEL, Gtk.ResponseType.CANCEL, "Exportieren", Gtk.ResponseType.OK)
        dialog.set_do_overwrite_confirmation(True)
        default_dir = self.playlist_export_dir
        try:
            default_dir.mkdir(parents=True, exist_ok=True)
            dialog.set_current_folder(str(default_dir))
        except OSError as exc:
            self.logger.warning(
                "Playlist-Exportordner nicht verfügbar | %s | %s",
                default_dir,
                exc,
            )
        extra = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL, spacing=8)
        extra.pack_start(Gtk.Label(label="Format:"), False, False, 0)
        format_combo = Gtk.ComboBoxText()
        format_combo.append("xspf", "XSPF – VLC/XML")
        format_combo.append("m3u8", "M3U8 – universell")
        format_combo.set_active_id("xspf")
        extra.pack_start(format_combo, False, False, 0)
        extra.show_all()
        dialog.set_extra_widget(extra)
        dialog.set_current_name(self.default_playlist_export_name(name, "xspf"))

        response = dialog.run()
        if response == Gtk.ResponseType.OK:
            export_format = format_combo.get_active_id() or "xspf"
            target = Path(dialog.get_filename())
            suffix = f".{export_format}"
            if target.suffix.lower() not in {".xspf", ".m3u8"}:
                target = target.with_suffix(suffix)
            elif target.suffix.lower() != suffix:
                target = target.with_suffix(suffix)
            if self.export_playlist(name, target, export_format):
                self.playlist_export_dir = target.parent
                self.save_config()
                self.status_label.set_text(f"Playlist exportiert: {target}")
        dialog.destroy()

    def current_playlist_name(self):
        model, tree_iter = self.playlist_list_view.get_selection().get_selected()
        return str(model[tree_iter][0]) if tree_iter is not None else self.active_playlist_name

    def refresh_playlist_workspace(self, select_name=None):
        """Baut die sichtbare Playlist-Liste ohne rekursive GTK-Signale neu auf."""
        if not hasattr(self, "playlist_list_store"):
            return
        query = (
            self.playlist_search_entry.get_text().strip().casefold()
            if hasattr(self, "playlist_search_entry") else ""
        )
        selected = select_name or self.active_playlist_name
        selection = self.playlist_list_view.get_selection()
        handler_id = getattr(self, "playlist_selection_handler_id", None)

        if handler_id is not None:
            selection.handler_block(handler_id)
        try:
            self.playlist_list_store.clear()
            select_path = None
            for name in sorted(self.playlists, key=str.casefold):
                if query and query not in name.casefold():
                    continue
                row = self.playlist_list_store.append([
                    name, len(self.playlists.get(name, []))
                ])
                if name == selected:
                    select_path = self.playlist_list_store.get_path(row)

            if select_path is not None:
                selection.select_path(select_path)
                self.active_playlist_name = selected
                self.playlist_list_view.scroll_to_cell(
                    select_path, None, False, 0, 0
                )
            elif len(self.playlist_list_store):
                selection.select_path(0)
                model, tree_iter = selection.get_selected()
                self.active_playlist_name = (
                    str(model[tree_iter][0]) if tree_iter is not None else None
                )
            else:
                self.active_playlist_name = None
        finally:
            if handler_id is not None:
                selection.handler_unblock(handler_id)

        self.refresh_playlist_tracks()

    def on_playlist_search_changed(self, _entry):
        self.refresh_playlist_workspace(select_name=self.active_playlist_name)

    def on_playlist_list_selection_changed(self, selection):
        model, tree_iter = selection.get_selected()
        new_name = str(model[tree_iter][0]) if tree_iter is not None else None
        if new_name == self.active_playlist_name:
            return
        self.playlist_checked_paths.clear()
        self.active_playlist_name = new_name
        self.refresh_playlist_tracks()

    def on_playlist_track_search_changed(self, _entry):
        self.refresh_playlist_tracks()

    def on_playlist_track_sort_changed(self, combo):
        self.playlist_track_sort_mode = (
            combo.get_active_text() or "Manuelle Reihenfolge"
        )
        self.refresh_playlist_tracks()

    def playlist_track_query(self):
        if not hasattr(self, "playlist_track_search_entry"):
            return ""
        return self.playlist_track_search_entry.get_text().strip().casefold()

    def playlist_manual_order_active(self):
        return (
            self.playlist_track_sort_mode == "Manuelle Reihenfolge"
            and not self.playlist_track_query()
        )

    def refresh_playlist_tracks(self):
        """Aktualisiert die Playlist-Ansicht, ohne die interne Reihenfolge zu verändern."""
        if not hasattr(self, "playlist_track_store"):
            return

        rows_handler = getattr(self, "playlist_rows_reordered_handler_id", None)
        if rows_handler is not None:
            self.playlist_track_store.handler_block(rows_handler)
        try:
            self.playlist_track_store.clear()
            name = self.active_playlist_name
            total_duration = 0.0
            rows = []
            query = self.playlist_track_query()

            for position, path_text in enumerate(
                self.playlists.get(name, []) if name else [], start=1
            ):
                path = Path(path_text)
                title = self.pretty_title(path)
                if query and query not in title.casefold() and query not in str(path).casefold():
                    continue
                technical = self.technical_for_path(path)
                duration = float(technical.get("duration_seconds") or 0)
                total_duration += duration
                personal = self.personal_for_path(path)
                last_position = float(personal.get("last_position_seconds") or 0)
                progress = (
                    int(min(100, max(0, round((last_position / duration) * 100))))
                    if duration > 0 else 0
                )
                rows.append([
                    position,
                    str(path),
                    title,
                    self.seconds_to_readable_duration(duration) if duration > 0 else "–",
                    progress,
                    duration,
                    str(path) in self.playlist_checked_paths,
                ])

            mode = self.playlist_track_sort_mode
            if mode == "Titel A–Z":
                rows.sort(key=lambda row: row[2].casefold())
            elif mode == "Titel Z–A":
                rows.sort(key=lambda row: row[2].casefold(), reverse=True)
            elif mode == "Fortschritt absteigend":
                rows.sort(key=lambda row: (row[4], row[2].casefold()), reverse=True)
            elif mode == "Laufzeit absteigend":
                rows.sort(key=lambda row: (row[5], row[2].casefold()), reverse=True)

            for row in rows:
                self.playlist_track_store.append(row)

            self.playlist_track_view.set_reorderable(
                self.playlist_manual_order_active()
            )
            title = f"Inhalt: {name}" if name else "Inhalt der Playlist"
            self.playlist_content_heading.set_markup(
                f"<b>{GLib.markup_escape_text(title)}</b>"
            )
            current_paths = set(self.playlists.get(name, [])) if name else set()
            self.playlist_checked_paths.intersection_update(current_paths)

            count = len(current_paths)
            visible_count = len(rows)
            checked_count = len(self.playlist_checked_paths)
            summary = f"{count} Einträge"
            if checked_count:
                summary += f" · {checked_count} ausgewählt"
            if query or mode != "Manuelle Reihenfolge":
                summary += f" · {visible_count} sichtbar"
            if total_duration > 0:
                summary += (
                    f" · Gesamtlaufzeit "
                    f"{self.seconds_to_readable_duration(total_duration)}"
                )
            if mode != "Manuelle Reihenfolge":
                summary += " · Ansichtssortierung verändert die Playlist nicht"
            elif query:
                summary += " · Verschieben während der Suche deaktiviert"
            self.playlist_summary_label.set_text(
                summary if name else "Keine Playlist ausgewählt"
            )
            self.update_playlist_detail(None)
        finally:
            if rows_handler is not None:
                self.playlist_track_store.handler_unblock(rows_handler)

    def on_playlist_check_toggled(self, _renderer, tree_path_text):
        """Schaltet die sichtbare Checkbox eines Playlist-Eintrags um."""
        tree_path = Gtk.TreePath.new_from_string(tree_path_text)
        tree_iter = self.playlist_track_store.get_iter(tree_path)
        path_text = str(self.playlist_track_store[tree_iter][1])
        active = bool(self.playlist_track_store[tree_iter][6])

        if active:
            self.playlist_checked_paths.discard(path_text)
        else:
            self.playlist_checked_paths.add(path_text)

        self.playlist_track_store[tree_iter][6] = not active
        self.refresh_playlist_summary_only()

    def refresh_playlist_summary_only(self):
        """Aktualisiert die Kurzinfo, ohne die Playlist-Liste neu aufzubauen."""
        name = self.active_playlist_name
        if not name:
            self.playlist_summary_label.set_text("Keine Playlist ausgewählt")
            return
        count = len(self.playlists.get(name, []))
        checked_count = len(self.playlist_checked_paths)
        summary = f"{count} Einträge"
        if checked_count:
            summary += f" · {checked_count} ausgewählt"
        if self.playlist_track_query() or self.playlist_track_sort_mode != "Manuelle Reihenfolge":
            summary += f" · {len(self.playlist_track_store)} sichtbar"
        self.playlist_summary_label.set_text(summary)

    def selected_playlist_track_paths(self):
        """Liefert Checkbox-Auswahl, ersatzweise die normale GTK-Zeilenauswahl."""
        if self.playlist_checked_paths:
            return [
                path for path in self.playlists.get(self.active_playlist_name, [])
                if path in self.playlist_checked_paths
            ]
        model, paths = self.playlist_track_view.get_selection().get_selected_rows()
        return [str(model[path][1]) for path in paths]

    def on_playlist_track_selection_changed(self, selection):
        model, paths = selection.get_selected_rows()
        path = Path(str(model[paths[0]][1])) if len(paths) == 1 else None
        self.update_playlist_detail(path)

    def update_playlist_detail(self, video_path):
        if not video_path:
            self.playlist_detail_image.clear()
            self.playlist_detail_label.set_text("Kein Video ausgewählt")
            return
        path = Path(video_path)
        technical = self.technical_for_path(path)
        personal = self.personal_for_path(path)
        duration = float(technical.get("duration_seconds") or 0)
        position = float(personal.get("last_position_seconds") or 0)
        progress = int(min(100, max(0, round(position / duration * 100)))) if duration > 0 else 0
        rating = int(personal.get("rating") or 0)
        text = (
            f"Titel: {self.pretty_title(path)}\n\n"
            f"Pfad: {path}\n\n"
            f"Laufzeit: {self.seconds_to_readable_duration(duration) if duration else '–'}\n"
            f"Fortschritt: {progress} %\n"
            f"Bewertung: {rating}/5\n"
            f"Favorit: {'Ja' if personal.get('favorite') else 'Nein'}\n"
            f"Dateigröße: {self.format_file_size(path.stat().st_size) if path.exists() else 'Datei fehlt'}"
        )
        self.playlist_detail_label.set_text(text)
        thumb = self.thumbnail_path(path)
        if thumb.exists():
            try:
                pixbuf = GdkPixbuf.Pixbuf.new_from_file_at_scale(str(thumb), 220, 300, True)
                self.playlist_detail_image.set_from_pixbuf(pixbuf)
            except GLib.Error:
                self.playlist_detail_image.clear()
        else:
            self.playlist_detail_image.clear()

    def on_playlist_track_activated(self, tree, tree_path, _column):
        model = tree.get_model()
        self.open_in_vlc(Path(str(model[tree_path][1])))

    def on_playlist_rows_reordered(self, model, _path, _iter, _new_order):
        """Übernimmt Drag-and-drop nur in ungefilterter manueller Ansicht."""
        if not self.playlist_manual_order_active():
            return
        name = self.current_playlist_name()
        if not name:
            return
        self.playlists[name] = [str(row[1]) for row in model]
        self.save_config()
        self.refresh_playlist_tracks()
        self.status_label.set_text(
            f"Reihenfolge von „{name}“ per Drag-and-drop geändert."
        )

    def on_playlist_add_library_selection_clicked(self, _button):
        selected = [str(path) for path in self.selected_videos]
        if not selected:
            self.show_error("Bitte zuerst in der Bibliothek mindestens ein Video auswählen.")
            return
        name = self.current_playlist_name()
        if not name:
            self.show_error("Bitte zuerst eine Playlist auswählen oder neu anlegen.")
            return
        values = self.playlists.setdefault(name, [])
        added = 0
        for path in selected:
            if path not in values:
                values.append(path)
                added += 1
        self.save_config()
        self.refresh_playlist_workspace(select_name=name)
        self.status_label.set_text(f"{added} Video(s) zu „{name}“ hinzugefügt.")

    def on_playlist_remove_clicked(self, _button):
        name = self.current_playlist_name()
        selected = set(self.selected_playlist_track_paths())
        if not name or not selected:
            return
        self.playlists[name] = [
            path for path in self.playlists[name] if path not in selected
        ]
        self.playlist_checked_paths.difference_update(selected)
        self.save_config()
        self.refresh_playlist_workspace(select_name=name)
        self.status_label.set_text(
            f"{len(selected)} Eintrag/Einträge aus „{name}“ entfernt."
        )

    def on_playlist_move_up_clicked(self, _button):
        self.move_playlist_tracks(-1)

    def on_playlist_move_down_clicked(self, _button):
        self.move_playlist_tracks(1)

    def on_playlist_move_top_clicked(self, _button):
        self.move_playlist_tracks_to_edge(to_top=True)

    def on_playlist_move_bottom_clicked(self, _button):
        self.move_playlist_tracks_to_edge(to_top=False)

    def select_and_reveal_playlist_tracks(self, selected_paths):
        """Stellt Checkbox- und Zeilenauswahl wieder her und hält sie sichtbar."""
        if not hasattr(self, "playlist_track_view"):
            return False
        wanted = set(selected_paths)
        self.playlist_checked_paths = set(wanted)
        selection = self.playlist_track_view.get_selection()
        selection.unselect_all()
        reveal_path = None
        for row in self.playlist_track_store:
            is_selected = str(row[1]) in wanted
            row[6] = is_selected
            if not is_selected:
                continue
            tree_path = self.playlist_track_store.get_path(row.iter)
            selection.select_path(tree_path)
            if reveal_path is None:
                reveal_path = tree_path
        if reveal_path is not None:
            self.playlist_track_view.set_cursor(reveal_path, None, False)
            self.playlist_track_view.scroll_to_cell(
                reveal_path, None, True, 0.5, 0.0
            )
        return False

    def ensure_manual_playlist_order(self):
        if self.playlist_manual_order_active():
            return True
        self.status_label.set_text(
            "Verschieben ist nur bei „Manuelle Reihenfolge“ und ohne aktive Suche möglich."
        )
        return False

    def move_playlist_tracks(self, direction):
        if not self.ensure_manual_playlist_order():
            return
        name = self.current_playlist_name()
        selected_paths = self.selected_playlist_track_paths()
        if not name or not selected_paths:
            self.status_label.set_text(
                "Zum Verschieben mindestens einen Playlist-Eintrag auswählen."
            )
            return

        items = self.playlists[name]
        selected_set = set(selected_paths)
        if direction < 0:
            for index in range(1, len(items)):
                if items[index] in selected_set and items[index - 1] not in selected_set:
                    items[index - 1], items[index] = items[index], items[index - 1]
        else:
            for index in range(len(items) - 2, -1, -1):
                if items[index] in selected_set and items[index + 1] not in selected_set:
                    items[index], items[index + 1] = items[index + 1], items[index]

        self.save_config()
        self.refresh_playlist_workspace(select_name=name)
        GLib.idle_add(
            self.select_and_reveal_playlist_tracks, selected_paths
        )

    def move_playlist_tracks_to_edge(self, to_top):
        if not self.ensure_manual_playlist_order():
            return
        name = self.current_playlist_name()
        selected_paths = self.selected_playlist_track_paths()
        if not name or not selected_paths:
            self.status_label.set_text(
                "Zum Verschieben mindestens einen Playlist-Eintrag auswählen."
            )
            return

        items = self.playlists[name]
        selected_set = set(selected_paths)
        selected_in_order = [item for item in items if item in selected_set]
        remaining = [item for item in items if item not in selected_set]
        self.playlists[name] = (
            selected_in_order + remaining if to_top
            else remaining + selected_in_order
        )
        self.save_config()
        self.refresh_playlist_workspace(select_name=name)
        GLib.idle_add(
            self.select_and_reveal_playlist_tracks, selected_paths
        )

    def on_playlist_rename_clicked(self, _button):
        old_name = self.current_playlist_name()
        if not old_name:
            return
        new_name = self.ask_playlist_name("Playlist umbenennen", old_name)
        if not new_name or new_name == old_name:
            return
        new_name = self.unique_playlist_name(new_name)
        self.playlists[new_name] = self.playlists.pop(old_name)
        self.active_playlist_name = new_name
        self.save_config()
        self.refresh_playlist_workspace(select_name=new_name)

    def on_playlist_delete_clicked(self, _button):
        name = self.current_playlist_name()
        if not name:
            return
        dialog = Gtk.MessageDialog(
            transient_for=self, modal=True, message_type=Gtk.MessageType.QUESTION,
            buttons=Gtk.ButtonsType.YES_NO, text=f"Playlist „{name}“ löschen?",
        )
        dialog.format_secondary_text("Die Mediendateien bleiben unverändert.")
        response = dialog.run()
        dialog.destroy()
        if response != Gtk.ResponseType.YES:
            return
        self.playlists.pop(name, None)
        self.active_playlist_name = None
        self.save_config()
        self.refresh_playlist_workspace()

    def on_playlist_play_clicked(self, _button):
        selected = self.selected_playlist_track_paths()
        if selected:
            self.open_in_vlc(Path(selected[0]))
            return
        name = self.current_playlist_name()
        paths = self.playlists.get(name, []) if name else []
        if paths:
            self.open_in_vlc(Path(paths[0]))

    def unique_playlist_name(self, requested_name):
        """Erzeugt einen eindeutigen, sichtbaren Namen für eine Playlist."""
        base = str(requested_name or "Neue Playlist").strip() or "Neue Playlist"
        if base not in self.playlists:
            return base
        index = 2
        while f"{base} ({index})" in self.playlists:
            index += 1
        return f"{base} ({index})"

    def ask_playlist_name(self, title, initial_name=""):
        dialog = Gtk.Dialog(
            title=title,
            transient_for=self,
            modal=True,
            destroy_with_parent=True,
        )
        dialog.add_button("Abbrechen", Gtk.ResponseType.CANCEL)
        dialog.add_button("Speichern", Gtk.ResponseType.OK)
        area = dialog.get_content_area()
        area.set_border_width(12)
        entry = Gtk.Entry()
        entry.set_text(initial_name)
        entry.set_activates_default(True)
        dialog.set_default_response(Gtk.ResponseType.OK)
        area.pack_start(Gtk.Label(label="Name der Playlist:"), False, False, 4)
        area.pack_start(entry, False, False, 4)
        dialog.show_all()
        response = dialog.run()
        name = entry.get_text().strip() if response == Gtk.ResponseType.OK else ""
        dialog.destroy()
        return name

    def on_playlist_new_clicked(self, _button):
        """Legt im Playlist-Reiter bewusst eine leere interne Playlist an."""
        name = self.ask_playlist_name("Neue Playlist")
        if not name:
            return
        name = self.unique_playlist_name(name)
        self.playlists[name] = []
        self.active_playlist_name = name
        self.save_config()
        self.refresh_playlist_workspace(select_name=name)
        self.status_label.set_text(f"Leere Playlist „{name}“ intern erstellt.")

    def on_create_playlist(self, _widget):
        name = self.ask_playlist_name("Neue Playlist")
        if not name:
            return
        name = self.unique_playlist_name(name)
        selected = [str(path) for path in self.selected_action_videos()]
        self.playlists[name] = list(dict.fromkeys(selected))
        self.active_playlist_name = name
        self.save_config()
        self.show_playlist_tab()
        self.refresh_playlist_workspace(select_name=name)
        self.status_label.set_text(
            f"Playlist „{name}“ mit {len(selected)} Video(s) intern erstellt."
        )

    def choose_playlist_dialog(self, title):
        names = sorted(self.playlists, key=str.casefold)
        if not names:
            return None
        dialog = Gtk.Dialog(
            title=title,
            transient_for=self,
            modal=True,
            destroy_with_parent=True,
        )
        dialog.add_button("Abbrechen", Gtk.ResponseType.CANCEL)
        dialog.add_button("Auswählen", Gtk.ResponseType.OK)
        area = dialog.get_content_area()
        area.set_border_width(12)
        combo = Gtk.ComboBoxText()
        for name in names:
            combo.append_text(name)
        combo.set_active(0)
        area.pack_start(combo, False, False, 4)
        dialog.show_all()
        response = dialog.run()
        name = combo.get_active_text() if response == Gtk.ResponseType.OK else None
        dialog.destroy()
        return name

    def on_add_selected_to_playlist(self, _widget):
        """Fügt die Bibliotheksauswahl hinzu, ohne den versteckten Reiter neu aufzubauen."""
        videos = self.selected_action_videos()
        if not videos:
            return
        if not self.playlists:
            self.on_create_playlist(_widget)
            return
        name = self.choose_playlist_dialog("Zu Playlist hinzufügen")
        if not name:
            return

        paths = self.playlists.setdefault(name, [])
        before = len(paths)
        for video in videos:
            path = str(video)
            if path not in paths:
                paths.append(path)
        added = len(paths) - before
        self.active_playlist_name = name
        self.save_config()

        # Nur einen tatsächlich sichtbaren Playlist-Reiter sofort neu zeichnen.
        # Beim Hinzufügen aus der Bibliothek genügt ansonsten die gespeicherte
        # Datenänderung; der Reiter aktualisiert sich beim nächsten Öffnen.
        if self.main_notebook.get_current_page() == 1:
            self.refresh_playlist_workspace(select_name=name)

        self.status_label.set_text(
            f"{added} Video(s) zu „{name}“ hinzugefügt."
        )

    def on_remove_selected_from_playlist(self, _widget):
        if not self.active_playlist_name:
            return
        selected = {str(path) for path in self.selected_action_videos()}
        paths = self.playlists.get(self.active_playlist_name, [])
        remaining = [path for path in paths if path not in selected]
        removed = len(paths) - len(remaining)
        self.playlists[self.active_playlist_name] = remaining
        self.save_config()
        self.refresh_playlist_workspace(select_name=self.active_playlist_name)
        self.refresh_visible_videos()
        self.status_label.set_text(
            f"{removed} Video(s) aus „{self.active_playlist_name}“ entfernt."
        )

    def open_playlist(self, name):
        if name not in self.playlists:
            return
        self.active_playlist_name = name
        self.show_playlist_tab()
        self.refresh_playlist_workspace(select_name=name)

    def on_manage_playlists(self, _widget):
        """Öffnet den zentralen Playlist-Reiter."""
        self.show_playlist_tab()

    def on_auto_artwork_after_scan_toggled(self, menu_item):
        self.auto_artwork_after_scan = bool(menu_item.get_active())
        self.save_config()
