        def add_action_row(title, description, callback, advanced=False):
            row = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL, spacing=12)
            row.set_border_width(6)

            text_box = Gtk.Box(orientation=Gtk.Orientation.VERTICAL, spacing=3)
            title_label = Gtk.Label()
            title_label.set_xalign(0)
            title_label.set_markup(f"<b>{GLib.markup_escape_text(title)}</b>")
            description_label = Gtk.Label(label=description)
            description_label.set_xalign(0)
            description_label.set_line_wrap(True)
            description_label.set_max_width_chars(72)
            description_label.set_justify(Gtk.Justification.LEFT)
            description_label.get_style_context().add_class("dim-label")
            text_box.pack_start(title_label, False, False, 0)
            text_box.pack_start(description_label, False, False, 0)
            row.pack_start(text_box, True, True, 0)

            button = Gtk.Button(label="Starten")
            button.set_valign(Gtk.Align.CENTER)
            button.set_sensitive(not self.scan_running)
            button.connect("clicked", lambda *_: start_action(callback))
            action_buttons.append(button)
            row.pack_end(button, False, False, 0)
            row.advanced_scan_row = advanced
            actions_box.pack_start(row, False, False, 0)
            return row

        for title, description, callback in standard_actions:
            add_action_row(title, description, callback)

        advanced_heading = Gtk.Label()
        advanced_heading.set_xalign(0)
        advanced_heading.set_markup("<b>Erweiterte Prüf- und Reparaturläufe</b>")
        advanced_heading.set_margin_top(8)
