    def begin_scan(self, name):
        """Initialisiert einen abbrechbaren Hintergrundlauf."""
        if self.scan_running:
            return False
        self.cancel_event.clear()
        self.scan_running = True
        self.active_scan_name = name
        self.scan_started_at = time.monotonic()
        item = getattr(self, "cancel_scan_menu_item", None)
        if item is not None:
            item.set_sensitive(True)
        return True

    def end_scan(self):
        """Beendet den Scanstatus und gibt die Oberfläche wieder frei."""
        self.scan_running = False
        self.active_scan_name = None
        self.scan_started_at = None
        self.cancel_event.clear()
        item = getattr(self, "cancel_scan_menu_item", None)
        if item is not None:
            item.set_sensitive(False)

    def on_cancel_scan(self, _widget=None):
        """Fordert den Abbruch des aktuell laufenden Scans an."""
        if not self.scan_running:
            self.status_label.set_text("Es läuft derzeit kein Scan.")
            return
        self.cancel_event.set()
        self.metadata_after_technical_scan = False
        name = self.active_scan_name or "Scan"
        self.status_label.set_text(f"{name} wird abgebrochen …")
        self.progress_bar.set_text("Abbruch wird ausgeführt …")

        # ffmpeg/ffprobe sofort beenden; Netzwerkaufrufe enden spätestens mit
        # dem konfigurierten Timeout und werden danach nicht fortgesetzt.
        with self.active_process_lock:
            process = self.active_process
        if process is not None and process.poll() is None:
            try:
                os.killpg(process.pid, signal.SIGKILL)
            except (ProcessLookupError, PermissionError):
                pass

    def finish_cancelled_scan(self, name, *, save_index=False, refresh=False):
        """Schließt einen abgebrochenen Lauf ab und bewahrt Zwischenstände."""
        if save_index:
            self.save_index(show_errors=False)
        self.end_scan()
        percent = self.progress_bar.get_fraction() * 100.0
        self.progress_bar.set_text(f"Scan abgebrochen · {percent:.1f} %")
        self.status_label.set_text(
            f"{name} wurde abgebrochen. Bereits gespeicherte Ergebnisse bleiben erhalten."
        )
        if refresh:
            self.refresh_visible_videos()
        return False

    # ------------------------------------------------------------------
    # Filmordner verwalten
    # ------------------------------------------------------------------

    def on_add_folder(self, _widget):
        if self.scan_running:
            return

        dialog = Gtk.FileChooserDialog(
            title="Filmordner hinzufügen",
            parent=self,
            action=Gtk.FileChooserAction.SELECT_FOLDER,
        )
        dialog.add_buttons(
            Gtk.STOCK_CANCEL, Gtk.ResponseType.CANCEL,
            Gtk.STOCK_ADD, Gtk.ResponseType.OK,
        )
        response = dialog.run()
        selected = dialog.get_filename()
        dialog.destroy()

        if response != Gtk.ResponseType.OK or not selected:
            return

        new_root = Path(selected).expanduser().resolve()
        if new_root in self.video_roots:
            self.status_label.set_text("Dieser Filmordner ist bereits eingetragen.")
            self.select_tree_path(new_root)
            return

        self.video_roots.append(new_root)
        self.save_config()
        self.scan_videos()

    def on_remove_folder(self, _widget):
        if self.scan_running:
            return

        root = self.get_selected_library_root()
        if root is None:
            self.show_error("Wähle links einen Filmordner oder einen seiner Unterordner aus.")
            return

        dialog = Gtk.MessageDialog(
            transient_for=self,
            message_type=Gtk.MessageType.QUESTION,
            buttons=Gtk.ButtonsType.YES_NO,
            text="Filmordner aus der Bibliothek entfernen?",
        )
        dialog.format_secondary_text(
            f"{root}\n\nDie Dateien auf der Festplatte werden nicht gelöscht."
        )
        response = dialog.run()
        dialog.destroy()
        if response != Gtk.ResponseType.YES:
            return

        self.video_roots = [path for path in self.video_roots if path != root]
        self.save_config()
        if self.video_roots:
            self.scan_videos()
        else:
            self.videos = []
            self.library_records = {}
            self.rebuild_library_lookup_caches()
            self.selected_folder = None
            self.selected_video = None
            self.folder_store.clear()
            self.clear_flowbox()
            self.save_index()
            self.cleanup_orphan_thumbnails()
            self.status_label.set_text("Alle Filmordner wurden entfernt.")
            self.progress_bar.set_fraction(0.0)
            self.progress_bar.set_text("Bereit")

    def get_selected_library_root(self):
        model, tree_iter = self.folder_tree.get_selection().get_selected()
        if tree_iter is None:
            return None
        selected_path = Path(model[tree_iter][1])
        matching = [
            root for root in self.video_roots
            if selected_path == root or root in selected_path.parents
        ]
        return max(matching, key=lambda path: len(path.parts)) if matching else None

    # ------------------------------------------------------------------
    # Bibliothek einlesen und abgleichen
    # ------------------------------------------------------------------

    def on_refresh(self, _widget):
        if self.video_roots and not self.scan_running:
            self.scan_videos()

    def on_reconcile_library(self, _widget):
        self.on_refresh(None)

    def scan_videos(self):
        if not self.video_roots or not self.begin_scan("Bibliotheksabgleich"):
            return

        self.selected_video = None
        self.status_label.set_text(f"{len(self.video_roots)} Filmordner werden abgeglichen …")
        self.update_scan_fraction(
            "Bibliotheksabgleich", 0.0, "Dateistruktur wird vorbereitet"
        )
        threading.Thread(target=self.scan_worker, daemon=True).start()

    def iter_video_files(self, root, errors):
        """Liefert Videodateien ohne stat()-Aufruf für jeden Verzeichniseintrag."""
        root = Path(root)
        def walk_error(exc):
            self.log_error(
                "Filmordner konnte nicht vollständig durchsucht werden",
                exc,
                details=str(getattr(exc, "filename", root)),
            )
            errors.append(f"{getattr(exc, 'filename', root)}: {exc}")

        for directory, _subdirs, filenames in os.walk(
            root,
            topdown=True,
            onerror=walk_error,
            followlinks=False,
        ):
            if self.cancel_event.is_set():
                raise ScanCancelled
            directory_path = Path(directory)
            for filename in filenames:
                if self.cancel_event.is_set():
                    raise ScanCancelled
                if Path(filename).suffix.lower() in VIDEO_EXTENSIONS:
                    yield directory_path / filename

    def scan_worker(self):
        found_paths = []
        errors = []
        try:
            root_total = max(1, len(self.video_roots))
            for root_number, root in enumerate(self.video_roots, start=1):
                if self.cancel_event.is_set():
                    raise ScanCancelled
                if not root.exists():
                    errors.append(f"Nicht gefunden: {root}")
                    continue
                for path in self.iter_video_files(root, errors):
                    found_paths.append(path)
                GLib.idle_add(
                    self.update_scan_fraction,
                    "Bibliotheksabgleich",
                    0.5 * root_number / root_total,
                    f"Ordner {root_number} von {root_total} geprüft",
                )

            unique_paths = sorted(set(found_paths), key=lambda p: str(p).lower())
            new_records = {}
            record_total = max(1, len(unique_paths))
            for record_number, path in enumerate(unique_paths, start=1):
                if self.cancel_event.is_set():
                    raise ScanCancelled
                record = self.make_record(path)
                if record:
                    new_records[record["path"]] = record
                if record_number == record_total or record_number % 50 == 0:
                    GLib.idle_add(
                        self.update_scan_fraction,
                        "Bibliotheksabgleich",
                        0.5 + 0.5 * record_number / record_total,
                        f"Index {record_number} von {record_total}",
                    )

            old_records = dict(self.library_records)
            self.merge_persistent_record_data(old_records, new_records)
            report = self.compare_libraries(old_records, new_records)
            GLib.idle_add(self.scan_finished, new_records, errors, report)
        except ScanCancelled:
            GLib.idle_add(
                self.finish_cancelled_scan,
                "Bibliotheksabgleich",
                save_index=False,
                refresh=False,
            )

    def merge_persistent_record_data(self, old_records, new_records):
        """Bewahrt Metadaten/Technikdaten bei Scan, Änderung und Verschiebung."""
        old_by_id = {rec.get("file_id"): rec for rec in old_records.values()}
        old_by_signature = {
            (rec.get("size"), rec.get("mtime_ns")): rec
            for rec in old_records.values()
        }
        for path, new_record in new_records.items():
            old_record = old_records.get(path)
            if old_record is None:
                old_record = old_by_id.get(new_record.get("file_id"))
            if old_record is None:
                old_record = old_by_signature.get(
                    (new_record.get("size"), new_record.get("mtime_ns"))
                )
            if old_record:
                # Die einmal vergebene Identität und damit auch der Name des
                # Vorschaubilds bleiben stabil. Das verhindert Cache-Verlust
                # durch wechselnde st_dev-/st_ino-Werte, besonders auf NTFS.
                if old_record.get("file_id"):
                    new_record["file_id"] = old_record["file_id"]
                if old_record.get("thumbnail"):
                    new_record["thumbnail"] = old_record["thumbnail"]
                new_record["metadata"] = old_record.get(
                    "metadata", self.default_metadata()
                )
                new_record["technical"] = old_record.get(
                    "technical", self.default_technical()
                )
                new_record["personal"] = old_record.get(
                    "personal", self.default_personal()
                )
            self.normalize_record(new_record)

    def compare_libraries(self, old_records, new_records):
        old_paths = set(old_records)
        new_paths = set(new_records)
        unchanged = []
        changed = []
        added_paths = set(new_paths - old_paths)
        removed_paths = set(old_paths - new_paths)

        for path in old_paths & new_paths:
            old = old_records[path]
            new = new_records[path]
            if old["file_id"] == new["file_id"]:
                unchanged.append(path)
            else:
                changed.append(path)

        # Verschiebungen/Umbenennungen erkennen: zuerst exakte Datei-ID,
        # danach Größe + Änderungszeit als Fallback für Dateisystemwechsel.
        old_by_id = {}
        old_by_signature = {}
        for path in removed_paths:
            record = old_records[path]
            old_by_id.setdefault(record["file_id"], []).append(path)
            signature = (record["size"], record["mtime_ns"])
            old_by_signature.setdefault(signature, []).append(path)

        moved = []
        consumed_old = set()
        consumed_new = set()
        for new_path in sorted(added_paths):
            record = new_records[new_path]
            candidates = old_by_id.get(record["file_id"], [])
            if not candidates:
                candidates = old_by_signature.get((record["size"], record["mtime_ns"]), [])
            old_path = next((p for p in candidates if p not in consumed_old), None)
            if old_path:
                moved.append((old_path, new_path))
                consumed_old.add(old_path)
                consumed_new.add(new_path)

                old_thumb = old_records[old_path].get("thumbnail")
                if old_thumb:
                    # Bestehendes Bild weiterverwenden, aber unter der neuen
                    # eindeutigen ID ablegen.
                    old_file = self.thumb_cache / old_thumb
                    new_file = self.thumb_cache / record["thumbnail"]
                    if old_file.exists() and old_file != new_file and not new_file.exists():
                        try:
                            shutil.copy2(old_file, new_file)
                        except OSError:
                            pass

        added = sorted(added_paths - consumed_new)
        removed = sorted(removed_paths - consumed_old)
        return {
            "new": added,
            "removed": removed,
            "moved": moved,
            "changed": sorted(changed),
            "unchanged": sorted(unchanged),
        }

    def scan_finished(self, new_records, errors, report):
        self.end_scan()
        self.library_records = new_records
        self.videos = [Path(path) for path in new_records]
        self.rebuild_library_lookup_caches()
        self.last_scan_report = report
        self.save_index()
        self.migrate_series_folder_mappings_from_moves(report)
        self.repair_orphan_series_folder_mappings()
        self.infer_series_folder_mappings_from_metadata()
        removed_thumbs = self.cleanup_orphan_thumbnails()
        self.build_folder_tree()

        if not self.restore_last_selected_folder():
            self.select_first_root()

        summary = (
            f"{len(self.videos)} Filme: "
            f"{len(report['new'])} neu, "
            f"{len(report['moved'])} verschoben/umbenannt, "
            f"{len(report['changed'])} geändert, "
            f"{len(report['removed'])} entfernt"
        )
        if removed_thumbs:
            summary += f"; {removed_thumbs} verwaiste Vorschaubilder gelöscht"
        if errors:
            summary += f"; {len(errors)} Ordnerproblem(e)"

        auto_targets = [
            Path(path_text)
            for path_text in (report.get("new") or []) + (report.get("changed") or [])
            if path_text in self.library_records
        ]

        if auto_targets and self.auto_artwork_after_scan:
            self.status_label.set_text(
                summary + f" · automatische Bildergänzung startet für {len(auto_targets)} Datei(en) …"
            )
            self.progress_bar.set_fraction(1.0)
            self.progress_bar.set_text("Bibliotheksabgleich abgeschlossen · 100.0 % · ETA: 0 s")
            self.fetch_missing_posters_for_videos(
                auto_targets,
                only_missing=True,
                reason="Automatische Bildergänzung",
            )
        else:
            if auto_targets and not self.auto_artwork_after_scan:
                summary += "; automatische Bildergänzung ist ausgeschaltet"
            self.status_label.set_text(summary)
            self.progress_bar.set_fraction(1.0)
            self.progress_bar.set_text("Bibliotheksabgleich abgeschlossen · 100.0 % · ETA: 0 s")
        return False

    def capture_folder_tree_state(self):
        selected = self.selected_folder
        expanded = set()

        def walk(tree_iter):
            while tree_iter is not None:
                tree_path = self.folder_store.get_path(tree_iter)
                if self.folder_tree.row_expanded(tree_path):
                    expanded.add(self.folder_store[tree_iter][1])
                child = self.folder_store.iter_children(tree_iter)
                if child is not None:
                    walk(child)
                tree_iter = self.folder_store.iter_next(tree_iter)

        first = self.folder_store.get_iter_first()
        if first is not None:
            walk(first)

        adjustment = None
        if hasattr(self, "folder_scrolled"):
            adjustment = self.folder_scrolled.get_vadjustment().get_value()
        return selected, expanded, adjustment

    def restore_folder_tree_state(self, selected, expanded, adjustment):
        def walk(tree_iter):
            while tree_iter is not None:
                folder_text = self.folder_store[tree_iter][1]
                tree_path = self.folder_store.get_path(tree_iter)
                if folder_text in expanded:
                    self.folder_tree.expand_row(tree_path, False)
                child = self.folder_store.iter_children(tree_iter)
                if child is not None:
                    walk(child)
                tree_iter = self.folder_store.iter_next(tree_iter)

        first = self.folder_store.get_iter_first()
        if first is not None:
            walk(first)
        if selected:
            self.select_tree_path(selected, scroll=False)

        if adjustment is not None and hasattr(self, "folder_scrolled"):
            def restore_scroll():
                vadj = self.folder_scrolled.get_vadjustment()
                upper = max(vadj.get_lower(), vadj.get_upper() - vadj.get_page_size())
                vadj.set_value(min(max(adjustment, vadj.get_lower()), upper))
                return False
            GLib.idle_add(restore_scroll)

    def rebuild_folder_tree_preserving_state(self, preferred_selection=None):
        selected, expanded, adjustment = self.capture_folder_tree_state()
        if preferred_selection is not None:
            selected = Path(preferred_selection)
        self.build_folder_tree()
        self.restore_folder_tree_state(selected, expanded, adjustment)

    @staticmethod
    def normalized_folder_match_text(value):
        """Normalisiert Ordner- und Serientitel für eine vorsichtige Zuordnung."""
        text = str(value or "").casefold()
        text = re.sub(r"[^a-z0-9äöüß]+", " ", text)
        return " ".join(text.split())

    def all_existing_media_folders(self):
        """Ermittelt ausschließlich Ordner, die aktuell Mediendateien enthalten."""
        folders = set()
        for video in self.videos:
            current = video.parent
            while True:
                folders.add(current)
                parent = current.parent
                if parent == current:
                    break
                if any(current == root for root in self.video_roots):
                    break
                current = parent
        return folders

    def migrate_series_folder_mappings_from_moves(self, report):
        """Überträgt Serienzuordnungen bei erkannten Datei-Verschiebungen.

        Für jede alte Serienwurzel wird aus den verschobenen Dateien der
        entsprechende neue Basisordner rekonstruiert. Dadurch bleiben Poster,
        Serien-ID und Staffelzuordnungen auch nach Umbenennen oder Verschieben
        erhalten.
        """
        moved = report.get("moved", []) if isinstance(report, dict) else []
        if not moved or not self.series_folder_mappings:
            return False

        changed = False
        updated = dict(self.series_folder_mappings)
        for old_folder_text, mapping in list(self.series_folder_mappings.items()):
            old_folder = Path(old_folder_text)
            if old_folder.exists():
                continue
            candidates = {}
            for old_path_text, new_path_text in moved:
                old_path = Path(old_path_text)
                new_path = Path(new_path_text)
                try:
                    relative = old_path.relative_to(old_folder)
                except ValueError:
                    continue
                candidate = new_path
                for _ in relative.parts:
                    candidate = candidate.parent
                candidates[candidate] = candidates.get(candidate, 0) + 1
            if not candidates:
                continue
            new_folder = max(candidates, key=candidates.get)
            if not new_folder.exists():
                continue
            updated.pop(old_folder_text, None)
            updated[str(new_folder)] = mapping
            changed = True

        if changed:
            self.series_folder_mappings = updated
            self.save_config()
        return changed

    def repair_orphan_series_folder_mappings(self):
        """Repariert alte pfadgebundene Serienzuordnungen vorsichtig.

        Die Funktion greift nur bei nicht mehr existierenden Zuordnungspfaden.
        Sie vergleicht den gespeicherten Serien- und Originaltitel sowie den
        alten Ordnernamen mit vorhandenen Medienordnern. Eine Reparatur erfolgt
        nur bei einem klaren, hinreichend guten Einzeltreffer.
        """
        if not self.series_folder_mappings:
            return False

        existing_folders = self.all_existing_media_folders()
        if not existing_folders:
            return False

        occupied = {Path(path) for path in self.series_folder_mappings if Path(path).exists()}
        updated = dict(self.series_folder_mappings)
        changed = False

        for old_folder_text, mapping in list(self.series_folder_mappings.items()):
            old_folder = Path(old_folder_text)
            if old_folder.exists():
                continue

            references = [
                mapping.get("title"),
                mapping.get("original_title"),
                old_folder.name,
            ]
            references = [
                self.normalized_folder_match_text(value)
                for value in references
                if self.normalized_folder_match_text(value)
            ]
            if not references:
                continue

            ranked = []
            for folder in existing_folders:
                if folder in occupied:
                    continue
                candidate = self.normalized_folder_match_text(folder.name)
                if not candidate or self.season_number_from_folder(folder) is not None:
                    continue
                score = max(
                    difflib.SequenceMatcher(None, reference, candidate).ratio()
                    for reference in references
                )
                ranked.append((score, folder))

            ranked.sort(key=lambda item: item[0], reverse=True)
            if not ranked:
                continue
            best_score, best_folder = ranked[0]
            second_score = ranked[1][0] if len(ranked) > 1 else 0.0
            if best_score < 0.78 or best_score - second_score < 0.08:
                continue

            updated.pop(old_folder_text, None)
            updated[str(best_folder)] = mapping
            occupied.add(best_folder)
            changed = True

        if changed:
            self.series_folder_mappings = updated
            self.save_config()
        return changed


    def infer_series_root_from_video(self, video_path):
        """Leitet den Serienhauptordner aus einer Episodendatei ab.

        Ein Staffelordner wird entweder an einem üblichen Namen wie
        »Staffel 3« erkannt oder aus den bereits gespeicherten Episodendaten
        abgeleitet. Dadurch gelten auch Ordner wie »The Good Doctor 1« als
        Staffelordner, wenn ihre Folgen eindeutig zu Staffel 1 gehören.
        """
        path = Path(video_path)
        current = path.parent
        while True:
            if self.inferred_season_number_for_folder(current) is not None:
                return current.parent
            if any(current == root for root in self.video_roots):
                break
            parent = current.parent
            if parent == current:
                break
            current = parent
        return path.parent

    def infer_series_folder_mappings_from_metadata(self):
        """Ergänzt fehlende Serienordner-Zuordnungen aus Episodenmetadaten.

        Wenn eine Serie bereits auf Episodenebene korrekt als TMDb-Episode
        erkannt wurde, liegen Serien-ID, Serientitel und Poster-URL schon im
        Bibliotheksindex vor. Damit können verlorene oder nie angelegte
        Ordnerzuordnungen rekonstruiert werden, auch wenn Ordner inzwischen
        umbenannt oder verschoben wurden.
        """
        candidates = {}
        for video in self.videos:
            record = self.library_records.get(str(video)) or {}
            metadata = record.get('metadata') or {}
            if metadata.get('status') != 'found' or metadata.get('media_type') != 'episode':
                continue
            series_tmdb_id = metadata.get('series_tmdb_id')
            if not series_tmdb_id:
                continue
            root_folder = self.infer_series_root_from_video(video)
            if not root_folder or not root_folder.exists():
                continue
            if self.season_number_from_folder(root_folder) is not None:
                continue
            root_key = str(root_folder)
            group = candidates.setdefault(root_key, {
                'folder': root_folder,
                'ids': {},
                'title': None,
                'original_title': None,
                'year': None,
                'poster_url': None,
            })
            tmdb_id = int(series_tmdb_id)
            group['ids'][tmdb_id] = group['ids'].get(tmdb_id, 0) + 1
            if not group['title'] and metadata.get('series_title'):
                group['title'] = metadata.get('series_title')
            if not group['original_title'] and metadata.get('original_title'):
                group['original_title'] = metadata.get('original_title')
            if not group['year'] and metadata.get('year'):
                group['year'] = metadata.get('year')
            if not group['poster_url'] and metadata.get('poster_url'):
                group['poster_url'] = metadata.get('poster_url')

        if not candidates:
            return self.normalize_series_mappings_for_season_subfolders()

        changed = False
        updated = dict(self.series_folder_mappings)
        for folder_key, data in candidates.items():
            if len(data['ids']) != 1:
                continue
            tmdb_id = next(iter(data['ids']))
            existing = updated.get(folder_key)
            mapping = {
                'tmdb_id': tmdb_id,
                'title': data.get('title') or Path(folder_key).name,
                'original_title': data.get('original_title'),
                'year': data.get('year'),
                'poster_url': data.get('poster_url'),
            }
            if existing:
                if not existing.get('poster_url') and mapping.get('poster_url'):
                    existing['poster_url'] = mapping['poster_url']
                    changed = True
                if not existing.get('title') and mapping.get('title'):
                    existing['title'] = mapping['title']
                    changed = True
                if not existing.get('original_title') and mapping.get('original_title'):
                    existing['original_title'] = mapping['original_title']
                    changed = True
                continue

            # Alte verwaiste Zuordnungen derselben Serie werden durch den
            # tatsächlich vorhandenen Serienordner ersetzt.
            for old_folder_text, old_mapping in list(updated.items()):
                if Path(old_folder_text).exists():
                    continue
                if int(old_mapping.get('tmdb_id') or 0) == tmdb_id:
                    updated.pop(old_folder_text, None)
                    changed = True
            updated[folder_key] = mapping
            changed = True

        if changed:
            self.series_folder_mappings = updated
            self.save_config()
        normalized = self.normalize_series_mappings_for_season_subfolders()
        return changed or normalized

    def build_folder_tree(self):
        # Direkte Serienzuordnungen werden im Baum sichtbar markiert; geerbte
        # Zuordnungen bleiben bewusst unmarkiert, damit der Hauptordner erkennbar bleibt.
        self.folder_store.clear()
        for root in self.video_roots:
            root_label = root.name or str(root)
            if str(root) in self.series_folder_mappings:
                root_label += "  [TMDb]"
            root_iter = self.folder_store.append(None, [root_label, str(root), True])
            folders = {root: root_iter}
            video_folders = sorted(
                {video.parent for video in self.videos if root == video.parent or root in video.parents},
                key=lambda path: (len(path.parts), str(path).lower()),
            )
            for folder in video_folders:
                if folder == root:
                    continue
                try:
                    relative_parts = folder.relative_to(root).parts
                except ValueError:
                    continue
                current_path = root
                parent_iter = root_iter
                for part in relative_parts:
                    current_path = current_path / part
                    if current_path not in folders:
                        label = part
                        if str(current_path) in self.series_folder_mappings:
                            label += "  [TMDb]"
                        folders[current_path] = self.folder_store.append(
                            parent_iter, [label, str(current_path), False]
                        )
                    parent_iter = folders[current_path]
            self.folder_tree.expand_row(self.folder_store.get_path(root_iter), False)

    def select_first_root(self):
        first = self.folder_store.get_iter_first()
        if first is not None:
            self.folder_tree.get_selection().select_iter(first)

    def restore_last_selected_folder(self):
        """Stellt beim Start nicht nur die Baumauswahl, sondern die Ansicht wieder her."""
        folder = Path(self.last_selected_folder) if self.last_selected_folder else None
        if not folder or not folder.is_dir():
            return False

        # Die eigentliche Ansicht wird ausdrücklich gesetzt. Eine reine
        # programmgesteuerte Auswahl im Gtk.TreeView löst nicht auf jeder
        # GTK-Version zuverlässig das Auswahlereignis aus.
        self.selected_folder = folder
        self.last_selected_folder = folder
        self.selected_video = None
        self.selected_tile_folder = None

        self.select_tree_path(folder, scroll=True)
        self.refresh_visible_videos()
        if self.detail_panel_visible:
            self.update_detail_panel(folder=folder)
        return True

    def select_tree_path(self, target, scroll=True):
        found = False

        def walk(tree_iter):
            nonlocal found
            while tree_iter is not None:
                if Path(self.folder_store[tree_iter][1]) == target:
                    tree_path = self.folder_store.get_path(tree_iter)

                    # Alle Vorfahren öffnen, bevor Auswahl und Scrollen erfolgen.
                    # Ohne diesen Schritt kann der richtige Ordner zwar intern
                    # ausgewählt sein, im eingeklappten Baum aber unsichtbar bleiben.
                    self.folder_tree.expand_to_path(tree_path)
                    self.folder_tree.get_selection().select_iter(tree_iter)
                    self.folder_tree.set_cursor(tree_path)

                    if scroll:
                        self.folder_tree.scroll_to_cell(
                            tree_path,
                            None,
                            True,
                            0.45,
                            0.0,
                        )
                    found = True
                    return True
                child = self.folder_store.iter_children(tree_iter)
                if child is not None and walk(child):
                    return True
                tree_iter = self.folder_store.iter_next(tree_iter)
            return False

        first = self.folder_store.get_iter_first()
        if first is not None:
            walk(first)
        return found

    def synchronize_tree_to_folder(self, folder):
        """Klappt den Baum zu einem Suchtreffer auf, ohne die Suche zu beenden."""
        folder = Path(folder)
        self.synchronizing_tree_selection = True
        try:
            found = self.select_tree_path(folder, scroll=True)
            if not found:
                # Falls der Index seit dem letzten Baumaufbau erweitert wurde,
                # wird der Baum einmal neu aufgebaut und die Auswahl wiederholt.
                state = self.capture_folder_tree_state()
                self.build_folder_tree()
                self.restore_folder_tree_state(state)
                found = self.select_tree_path(folder, scroll=True)
            return found
        finally:
            self.synchronizing_tree_selection = False

    def get_series_folder_mapping(self, path):
        """Liefert die genaueste Zuordnung für einen Ordner oder eine Datei."""
        candidate = Path(path)
        if candidate.is_file():
            candidate = candidate.parent
        matches = []
        for folder_text, mapping in self.series_folder_mappings.items():
            folder = Path(folder_text)
            if candidate == folder or folder in candidate.parents:
                matches.append((len(folder.parts), folder, mapping))
        if not matches:
            return None
        _depth, folder, mapping = max(matches, key=lambda item: item[0])
        result = dict(mapping)
        result["folder"] = str(folder)
        return result

    def on_folder_tree_button_press(self, tree, event):
        if event.type != Gdk.EventType.BUTTON_PRESS or event.button != 3:
            return False
        hit = tree.get_path_at_pos(int(event.x), int(event.y))
        if not hit:
            return False
        tree_path, _column, _cell_x, _cell_y = hit
        tree.get_selection().select_path(tree_path)
        model = tree.get_model()
        tree_iter = model.get_iter(tree_path)
        folder = Path(model[tree_iter][1])
        self.selected_folder = folder
        self.last_selected_folder = folder
        if self.detail_panel_visible:
            self.update_detail_panel(folder=folder)
        self.status_label.set_text(
            f"Ordner ausgewählt: {folder.name or folder}"
        )
        self.show_folder_context_menu(event, folder)
        return True

    def show_folder_context_menu(self, event, folder):
        menu = Gtk.Menu()
        mapping = self.series_folder_mappings.get(str(folder))
        inherited = self.get_series_folder_mapping(folder)
        self.add_menu_item(
            menu,
            "Eigenes Ordnerbild zuweisen …",
            lambda *_: self.assign_custom_folder_image(folder),
        )
        if self.get_custom_folder_image(folder):
            self.add_menu_item(
                menu,
                "Eigenes Ordnerbild entfernen",
                lambda *_: self.remove_custom_folder_image(folder),
            )
        self.add_menu_item(
            menu,
            "Ordnerbilder-Ordner öffnen",
            lambda *_: self.open_directory(self.folder_images_dir),
        )
        menu.append(Gtk.SeparatorMenuItem())
        self.add_menu_item(
            menu,
            "Ordner einer TMDb-Serie zuordnen …" if not mapping else "TMDb-Serienzuordnung ändern …",
            lambda *_: self.assign_series_folder(folder),
        )
        if mapping:
            self.add_menu_item(
                menu,
                "TMDb-Serienzuordnung entfernen",
                lambda *_: self.remove_series_folder_mapping(folder),
            )
        if inherited and not mapping:
            menu.append(Gtk.SeparatorMenuItem())
            inherited_item = Gtk.MenuItem(
                label=f"Geerbte Zuordnung: {inherited.get('title') or inherited.get('tmdb_id')}"
            )
            inherited_item.set_sensitive(False)
            menu.append(inherited_item)
        menu.append(Gtk.SeparatorMenuItem())
        self.add_menu_item(
            menu,
            "Alle Unterordner aufklappen",
            lambda *_: self.expand_folder_subtree(folder, True),
        )
        self.add_menu_item(
            menu,
            "Alle Unterordner zuklappen",
            lambda *_: self.expand_folder_subtree(folder, False),
        )
        menu.show_all()
        menu.popup_at_pointer(event)

    def find_tree_iter_for_folder(self, target):
        target = Path(target)
        result = None

        def walk(tree_iter):
            nonlocal result
            while tree_iter is not None:
                if Path(self.folder_store[tree_iter][1]) == target:
                    result = tree_iter
                    return True
                child = self.folder_store.iter_children(tree_iter)
                if child is not None and walk(child):
                    return True
                tree_iter = self.folder_store.iter_next(tree_iter)
            return False

        first = self.folder_store.get_iter_first()
        if first is not None:
            walk(first)
        return result

    def expand_folder_subtree(self, folder, expand):
        tree_iter = self.find_tree_iter_for_folder(folder)
        if tree_iter is None:
            return
        tree_path = self.folder_store.get_path(tree_iter)
        if expand:
            self.folder_tree.expand_row(tree_path, True)
            self.status_label.set_text(f"Alle Unterordner von „{Path(folder).name}“ wurden aufgeklappt.")
        else:
            def collapse_children(parent_iter):
                child = self.folder_store.iter_children(parent_iter)
                while child is not None:
                    collapse_children(child)
                    child_path = self.folder_store.get_path(child)
                    self.folder_tree.collapse_row(child_path)
                    child = self.folder_store.iter_next(child)
            collapse_children(tree_iter)
            self.folder_tree.collapse_row(tree_path)
            self.folder_tree.expand_row(tree_path, False)
            self.status_label.set_text(f"Alle Unterordner von „{Path(folder).name}“ wurden zugeklappt.")

    def suggested_series_title_for_folder(self, folder):
        folder = Path(folder)
        if self.inferred_season_number_for_folder(folder) is not None:
            return folder.parent.name
        return folder.name

    @staticmethod
    def season_number_from_folder(folder):
        """Liest die Staffelnummer aus Namen wie »Staffel 3« oder »Season 3«."""
        match = re.match(r"^(?:Staffel|Season)\s*(\d+)", Path(folder).name, re.IGNORECASE)
        return int(match.group(1)) if match else None

    def inferred_season_number_for_folder(self, folder):
        """Erkennt eine Staffel zusätzlich anhand eindeutiger Episodendaten.

        Die Auswertung beschränkt sich auf Videodateien, die direkt im Ordner
        liegen. Nur wenn alle bereits gefundenen Episoden derselben Serie und
        derselben Staffel angehören, wird der Ordner als Staffelordner gewertet.
        """
        folder = Path(folder)
        explicit = self.season_number_from_folder(folder)
        if explicit is not None:
            return explicit

        season_numbers = set()
        series_ids = set()
        episode_count = 0
        for video in self.videos:
            if video.parent != folder:
                continue
            metadata = (self.library_records.get(str(video)) or {}).get("metadata") or {}
            if metadata.get("status") != "found" or metadata.get("media_type") != "episode":
                continue
            season_number = metadata.get("season_number")
            series_id = metadata.get("series_tmdb_id")
            if season_number is None or not series_id:
                continue
            season_numbers.add(int(season_number))
            series_ids.add(int(series_id))
            episode_count += 1

        if episode_count and len(season_numbers) == 1 and len(series_ids) == 1:
            return next(iter(season_numbers))
        return None

    def normalize_series_mappings_for_season_subfolders(self):
        """Verschiebt irrtümliche Serienzuordnungen von Staffel- auf Hauptordner.

        Wurde etwa »The Good Doctor 1« manuell als Serie zugeordnet, obwohl die
        enthaltenen Episoden eindeutig Staffel 1 sind, wird dieselbe TMDb-ID am
        Elternordner »The Good Doctor« gespeichert. Gleichartige Zuordnungen
        der Schwester-Staffeln werden anschließend entfernt und nur noch geerbt.
        """
        updated = dict(self.series_folder_mappings)
        changed = False
        grouped = {}
        for folder_text, mapping in list(updated.items()):
            folder = Path(folder_text)
            if not folder.exists():
                continue
            season_number = self.inferred_season_number_for_folder(folder)
            if season_number is None or not mapping.get("tmdb_id"):
                continue
            key = (str(folder.parent), int(mapping["tmdb_id"]))
            grouped.setdefault(key, []).append((folder, mapping))

        for (parent_text, tmdb_id), entries in grouped.items():
            parent = Path(parent_text)
            parent_mapping = updated.get(parent_text)
            source_mapping = dict(entries[0][1])
            if not parent_mapping:
                updated[parent_text] = source_mapping
                changed = True
            elif int(parent_mapping.get("tmdb_id") or 0) != tmdb_id:
                continue
            else:
                for field in ("title", "original_title", "year", "poster_url"):
                    if not parent_mapping.get(field) and source_mapping.get(field):
                        parent_mapping[field] = source_mapping[field]
                        changed = True

            for folder, mapping in entries:
                if int(mapping.get("tmdb_id") or 0) == tmdb_id and str(folder) in updated:
                    updated.pop(str(folder), None)
                    changed = True

        if changed:
            self.series_folder_mappings = updated
            self.save_config()
        return changed

    def season_folder_context(self, folder):
        """Liefert Serienzuordnung und Staffelnummer für einen Staffelordner."""
        season_number = self.inferred_season_number_for_folder(folder)
        if season_number is None:
            return None
        mapping = self.get_series_folder_mapping(folder)
        if not mapping or not mapping.get("tmdb_id"):
            return None
        return mapping, season_number

    def assign_series_folder(self, folder):
        if self.scan_running:
            self.status_label.set_text("Während eines laufenden Scans kann keine Serienzuordnung geändert werden.")
            return
        if not (self.tmdb_api_key or self.tmdb_read_token):
            self.show_error("Kein TMDb-Zugang gespeichert.")
            return

        default_title = self.suggested_series_title_for_folder(folder)
        dialog = Gtk.Dialog(
            title="Ordner einer TMDb-Serie zuordnen",
            transient_for=self,
            modal=True,
        )
        dialog.add_buttons(Gtk.STOCK_CANCEL, Gtk.ResponseType.CANCEL, "Suchen", Gtk.ResponseType.OK)
        area = dialog.get_content_area()
        area.set_border_width(12)
        area.set_spacing(8)
        info = Gtk.Label(label=f"Ordner:\n{folder}\n\nSerientitel für die TMDb-Suche:")
        info.set_xalign(0)
        info.set_line_wrap(True)
        area.pack_start(info, False, False, 0)
        entry = Gtk.Entry()
        entry.set_text(default_title)
        entry.set_activates_default(True)
        area.pack_start(entry, False, False, 0)
        dialog.set_default_response(Gtk.ResponseType.OK)
        dialog.show_all()
        response = dialog.run()
        search_title = entry.get_text().strip()
        dialog.destroy()
        if response != Gtk.ResponseType.OK or not search_title:
            return

        self.status_label.set_text(f"TMDb-Serien werden gesucht: {search_title}")
        while Gtk.events_pending():
            Gtk.main_iteration_do(False)
        try:
            candidates = self.tmdb_search_candidates(search_title, "", True)
        except Exception as exc:
            self.show_error(f"TMDb-Suche fehlgeschlagen:\n{exc}")
            return
        if not candidates:
            self.show_error("Keine passende TMDb-Serie gefunden.")
            return

        ranked = sorted(
            ((self.score_tmdb_candidate(search_title, "", item, True), item) for item in candidates),
            key=lambda pair: pair[0],
            reverse=True,
        )
        chosen = self.choose_series_candidate_dialog(folder, search_title, ranked[:10])
        if not chosen:
            return
        tmdb_id, title, original_title, year, poster_path = chosen
        self.series_folder_mappings[str(folder)] = {
            "tmdb_id": int(tmdb_id),
            "title": title,
            "original_title": original_title,
            "year": year,
            "poster_url": f"https://image.tmdb.org/t/p/w500{poster_path}" if poster_path else None,
        }
        self.save_config()
        self.rebuild_folder_tree_preserving_state(folder)
        self.reset_metadata_below_folder(folder)
        self.status_label.set_text(
            f"Serienordner zugeordnet: {folder.name} → {title}. Metadaten werden neu geprüft."
        )
        videos = [path for path in self.videos if path == folder or folder in path.parents]
        self.start_metadata_scan(videos, empty_message="Keine Dateien in diesem Serienordner gefunden.")

    def choose_series_candidate_dialog(self, folder, search_title, ranked):
        dialog = Gtk.Dialog(
            title="TMDb-Serie auswählen",
            transient_for=self,
            modal=True,
        )
        dialog.add_buttons(Gtk.STOCK_CANCEL, Gtk.ResponseType.CANCEL, "Zuordnen", Gtk.ResponseType.OK)
        dialog.set_default_size(760, 440)
        area = dialog.get_content_area()
        area.set_border_width(12)
        area.set_spacing(10)
        heading = Gtk.Label(label=f"Ordner: {folder}\nSuchbegriff: {search_title}")
        heading.set_xalign(0)
        heading.set_line_wrap(True)
        area.pack_start(heading, False, False, 0)

        store = Gtk.ListStore(int, str, str, str, float, str)
        for score, item in ranked:
            date = item.get("first_air_date") or ""
            store.append([
                int(item.get("id") or 0),
                str(item.get("name") or "–"),
                str(item.get("original_name") or "–"),
                date[:4] if len(date) >= 4 else "–",
                float(score),
                str(item.get("poster_path") or ""),
            ])
        tree = Gtk.TreeView(model=store)
        for title, column, width in (
            ("Titel", 1, 250), ("Originaltitel", 2, 220), ("Jahr", 3, 70), ("Treffer", 4, 80)
        ):
            renderer = Gtk.CellRendererText()
            tvcol = Gtk.TreeViewColumn(title, renderer, text=column)
            tvcol.set_min_width(width)
            tree.append_column(tvcol)
        if len(store):
            tree.get_selection().select_path(0)
        tree.connect("row-activated", lambda *_: dialog.response(Gtk.ResponseType.OK))
        scroll = Gtk.ScrolledWindow()
        scroll.set_policy(Gtk.PolicyType.AUTOMATIC, Gtk.PolicyType.AUTOMATIC)
        scroll.add(tree)
        area.pack_start(scroll, True, True, 0)
        dialog.show_all()
        response = dialog.run()
        model, tree_iter = tree.get_selection().get_selected()
        result = None
        if response == Gtk.ResponseType.OK and tree_iter is not None:
            result = (
                int(model[tree_iter][0]),
                str(model[tree_iter][1]),
                str(model[tree_iter][2]),
                str(model[tree_iter][3]),
                str(model[tree_iter][5]),
            )
        dialog.destroy()
        return result

    def reset_metadata_below_folder(self, folder):
        folder = Path(folder)
        for path, record in self.library_records.items():
            media_path = Path(path)
            if media_path.parent == folder or folder in media_path.parents:
                record["metadata"] = self.default_metadata()
        self.save_index(show_errors=False)

    def remove_series_folder_mapping(self, folder):
        if str(folder) not in self.series_folder_mappings:
            return
        dialog = Gtk.MessageDialog(
            transient_for=self,
            modal=True,
            message_type=Gtk.MessageType.QUESTION,
            buttons=Gtk.ButtonsType.YES_NO,
            text="TMDb-Serienzuordnung entfernen?",
        )
        dialog.format_secondary_text(
            f"{folder}\n\nVorhandene Dateinamen und Mediendateien bleiben unverändert."
        )
        response = dialog.run()
        dialog.destroy()
        if response != Gtk.ResponseType.YES:
            return
        del self.series_folder_mappings[str(folder)]
        self.save_config()
        self.rebuild_folder_tree_preserving_state(folder)
        self.status_label.set_text("TMDb-Serienzuordnung wurde entfernt.")

    def on_folder_selected(self, selection):
        # Eine programmgesteuerte Synchronisierung von Suchtreffern soll nur
        # den Baum sichtbar nachführen. Sie darf weder die Suche beenden noch
        # die Trefferansicht neu aufbauen.
        if self.synchronizing_tree_selection:
            return

        # Ein bewusster Wechsel durch den Benutzer beendet globale Sonderansichten.
        if self.search_query:
            self.search_query = ""
        if self.personal_view != "Ordneransicht":
            self.personal_view = "Ordneransicht"
            self.active_playlist_name = None
            item = self.personal_view_menu_items.get("Ordneransicht")
            if item and not item.get_active():
                item.set_active(True)
        model, tree_iter = selection.get_selected()
        if tree_iter is None:
            return
        self.selected_folder = Path(model[tree_iter][1])
        self.last_selected_folder = self.selected_folder
        self.schedule_config_save()
        self.refresh_visible_videos()
        self.update_detail_panel(folder=self.selected_folder)

    # ------------------------------------------------------------------
    # Sortierung, Suche und Auswahl
    # ------------------------------------------------------------------
    def on_personal_view_toggled(self, menu_item, name):
        """Schaltet zwischen Ordneransicht und persönlichen Sammlungen."""
        if not menu_item.get_active():
            return
        self.personal_view = name
        if name != "Aktuelle Playlist":
            self.active_playlist_name = None
        self.search_query = ""
        self.refresh_visible_videos()

    def video_matches_personal_view(self, video_path, playlist_membership=None):
        """Prüft Favorit, Fortschritt und Wiedergabestatus eines Videos."""
        if self.personal_view == "Ordneransicht":
            return True

        personal = self.personal_for_path(video_path)
        position = float(
            personal.get("last_position_seconds") or 0
        )
        completed = bool(personal.get("completed"))
        last_played = personal.get("last_played")

        if self.personal_view == "Aktuelle Playlist":
            if not self.active_playlist_name:
                return False
            if playlist_membership is None:
                playlist_membership = set(
                    self.playlists.get(self.active_playlist_name, [])
                )
            return str(video_path) in playlist_membership
        if self.personal_view == "Favoriten":
            return bool(personal.get("favorite"))
        if self.personal_view == "Bewertet":
            return int(personal.get("rating") or 0) > 0
        if self.personal_view == "Unbewertet":
            return int(personal.get("rating") or 0) <= 0
        if self.personal_view == "Angefangen":
            return position > 0 and not completed
        if self.personal_view == "Ungesehen":
            return position <= 0 and not completed
        if self.personal_view == "Gesehen":
            return completed
        if self.personal_view == "Zuletzt abgespielt":
            return bool(last_played)
        return True

    def sort_personal_view_videos(self, videos):
        """Sortiert persönliche Ansichten; zuletzt abgespielt ist eine feste Chronik."""
        if self.personal_view == "Zuletzt abgespielt":
            ordered = sorted(
                videos,
                key=lambda path: int(self.personal_for_path(path).get("last_played") or 0),
                reverse=True,
            )
            return ordered[: self.recently_played_limit]
        return self.sort_videos(videos)

