    def technical_for_path(self, path):
        return (
            self.library_records.get(str(path), {}).get("technical")
            or self.default_technical()
        )

    @staticmethod
    def resolution_category(technical):
        width = technical.get("width")
        height = technical.get("height")
        if not isinstance(width, int) or not isinstance(height, int):
            return "Unbekannt"
        longest = max(width, height)
        shortest = min(width, height)
        if longest >= 3000 or shortest >= 1800:
            return "4K / UHD"
        if longest >= 1900 or shortest >= 1000:
            return "Full HD"
        if longest >= 1200 or shortest >= 700:
            return "HD"
        return "SD"

    @staticmethod
    def codec_category(technical):
        codec = str(technical.get("video_codec") or "").strip().lower()
        if not codec:
            return "Unbekannt"
        if codec in {"hevc", "h265", "h.265"}:
            return "H.265 / HEVC"
        if codec in {"h264", "avc", "h.264"}:
            return "H.264 / AVC"
        if codec in {"mpeg4", "msmpeg4v1", "msmpeg4v2", "msmpeg4v3"}:
            return "MPEG-4"
        return "Andere"

    def matches_technical_filters(self, path):
        """Prüft die gespeicherten ffprobe-Daten gegen die aktiven Filter."""
        technical = self.technical_for_path(path)
        if (
            self.resolution_filter != "Alle"
            and self.resolution_category(technical) != self.resolution_filter
        ):
            return False
        if (
            self.codec_filter != "Alle"
            and self.codec_category(technical) != self.codec_filter
        ):
            return False
        return True

    def sort_videos(self, videos):
        if self.sort_mode == "Dateiname":
            key_func = lambda path: path.name.lower()
        elif self.sort_mode == "Änderungsdatum":
            key_func = lambda path: self.safe_stat_value(path, "st_mtime_ns")
        elif self.sort_mode == "Dateigröße":
            key_func = lambda path: self.safe_stat_value(path, "st_size")
        elif self.sort_mode == "Laufzeit":
            key_func = lambda path: (
                self.technical_for_path(path).get("duration_seconds") or -1
            )
        elif self.sort_mode == "Auflösung":
            key_func = lambda path: (
                (self.technical_for_path(path).get("width") or 0)
                * (self.technical_for_path(path).get("height") or 0)
            )
        elif self.sort_mode == "Bewertung":
            key_func = lambda path: (
                int(self.personal_for_path(path).get("rating") or 0),
                self.pretty_title(path).casefold(),
            )
        elif self.sort_mode == "Wiedergabefortschritt":
            def key_func(path):
                personal = self.personal_for_path(path)
                position = float(personal.get("last_position_seconds") or 0.0)
                duration = float(
                    self.technical_for_path(path).get("duration_seconds")
                    or personal.get("playback_duration_seconds")
                    or 0.0
                )
                percent = position / duration if duration > 0 else 0.0
                return (percent, self.pretty_title(path).casefold())
        else:
            key_func = lambda path: self.pretty_title(path).lower()
        return sorted(videos, key=key_func, reverse=self.sort_descending)

    @staticmethod
    def safe_stat_value(path, attribute):
        try:
            return getattr(path.stat(), attribute)
        except OSError:
            return 0

    @staticmethod
    def normalize_library_search_text(value):
        """Normalisiert Suchtexte unabhängig von Großschreibung und Akzenten."""
        value = unicodedata.normalize("NFKD", str(value or ""))
        value = "".join(
            char for char in value
            if not unicodedata.combining(char)
        )
        value = value.casefold()
        value = re.sub(r"[^\w]+", " ", value, flags=re.UNICODE)
        return re.sub(r"\s+", " ", value).strip()

    def video_search_fields(self, video_path):
        """Liefert getrennte, verlässliche Suchfelder eines Videos.

        Die Felder bleiben bewusst getrennt. So kann ein mehrteiliger Suchtext
        nicht aus zufälligen Wortteilen verschiedener Metadatenfelder
        zusammengesetzt werden.
        """
        record = self.library_records.get(str(video_path), {})
        metadata = record.get("metadata") or {}

        fields = [
            video_path.name,
            video_path.stem,
            self.pretty_title(video_path),
        ]

        if metadata.get("status") == "found":
            fields.extend([
                metadata.get("title"),
                metadata.get("original_title"),
                metadata.get("year"),
            ])
            for field_name in ("director", "cast", "genres"):
                field_value = metadata.get(field_name)
                if isinstance(field_value, (list, tuple, set)):
                    fields.extend(field_value)
                elif field_value:
                    fields.append(field_value)

        return [
            self.normalize_library_search_text(value)
            for value in fields
            if value
        ]

    def video_matches_library_search(self, video_path, query):
        """Prüft eine zusammenhängende Suchphrase pro einzelnem Datenfeld."""
        normalized_query = self.normalize_library_search_text(query)
        if not normalized_query:
            return True

        # Eine Suche wie »die firma« muss in genau dieser Reihenfolge innerhalb
        # eines einzelnen Feldes vorkommen. Die Wörter dürfen nicht mehr
        # unabhängig aus Titel, Genre und Darsteller zusammengesammelt werden.
        return any(
            normalized_query in field
            for field in self.video_search_fields(video_path)
        )

    def searchable_library_folders(self):
        """Liefert den beim Bibliotheksaufbau erzeugten Ordner-Cache."""
        if self.library_folder_cache is None:
            self.rebuild_library_lookup_caches()
        return self.library_folder_cache

    def folder_matches_library_search(self, folder, query):
        """Prüft Ordnername und Pfad unabhängig von Groß-/Kleinschreibung."""
        normalized_query = self.normalize_library_search_text(query)
        if not normalized_query:
            return True
        searchable = self.normalize_library_search_text(
            f"{Path(folder).name} {Path(folder)}"
        )
        return all(token in searchable for token in normalized_query.split())

    def refresh_visible_videos(self, preserve_selection=None):
        # Der erste Aufbau einer Sitzung startet garantiert ungefiltert. Damit
        # kann ein alter Such- oder Technikfilter keinen scheinbar leeren
        # Ordner erzeugen, obwohl der Bibliotheksindex Videos enthält.
        if not getattr(self, "startup_view_initialized", False):
            self.personal_view = "Ordneransicht"
            self.search_query = ""
            self.resolution_filter = "Alle"
            self.codec_filter = "Alle"
            self.startup_view_initialized = True

        # Sammelaktionen dürfen die aktuelle Auswahl über den notwendigen
        # Kachel-Neuaufbau hinweg erhalten. Ordnerwechsel und normale Aktualisierungen
        # übergeben dagegen keine Auswahl und starten wie bisher ohne Markierung.
        preserved_paths = {
            str(Path(path)) for path in (preserve_selection or [])
        }

        # Jeder Neuaufbau erhält eine eigene Generation. Noch laufende oder
        # eingereihte Aufträge älterer Ordner dürfen den Fortschritt und die
        # sichtbaren Kacheln der neuen Ansicht nicht mehr beeinflussen.
        self.thumbnail_view_generation += 1
        if self.thumbnail_live_source_id is not None:
            GLib.source_remove(self.thumbnail_live_source_id)
            self.thumbnail_live_source_id = None
        self.clear_flowbox()
        self.thumbnail_batch_generated = False
        self.visible_video_tiles = {}
        self.selected_video = None
        self.selected_videos = []
        self.selected_tile_folder = None
        self.selection_anchor_child = None
        self.selection_anchor_index = None
        self.selection_cursor_index = None
        self.update_film_menu_state()
        if self.selected_folder is None:
            return

        query = self.search_query.strip()

        # Ohne Suchbegriff bleibt die gewohnte Ordneransicht erhalten. Bei
        # aktiver Suche werden dagegen alle Videos der gesamten Bibliothek
        # geprüft; zuvor war die Suche fälschlich auf den aktuellen Ordner
        # begrenzt.
        if query:
            # Globale Suche zeigt passende Ordner und passende Videos.
            subfolders = sorted(
                [
                    folder
                    for folder in self.searchable_library_folders()
                    if self.folder_matches_library_search(folder, query)
                ],
                key=lambda path: str(path).casefold(),
            )
            candidate_videos = self.videos
        elif self.personal_view != "Ordneransicht":
            subfolders = []
            candidate_videos = self.videos
        else:
            subfolders = self.direct_visible_subfolders(
                self.selected_folder
            )
            candidate_videos = list(
                self.videos_by_parent.get(self.selected_folder, ())
            )

        playlist_membership = (
            set(self.playlists.get(self.active_playlist_name, []))
            if self.personal_view == "Aktuelle Playlist"
            and self.active_playlist_name
            else None
        )
        matches = []
        for video in candidate_videos:
            if query and not self.video_matches_library_search(video, query):
                continue
            if (
                not query
                and self.personal_view != "Ordneransicht"
                and not self.video_matches_personal_view(
                    video, playlist_membership
                )
            ):
                continue
            if not self.matches_technical_filters(video):
                continue
            matches.append(video)

        matches = self.sort_personal_view_videos(matches)
        # Der aktuell geöffnete Serien- oder Staffelordner darf nicht noch
        # einmal als Kachel in sich selbst erscheinen. Seine Poster werden
        # bereits an der normalen Unterordnerkachel im Elternordner verwendet.
        exact_mapping = None
        season_context = None
        extra_tiles = 0
        self.thumb_total = len(subfolders) + len(matches) + extra_tiles
        self.thumb_done = 0
        self.thumb_failed = 0
        self.visible_thumbnail_started_at = time.monotonic()
        if exact_mapping:
            self.flowbox.add(
                self.create_series_folder_tile(self.selected_folder, exact_mapping)
            )
        elif season_context:
            mapping, season_number = season_context
            self.flowbox.add(
                self.create_season_folder_tile(
                    self.selected_folder, mapping, season_number
                )
            )
        for folder in subfolders:
            self.flowbox.add(self.create_subfolder_tile(folder))
        for video in matches:
            self.flowbox.add(self.create_video_tile(video))
        self.flowbox.show_all()

        # Die nach einer Sammelaktion weiterhin sichtbaren Videos werden wieder
        # markiert. In gefilterten persönlichen Ansichten bleiben nur diejenigen
        # ausgewählt, die nach der Änderung noch zur Ansicht gehören.
        restored_children = []
        if preserved_paths:
            for child in self.flowbox.get_children():
                video_path = getattr(child, "video_path", None)
                if video_path and str(Path(video_path)) in preserved_paths:
                    self.flowbox.select_child(child)
                    restored_children.append(child)

            if restored_children:
                self.selection_anchor_child = restored_children[0]
                self.selection_anchor_index = self.flowbox_child_index(
                    restored_children[0]
                )
                self.selection_cursor_index = self.flowbox_child_index(
                    restored_children[-1]
                )

        self.start_thumbnail_live_refresh()

        # Bei genau einem eindeutigen Suchergebnis folgt der Ordnerbaum sofort
        # automatisch. Bei mehreren Treffern bleibt die Auswahl offen, bis der
        # Benutzer einen konkreten Treffer anklickt.
        if query:
            unique_target_folder = None
            if len(matches) == 1 and not subfolders:
                unique_target_folder = Path(matches[0]).parent
            elif len(subfolders) == 1 and not matches:
                unique_target_folder = Path(subfolders[0])
            elif len(matches) == 1 and len(subfolders) == 1:
                video_parent = Path(matches[0]).parent
                folder_target = Path(subfolders[0])
                if video_parent == folder_target:
                    unique_target_folder = folder_target

            if unique_target_folder is not None:
                self.synchronize_tree_to_folder(unique_target_folder)

        folder_label = self.selected_folder.name or str(self.selected_folder)
        if self.search_query:
            status_parts = [
                f"{len(subfolders)} Ordner und {len(matches)} Videos "
                "in der gesamten Bibliothek"
            ]
            status_parts.append(f"Suche: „{self.search_query}“")
        elif self.personal_view != "Ordneransicht":
            status_parts = [
                f"{len(matches)} Videos in „{self.active_playlist_name or self.personal_view}“"
            ]
        else:
            status_parts = [
                f"{len(subfolders)} Unterordner, "
                f"{len(matches)} Filme in „{folder_label}“"
            ]
        active_filters = []
        if self.resolution_filter != "Alle":
            active_filters.append(self.resolution_filter)
        if self.codec_filter != "Alle":
            active_filters.append(self.codec_filter)
        if active_filters:
            status_parts.append(f"Filter: {', '.join(active_filters)}")
        direction = "absteigend" if self.sort_descending else "aufsteigend"
        status_parts.append(f"Sortierung: {self.sort_mode}, {direction}")
        self.status_label.set_text(" – ".join(status_parts))
        if not matches and not subfolders:
            self.progress_bar.set_fraction(0.0)
            self.progress_bar.set_text("Keine Treffer")
            if self.search_query:
                self.status_label.set_text(
                    f"Keine Treffer für „{self.search_query}“. "
                    "Ein Ordnerwechsel beendet die Suche automatisch."
                )
            elif self.personal_view != "Ordneransicht":
                self.status_label.set_text(
                    f"Die Ansicht „{self.active_playlist_name or self.personal_view}“ ist leer."
                )

    def direct_visible_subfolders(self, folder, query=""):
        """Liefert direkt enthaltene, sichtbare Unterordner alphabetisch sortiert."""
        try:
            folders = [
                path for path in Path(folder).iterdir()
                if path.is_dir() and not path.name.startswith(".")
            ]
        except OSError:
            return []
        if query:
            folders = [path for path in folders if query in path.name.lower()]
        return sorted(folders, key=lambda path: path.name.casefold())

    def on_flowbox_background_click(self, flowbox, event):
        """Hebt bei einem Klick auf freien Kachelraum die Auswahl auf."""
        if event.button != 1:
            return False
        child = flowbox.get_child_at_pos(int(event.x), int(event.y))
        if child is None:
            flowbox.unselect_all()
            self.selection_anchor_child = None
            self.selection_anchor_index = None
            self.selection_cursor_index = None
            self.selected_video = None
            self.selected_videos = []
            self.selected_tile_folder = None
            self.update_film_menu_state()
            if self.selected_folder:
                self.update_detail_panel(folder=self.selected_folder)
            else:
                self.clear_detail_panel()
            self.status_label.set_text("Auswahl aufgehoben.")
            return True
        return False

    def selected_action_videos(self):
        """Liefert die Videos, auf die eine Einzel- oder Sammelaktion wirkt."""
        return [Path(path) for path in self.selected_videos]

    def apply_personal_batch(self, videos, *, favorite=None, rating=None,
                             completed=None, reset_progress=False):
        """Ändert persönliche Daten mehrerer Videos in einem Speichervorgang."""
        changed = 0
        for video in videos:
            record = self.library_records.get(str(Path(video)))
            if record is None:
                continue
            self.normalize_record(record)
            personal = record["personal"]

            if favorite is not None:
                personal["favorite"] = bool(favorite)
            if rating is not None:
                personal["rating"] = max(0, min(5, int(rating)))
            if completed is not None:
                personal["completed"] = bool(completed)
                personal["completion_source"] = (
                    "manual" if completed else None
                )
                if completed:
                    duration = float(
                        personal.get("playback_duration_seconds")
                        or self.technical_for_path(video).get(
                            "duration_seconds"
                        )
                        or 0
                    )
                    if duration > 0:
                        personal["last_position_seconds"] = duration
                else:
                    personal["last_position_seconds"] = 0.0
                    personal["last_played"] = None
            if reset_progress:
                personal["last_position_seconds"] = 0.0
                personal["completed"] = False
                personal["completion_source"] = None
                personal["last_played"] = None
            changed += 1

        if changed:
            self.save_index(show_errors=False)
            self.refresh_visible_videos(
                preserve_selection=[Path(video) for video in videos]
            )
        return changed

    def selected_flowbox_videos(self):
        """Liefert alle aktuell markierten Videokacheln in Anzeigereihenfolge."""
        return [
            Path(child.video_path)
            for child in self.flowbox.get_selected_children()
            if getattr(child, "video_path", None)
        ]

    def flowbox_child_index(self, child):
        """Ermittelt den stabilen Anzeigeindex einer Kachel."""
        try:
            return int(child.get_index())
        except (AttributeError, TypeError, ValueError):
            try:
                return self.flowbox.get_children().index(child)
            except ValueError:
                return None

    def select_video_child_from_event(self, child, event):
        """Setzt eine übliche Mehrfachauswahl für Videokacheln.

        Strg-Klick schaltet einzelne Kacheln um. Shift-Klick markiert alle
        Videokacheln zwischen dem gespeicherten Anker und der aktuellen Kachel.
        Ein normaler Klick ersetzt die bestehende Auswahl.
        """
        ctrl = bool(event.state & Gdk.ModifierType.CONTROL_MASK)
        shift = bool(event.state & Gdk.ModifierType.SHIFT_MASK)
        selected = set(self.flowbox.get_selected_children())
        current_index = self.flowbox_child_index(child)

        if shift and self.selection_anchor_index is not None:
            children = self.flowbox.get_children()
            if current_index is not None:
                if not ctrl:
                    self.flowbox.unselect_all()
                first, last = sorted(
                    (self.selection_anchor_index, current_index)
                )
                for candidate in children[first:last + 1]:
                    if getattr(candidate, "video_path", None):
                        self.flowbox.select_child(candidate)
                self.selection_cursor_index = current_index
                return

        if ctrl:
            if child in selected:
                self.flowbox.unselect_child(child)
            else:
                self.flowbox.select_child(child)
            self.selection_anchor_child = child
            self.selection_anchor_index = current_index
            self.selection_cursor_index = current_index
            return

        self.flowbox.unselect_all()
        self.flowbox.select_child(child)
        self.selection_anchor_child = child
        self.selection_anchor_index = current_index
        self.selection_cursor_index = current_index

    def select_folder_child(self, child):
        """Ordnerkacheln bleiben Einzelziele und beenden eine Videoauswahl."""
        self.flowbox.unselect_all()
        self.flowbox.select_child(child)
        self.selection_anchor_child = child
        self.selection_anchor_index = self.flowbox_child_index(child)
        self.selection_cursor_index = self.selection_anchor_index

    def on_selection_changed(self, flowbox):
        selected = flowbox.get_selected_children()
        videos = [
            Path(child.video_path)
            for child in selected
            if getattr(child, "video_path", None)
        ]
        folders = [
            Path(child.folder_path)
            for child in selected
            if getattr(child, "folder_path", None)
        ]

        self.selected_videos = videos
        self.selected_video = videos[0] if len(videos) == 1 else None
        self.selected_tile_folder = (
            folders[0] if len(folders) == 1 and not videos else None
        )
        self.update_film_menu_state()

        if len(videos) > 1:
            self.status_label.set_text(
                f"{len(videos)} Videos ausgewählt"
            )
            self.show_multiple_video_details(videos)
        elif self.selected_video:
            if self.search_query:
                self.synchronize_tree_to_folder(
                    self.selected_video.parent
                )
            self.status_label.set_text(
                f"Ausgewählt: {self.pretty_title(self.selected_video)}"
            )
            self.update_detail_panel(video=self.selected_video)
        elif self.selected_tile_folder:
            if self.search_query:
                self.synchronize_tree_to_folder(
                    self.selected_tile_folder
                )
            self.status_label.set_text(
                f"Ordner ausgewählt: {self.selected_tile_folder.name}"
            )
            self.update_detail_panel(folder=self.selected_tile_folder)
        elif self.selected_folder:
            self.update_detail_panel(folder=self.selected_folder)
        else:
            self.clear_detail_panel()

    def on_toggle_selected_favorite(self, _widget):
        videos = self.selected_action_videos()
        if not videos:
            return
        all_favorites = all(
            bool(self.personal_for_path(video).get("favorite"))
            for video in videos
        )
        changed = self.apply_personal_batch(
            videos, favorite=not all_favorites
        )
        if changed:
            action = (
                "Aus Favoriten entfernt"
                if all_favorites else "Zu Favoriten hinzugefügt"
            )
            self.status_label.set_text(
                f"{action}: {changed} Video(s)"
            )

    def on_selected_rating_toggled(self, menu_item, value):
        if self.updating_menu_state or not menu_item.get_active():
            return
        videos = self.selected_action_videos()
        if not videos:
            return
        changed = self.apply_personal_batch(videos, rating=value)
        if changed:
            self.status_label.set_text(
                f"Bewertung {value}/5 für {changed} Video(s) gespeichert."
            )

    def on_mark_selected_seen(self, _widget):
        videos = self.selected_action_videos()
        changed = self.apply_personal_batch(
            videos, completed=True
        )
        if changed:
            self.status_label.set_text(
                f"{changed} Video(s) als gesehen markiert."
            )

    def on_mark_selected_unseen(self, _widget):
        videos = self.selected_action_videos()
        changed = self.apply_personal_batch(
            videos, completed=False
        )
        if changed:
            self.status_label.set_text(
                f"{changed} Video(s) als ungesehen markiert."
            )

    def on_reset_selected_progress(self, _widget):
        videos = self.selected_action_videos()
        changed = self.apply_personal_batch(
            videos, reset_progress=True
        )
        if changed:
            self.status_label.set_text(
                f"Wiedergabefortschritt für {changed} Video(s) zurückgesetzt."
            )

    def on_show_selected_metadata(self, _widget):
        if len(self.selected_videos) == 1:
            self.show_metadata_info(self.selected_videos[0])

    def on_edit_selected_search_data(self, _widget):
        if len(self.selected_videos) == 1:
            self.edit_intelligent_search_data(self.selected_videos[0])

    def on_rescan_selected_metadata(self, _widget):
        if len(self.selected_videos) == 1:
            self.rescan_single_metadata(self.selected_videos[0])

    def update_film_menu_state(self):
        """Synchronisiert alle auswahlabhängigen Hauptmenüs zentral."""
        selected_count = len(self.selected_videos)
        single_video = selected_count == 1
        video = self.selected_videos[0] if single_video else None

        metadata_found = False
        has_progress = False
        favorite = False
        rating = 0

        if video is not None:
            record = self.library_records.get(str(video)) or {}
            self.normalize_record(record)
            metadata = record.get("metadata") or {}
            personal = record.get("personal") or self.default_personal()
            metadata_found = metadata.get("status") == "found"
            has_progress = (
                float(personal.get("last_position_seconds") or 0) > 0
            )
            favorite = bool(personal.get("favorite"))
            rating = int(personal.get("rating") or 0)

        # Einzeldateiaktionen.
        for name in (
            "play_menu_item",
            "reveal_file_menu_item",
            "open_folder_menu_item",
            "copy_path_menu_item",
        ):
            item = getattr(self, name, None)
            if item:
                item.set_sensitive(single_video)

        # Das Film-Menü unterstützt Einzel- und Sammelaktionen.
        if hasattr(self, "film_top_menu_item"):
            self.film_top_menu_item.set_sensitive(selected_count > 0)
        if hasattr(self, "favorite_menu_item"):
            self.favorite_menu_item.set_sensitive(selected_count > 0)
            all_favorites = (
                selected_count > 0
                and all(
                    bool(self.personal_for_path(path).get("favorite"))
                    for path in self.selected_videos
                )
            )
            self.favorite_menu_item.set_label(
                "Aus Favoriten entfernen"
                if all_favorites else "Zu Favoriten hinzufügen"
            )

        if hasattr(self, "rating_menu_item"):
            self.rating_menu_item.set_sensitive(selected_count > 0)

        any_progress = any(
            float(
                self.personal_for_path(path).get(
                    "last_position_seconds"
                ) or 0
            ) > 0
            for path in self.selected_videos
        )
        if hasattr(self, "reset_progress_menu_item"):
            self.reset_progress_menu_item.set_sensitive(
                selected_count > 0 and any_progress
            )
        if hasattr(self, "mark_seen_menu_item"):
            self.mark_seen_menu_item.set_sensitive(selected_count > 0)
        if hasattr(self, "mark_unseen_menu_item"):
            self.mark_unseen_menu_item.set_sensitive(selected_count > 0)

        if hasattr(self, "metadata_info_menu_item"):
            self.metadata_info_menu_item.set_sensitive(
                single_video and metadata_found
            )

        for name in (
            "intelligent_search_menu_item",
            "metadata_rescan_menu_item",
        ):
            item = getattr(self, name, None)
            if item:
                item.set_sensitive(single_video)

        # Radioeinträge werden nur optisch synchronisiert. Der Schutz verhindert,
        # dass set_active beim bloßen Auswahlwechsel eine Bewertung verändert.
        self.updating_menu_state = True
        try:
            for value, item in getattr(
                self, "rating_menu_items", {}
            ).items():
                item.set_active(single_video and value == rating)
        finally:
            self.updating_menu_state = False

        if hasattr(self, "add_to_playlist_menu_item"):
            self.add_to_playlist_menu_item.set_sensitive(selected_count > 0)

        # Wiedergabe und Metadaten bleiben Einzelaktionen; ihre Einträge
        # sind bei Mehrfachauswahl bereits einzeln deaktiviert.

    def show_multiple_video_details(self, videos):
        """Zeigt eine kompakte Zusammenfassung einer Mehrfachauswahl."""
        if not self.detail_panel_visible:
            return

        total_duration = 0.0
        favorites = 0
        completed = 0
        ratings = []

        for video in videos:
            technical = self.technical_for_path(video)
            personal = self.personal_for_path(video)
            total_duration += float(
                technical.get("duration_seconds")
                or personal.get("playback_duration_seconds")
                or 0
            )
            favorites += int(bool(personal.get("favorite")))
            completed += int(bool(personal.get("completed")))
            rating = int(personal.get("rating") or 0)
            if rating:
                ratings.append(rating)

        self.detail_title_label.set_markup(
            f"<b>{len(videos)} Videos ausgewählt</b>"
        )
        self.set_scaled_placeholder_icon(
            self.detail_image, "video-x-generic", 260, 146
        )

        lines = [
            f"Gesamtlaufzeit: {self.seconds_to_readable_duration(total_duration)}"
            if total_duration else "Gesamtlaufzeit: nicht vollständig erfasst",
            f"Favoriten: {favorites}",
            f"Als gesehen markiert: {completed}",
            (
                f"Bewertung: durchschnittlich {sum(ratings) / len(ratings):.1f}/5"
                if ratings else "Bewertung: keine bewerteten Videos"
            ),
            "",
            "Sammelaktionen wirken auf die gesamte Auswahl.",
            "",
            "Ausgewählt:",
        ]
        preview_names = [
            self.pretty_title(video) for video in videos[:12]
        ]
        lines.extend(f"• {name}" for name in preview_names)
        if len(videos) > len(preview_names):
            lines.append(
                f"• … und {len(videos) - len(preview_names)} weitere"
            )
        split_at = lines.index("Ausgewählt:") if "Ausgewählt:" in lines else len(lines)
        self.set_detail_sections(
            overview="\n".join(lines[:split_at]).strip(),
            media="\n".join(lines[split_at:]).strip(),
        )

    def build_detail_panel(self):
        """Erzeugt den gegliederten Informationsbereich rechts."""
        outer = Gtk.Box(orientation=Gtk.Orientation.VERTICAL, spacing=10)
        outer.set_border_width(12)
        self.detail_scrolled.add(outer)

        heading = Gtk.Label()
        heading.set_markup("<b>Details</b>")
        heading.set_xalign(0)
        outer.pack_start(heading, False, False, 0)

        self.detail_image = Gtk.Image()
        self.detail_image.set_size_request(260, 146)
        outer.pack_start(self.detail_image, False, False, 0)

        self.detail_title_label = Gtk.Label(label="Keine Auswahl")
        self.detail_title_label.set_xalign(0)
        self.detail_title_label.set_line_wrap(True)
        self.detail_title_label.set_selectable(True)
        outer.pack_start(self.detail_title_label, False, False, 0)

        separator = Gtk.Separator(orientation=Gtk.Orientation.HORIZONTAL)
        outer.pack_start(separator, False, False, 0)

        self.detail_section_labels = {}
        for key, title in (
            ("overview", "Übersicht"),
            ("media", "Medieninformationen"),
            ("technical", "Technische Daten"),
            ("description", "Beschreibung"),
            ("path", "Speicherort"),
        ):
            expander = Gtk.Expander(label=title)
            expander.set_expanded(key in {"overview", "media"})
            label = Gtk.Label(label="")
            label.set_xalign(0)
            label.set_yalign(0)
            label.set_line_wrap(True)
            label.set_selectable(True)
            label.set_margin_top(6)
            label.set_margin_bottom(6)
            label.set_margin_start(8)
            label.set_margin_end(4)
            expander.add(label)
            outer.pack_start(expander, False, False, 0)
            self.detail_section_labels[key] = label

        # Kompatibilitätsalias für ältere Aktualisierungspfade innerhalb dieser Version.
        self.detail_text_label = self.detail_section_labels["overview"]
        self.clear_detail_panel()

    def set_detail_sections(self, *, overview="", media="", technical="", description="", path=""):
        """Füllt die gegliederten Detailabschnitte und blendet leere Inhalte aus."""
        values = {
            "overview": overview,
            "media": media,
            "technical": technical,
            "description": description,
            "path": path,
        }
        for key, label in self.detail_section_labels.items():
            text = str(values.get(key) or "").strip()
            label.set_text(text)
            parent = label.get_parent()
            if parent:
                parent.set_visible(bool(text))

    def on_detail_panel_toggled(self, menu_item):
        self.detail_panel_visible = menu_item.get_active()
        if hasattr(self, "detail_scrolled"):
            self.detail_scrolled.set_visible(self.detail_panel_visible)
            if self.detail_panel_visible:
                self.detail_paned.set_position(self.detail_paned_position)
                if len(self.selected_videos) > 1:
                    self.show_multiple_video_details(self.selected_videos)
                elif self.selected_video:
                    self.update_detail_panel(video=self.selected_video)
                elif self.selected_tile_folder:
                    self.update_detail_panel(folder=self.selected_tile_folder)
                elif self.selected_folder:
                    self.update_detail_panel(folder=self.selected_folder)
        self.save_config()

    def clear_detail_panel(self):
        if not hasattr(self, "detail_title_label"):
            return
        self.detail_title_label.set_markup("<b>Keine Auswahl</b>")
        self.set_detail_sections(overview="Wähle einen Film oder Ordner aus.")
        self.set_scaled_placeholder_icon(self.detail_image, "video-x-generic", 260, 146)

    @staticmethod
    def format_file_size(size_bytes):
        try:
            value = float(size_bytes)
        except (TypeError, ValueError):
            return "nicht verfügbar"
        units = ("B", "KiB", "MiB", "GiB", "TiB")
        for unit in units:
            if value < 1024 or unit == units[-1]:
                return f"{value:.1f} {unit}" if unit != "B" else f"{int(value)} B"
            value /= 1024
        return "nicht verfügbar"

    def update_detail_panel(self, video=None, folder=None):
        if not self.detail_panel_visible or not hasattr(self, "detail_title_label"):
            return
        if video is not None:
            self.show_video_details_in_panel(Path(video))
        elif folder is not None:
            self.show_folder_details_in_panel(Path(folder))
        else:
            self.clear_detail_panel()

    def show_video_details_in_panel(self, video_path):
        record = self.library_records.get(str(video_path)) or {}
        metadata = record.get("metadata") or self.default_metadata()
        technical = record.get("technical") or self.default_technical()
        personal = record.get("personal") or self.default_personal()
        title = metadata.get("title") or self.pretty_title(video_path)
        self.detail_title_label.set_markup(f"<b>{GLib.markup_escape_text(str(title))}</b>")

        thumb_path = self.thumbnail_path(video_path)
        if thumb_path.exists():
            self.load_thumbnail(self.detail_image, thumb_path, 260, 146)
        else:
            self.set_scaled_placeholder_icon(self.detail_image, "video-x-generic", 260, 146)

        try:
            stat = video_path.stat()
            size_text = self.format_file_size(stat.st_size)
            modified = GLib.DateTime.new_from_unix_local(int(stat.st_mtime)).format("%d.%m.%Y %H:%M")
        except OSError:
            size_text = "nicht erreichbar"
            modified = "nicht erreichbar"

        duration = technical.get("duration_seconds") or metadata.get("runtime")
        duration_text = self.seconds_to_readable_duration(duration) if duration else "nicht erfasst"
        resolution = (
            f"{technical.get('width')} × {technical.get('height')}"
            if technical.get("width") and technical.get("height") else "nicht erfasst"
        )
        genres = ", ".join(metadata.get("genres") or []) or "nicht erfasst"
        lines = []
        if metadata.get("media_type") == "episode":
            episode_bits = []
            if metadata.get("series_title"):
                episode_bits.append(str(metadata.get("series_title")))
            if metadata.get("season_number") is not None and metadata.get("episode_number") is not None:
                episode_bits.append(f"S{int(metadata['season_number']):02d}E{int(metadata['episode_number']):02d}")
            if metadata.get("episode_title"):
                episode_bits.append(str(metadata.get("episode_title")))
            if episode_bits:
                lines.append("Episode: " + " · ".join(episode_bits))
        rating = int(personal.get("rating") or 0)
        rating_text = ("★" * rating + "☆" * (5 - rating)) if rating else "nicht bewertet"
        duration_value = float(duration or personal.get("playback_duration_seconds") or 0)
        position_value = float(personal.get("last_position_seconds") or 0)
        progress_percent = int(min(100, max(0, (position_value / duration_value * 100) if duration_value else 0)))
        position_text = self.seconds_to_readable_duration(position_value) if position_value else "noch nicht begonnen"
        overview_lines = list(lines)
        overview_lines.extend([
            f"Favorit: {'ja' if personal.get('favorite') else 'nein'}",
            f"Bewertung: {rating_text}",
            f"Wiedergabe: {progress_percent} % · {position_text}",
        ])
        media_lines = [
            f"Jahr: {metadata.get('year') or 'nicht erfasst'}",
            f"Genre: {genres}",
            f"Laufzeit: {duration_text}",
        ]
        technical_lines = [
            f"Datei: {video_path.name}",
            f"Auflösung: {resolution}",
            f"Videocodec: {technical.get('video_codec') or 'nicht erfasst'}",
            f"Größe: {size_text}",
            f"Geändert: {modified}",
            f"Technikdaten: {'vorhanden' if technical.get('status') == 'found' else 'fehlen'}",
            f"Metadaten: {'vorhanden' if metadata.get('status') == 'found' else 'fehlen'}",
        ]
        if metadata.get("manual_original_title"):
            media_lines.append(f"Suchalias/Originaltitel: {metadata.get('manual_original_title')}")
        if metadata.get("discovery_source"):
            media_lines.append(f"Suchquelle: {metadata.get('discovery_source')}")
        overview = str(metadata.get("overview") or "").strip()
        self.set_detail_sections(
            overview="\n".join(overview_lines),
            media="\n".join(media_lines),
            technical="\n".join(technical_lines),
            description=overview,
            path=str(video_path),
        )

    def folder_personal_for_path(self, folder):
        """Liefert Favoritenstatus und eigene Bewertung eines Ordners."""
        key = str(Path(folder))
        values = self.folder_personal.setdefault(
            key, {"favorite": False, "rating": 0}
        )
        values["favorite"] = bool(values.get("favorite", False))
        values["rating"] = max(
            0, min(5, int(values.get("rating") or 0))
        )
        return values

    def videos_in_folder(self, folder, recursive=True):
        """Liefert Videos direkt oder rekursiv unterhalb eines Ordners."""
        folder = Path(folder)
        if recursive:
            return [
                video for video in self.videos
                if video.parent == folder or folder in video.parents
            ]
        return list(self.videos_by_parent.get(folder, ()))

    def refresh_folder_personal_state(self, folder):
        """Speichert Ordnerwerte und aktualisiert Kacheln sowie Detailbereich."""
        self.save_config()
        self.refresh_visible_videos()
        if self.detail_panel_visible:
            self.update_detail_panel(folder=Path(folder))

    def set_folder_favorite(self, folder, favorite):
        personal = self.folder_personal_for_path(folder)
        personal["favorite"] = bool(favorite)
        self.refresh_folder_personal_state(folder)
        self.status_label.set_text(
            f"Ordner {'zu Favoriten hinzugefügt' if favorite else 'aus Favoriten entfernt'}: "
            f"{Path(folder).name}"
        )

    def set_folder_rating(self, folder, rating):
        personal = self.folder_personal_for_path(folder)
        personal["rating"] = max(0, min(5, int(rating)))
        self.refresh_folder_personal_state(folder)
        self.status_label.set_text(
            f"Ordnerbewertung gespeichert: {Path(folder).name} – "
            f"{personal['rating']}/5 Sterne"
        )

    def apply_folder_favorite_to_videos(self, folder):
        videos = self.videos_in_folder(folder, recursive=True)
        if not videos:
            self.status_label.set_text("Dieser Ordner enthält keine Videos.")
            return
        favorite = bool(
            self.folder_personal_for_path(folder).get("favorite")
        )
        changed = self.apply_personal_batch(
            videos, favorite=favorite
        )
        self.status_label.set_text(
            f"Favoritenstatus des Ordners auf {changed} Video(s) angewendet."
        )

    def apply_folder_rating_to_videos(self, folder):
        videos = self.videos_in_folder(folder, recursive=True)
        if not videos:
            self.status_label.set_text("Dieser Ordner enthält keine Videos.")
            return
        rating = int(
            self.folder_personal_for_path(folder).get("rating") or 0
        )
        changed = self.apply_personal_batch(
            videos, rating=rating
        )
        self.status_label.set_text(
            f"Ordnerbewertung {rating}/5 auf {changed} Video(s) angewendet."
        )

    def show_folder_details_in_panel(self, folder):
        self.detail_title_label.set_markup(f"<b>{GLib.markup_escape_text(folder.name or str(folder))}</b>")
        direct_videos = [video for video in self.videos if video.parent == folder]
        all_videos = [video for video in self.videos if video.parent == folder or folder in video.parents]
        try:
            subfolder_count = sum(1 for item in folder.iterdir() if item.is_dir() and not item.name.startswith('.'))
        except OSError:
            subfolder_count = 0

        custom_image = self.get_custom_folder_image(folder)
        local_image = self.find_local_folder_image(folder)
        mapping = self.series_folder_mappings.get(str(folder))
        season_context = self.season_folder_context(folder)
        image_path = None
        if custom_image:
            image_path = custom_image
        elif local_image:
            image_path = local_image
        elif mapping:
            candidate = self.series_folder_thumbnail_path(mapping)
            if candidate.exists():
                image_path = candidate
        elif season_context:
            inherited_mapping, season_number = season_context
            candidate = self.season_folder_thumbnail_path(inherited_mapping, season_number)
            if candidate.exists():
                image_path = candidate
        if image_path is None:
            image_path = self.first_existing_video_thumbnail_in_folder(folder)
        if image_path and Path(image_path).exists():
            self.load_thumbnail(self.detail_image, Path(image_path), 260, 146)
        else:
            self.set_scaled_placeholder_icon(self.detail_image, "folder-videos", 260, 146)

        mapping_info = self.get_series_folder_mapping(folder)
        folder_personal = self.folder_personal_for_path(folder)
        folder_rating = int(folder_personal.get("rating") or 0)
        folder_rating_text = (
            "★" * folder_rating + "☆" * (5 - folder_rating)
            if folder_rating else "nicht bewertet"
        )
        video_ratings = [
            int(self.personal_for_path(video).get("rating") or 0)
            for video in all_videos
            if int(self.personal_for_path(video).get("rating") or 0) > 0
        ]
        average_rating = (
            f"{sum(video_ratings) / len(video_ratings):.1f}/5"
            if video_ratings else "keine Bewertungen"
        )
        lines = [
            f"Ordnerfavorit: {'ja' if folder_personal.get('favorite') else 'nein'}",
            f"Ordnerbewertung: {folder_rating_text}",
            f"Durchschnitt der Videos: {average_rating}",
            "",
            f"Direkte Unterordner: {subfolder_count}",
            f"Videos direkt im Ordner: {len(direct_videos)}",
            f"Videos insgesamt: {len(all_videos)}",
        ]
        if mapping_info:
            lines.append(f"TMDb-Serie: {mapping_info.get('title') or mapping_info.get('tmdb_id')}")
            season_number = self.inferred_season_number_for_folder(folder)
            if season_number is not None:
                lines.append(f"Staffel: {season_number}")
        lines.extend(["", f"Pfad:\n{folder}"])
        overview_lines = lines[:3]
        media_lines = [line for line in lines[3:] if line and not line.startswith("Pfad:")]
        self.set_detail_sections(
            overview="\n".join(overview_lines),
            media="\n".join(media_lines),
            path=str(folder),
        )

    # ------------------------------------------------------------------
    # Filmkacheln und Aktionen
    # ------------------------------------------------------------------

    def set_scaled_placeholder_icon(self, image_widget, icon_name, tile_width, tile_height):
        """Zeigt ein Platzhaltersymbol proportional zur gewählten Kachelgröße."""
        icon_size = max(48, min(128, int(min(tile_width, tile_height) * 0.55)))
        try:
            theme = Gtk.IconTheme.get_default()
            pixbuf = theme.load_icon(icon_name, icon_size, Gtk.IconLookupFlags.FORCE_SIZE)
            image_widget.set_from_pixbuf(pixbuf)
        except (GLib.Error, TypeError):
            image_widget.set_from_icon_name(icon_name, Gtk.IconSize.DIALOG)
        image_widget.queue_resize()
        image_widget.queue_draw()
        return False

    def start_thumbnail_live_refresh(self):
        """Startet genau einen GTK-Timer für die sichtbaren Videokacheln."""
        if self.thumbnail_live_source_id is None and self.visible_video_tiles:
            self.thumbnail_live_source_id = GLib.timeout_add(
                120, self.refresh_ready_video_thumbnails
            )
        return False

    def refresh_ready_video_thumbnails(self):
        """Blendet neu verfügbare Cache-Bilder im GTK-Hauptthread sofort ein.

        Der Hintergrundthread erzeugt ausschließlich Dateien. Diese Routine
        prüft nur Kacheln, deren Bild noch nicht geladen wurde. Dadurch gibt es
        weder einen kompletten Neuaufbau der Ansicht noch eine Abhängigkeit von
        einem einzelnen threadübergreifenden Callback.
        """
        pending = False
        for info in list(self.visible_video_tiles.values()):
            image_widget = info["image"]
            if info["loaded"]:
                continue
            if image_widget.get_parent() is None:
                continue
            thumb_path = info["thumb_path"]
            if not thumb_path.is_file():
                pending = True
                continue
            try:
                pixbuf = GdkPixbuf.Pixbuf.new_from_file_at_scale(
                    str(thumb_path), info["width"], info["height"], True
                )
            except (OSError, GLib.Error):
                pending = True
                continue
            image_widget.set_from_pixbuf(pixbuf)
            image_widget.show()
            image_widget.queue_draw()
            info["loaded"] = True

        if pending:
            return True
        self.thumbnail_live_source_id = None
        return False

    def apply_generated_thumbnail(
        self, image_widget, thumb_path, tile_width, tile_height,
        placeholder_icon="video-x-generic"
    ):
        """Stößt nach Fertigstellung sofort die GTK-seitige Live-Prüfung an."""
        self.thumbnail_batch_generated = True
        self.refresh_ready_video_thumbnails()
        return False

    def get_custom_folder_image(self, folder):
        """Liefert das manuell zugewiesene Ordnerbild für genau diesen Ordner."""
        folder = Path(folder)
        stored = self.folder_image_mappings.get(str(folder))
        if not stored:
            return None
        candidate = Path(stored)
        if not candidate.is_absolute():
            candidate = self.folder_images_dir / candidate
        return candidate if candidate.is_file() else None

    def choose_managed_folder_image(self, title):
        dialog = Gtk.FileChooserDialog(
            title=title,
            parent=self,
            action=Gtk.FileChooserAction.OPEN,
        )
        dialog.add_buttons(
            Gtk.STOCK_CANCEL, Gtk.ResponseType.CANCEL,
            Gtk.STOCK_OPEN, Gtk.ResponseType.OK,
        )
        dialog.set_current_folder(str(self.folder_images_dir))
        image_filter = Gtk.FileFilter()
        image_filter.set_name("Bilddateien")
        for pattern in ("*.jpg", "*.jpeg", "*.png", "*.webp", "*.bmp", "*.gif"):
            image_filter.add_pattern(pattern)
            image_filter.add_pattern(pattern.upper())
        dialog.add_filter(image_filter)
        all_filter = Gtk.FileFilter()
        all_filter.set_name("Alle Dateien")
        all_filter.add_pattern("*")
        dialog.add_filter(all_filter)
        response = dialog.run()
        selected = dialog.get_filename()
        dialog.destroy()
        if response != Gtk.ResponseType.OK or not selected:
            return None
        return Path(selected)

    def store_folder_image_reference(self, image_path):
        image_path = Path(image_path)
        try:
            relative = image_path.resolve().relative_to(self.folder_images_dir.resolve())
            return str(relative)
        except ValueError:
            pass

        target = self.folder_images_dir / image_path.name
        if target.exists() and target.resolve() != image_path.resolve():
            base = image_path.stem
            suffix = image_path.suffix
            counter = 2
            while True:
                candidate = self.folder_images_dir / f"{base}-{counter}{suffix}"
                if not candidate.exists():
                    target = candidate
                    break
                counter += 1
        try:
            shutil.copy2(image_path, target)
        except OSError as exc:
            self.show_error(f"Ordnerbild konnte nicht kopiert werden:\n{exc}")
            return None
        return str(target.relative_to(self.folder_images_dir))

    def refresh_after_folder_image_change(self, folder):
        folder = Path(folder)
        if self.selected_folder and (
            folder == self.selected_folder or folder.parent == self.selected_folder
        ):
            self.refresh_visible_videos()
        if self.selected_tile_folder and folder == self.selected_tile_folder:
            self.update_detail_panel(folder=folder)
        elif self.selected_folder and folder == self.selected_folder:
            self.update_detail_panel(folder=folder)

    def assign_custom_folder_image(self, folder):
        folder = Path(folder)
        selected = self.choose_managed_folder_image(
            f"Ordnerbild zuweisen: {folder.name or folder}"
        )
        if not selected:
            return
        stored = self.store_folder_image_reference(selected)
        if not stored:
            return
        self.folder_image_mappings[str(folder)] = stored
        self.save_config()
        self.refresh_after_folder_image_change(folder)
        self.status_label.set_text(
            f"Eigenes Ordnerbild zugewiesen: {folder.name} → {Path(stored).name}"
        )

    def remove_custom_folder_image(self, folder):
        folder = Path(folder)
        if self.folder_image_mappings.pop(str(folder), None) is None:
            self.status_label.set_text(f"Für „{folder.name}“ ist kein eigenes Ordnerbild gespeichert.")
            return
        self.save_config()
        self.refresh_after_folder_image_change(folder)
        self.status_label.set_text(f"Eigenes Ordnerbild für „{folder.name}“ wurde entfernt.")

    def on_open_folder_images_directory(self, _widget=None):
        self.open_directory(self.folder_images_dir)
        self.status_label.set_text(f"Ordnerbilder-Ordner geöffnet: {self.folder_images_dir}")

    def find_local_folder_image(self, folder):
        """Sucht ein typisches Poster-/Ordnerbild direkt im Unterordner."""
        folder = Path(folder)
        candidates = []
        for stem in LOCAL_POSTER_FILENAMES:
            for ext in LOCAL_POSTER_EXTENSIONS:
                candidates.append(folder / f"{stem}{ext}")
        # Staffelbilder aus gängigen Medienbibliotheken ebenfalls erkennen.
        season_number = self.inferred_season_number_for_folder(folder)
        if season_number is not None:
            for stem in (f"season{season_number:02d}-poster", f"season{season_number}-poster"):
                for ext in LOCAL_POSTER_EXTENSIONS:
                    candidates.insert(0, folder / f"{stem}{ext}")
        for candidate in candidates:
            if candidate.is_file():
                return candidate
        return None

    def first_existing_video_thumbnail_in_folder(self, folder):
        """Nutzt ersatzweise ein vorhandenes Bild einer direkt enthaltenen Datei."""
        videos = sorted(
            (video for video in self.videos if video.parent == Path(folder)),
            key=lambda path: path.name.casefold(),
        )
        for video in videos:
            thumb = self.thumbnail_path(video)
            if thumb.exists():
                return thumb
        return None

    def create_subfolder_tile(self, folder):
        """Erzeugt eine bebilderte Kachel für einen direkten Unterordner."""
        folder = Path(folder)
        tile_width, tile_height = TILE_SIZES[self.tile_size_name]
        event_box = Gtk.EventBox()
        click_hint = (
            "Einfachklick zum Öffnen"
            if self.folder_tile_open_mode == "single"
            else "Doppelklick zum Öffnen"
        )
        event_box.set_tooltip_text(f"Unterordner: {folder}\n{click_hint}")
        event_box.connect("button-press-event", self.on_folder_tile_clicked, folder)

        frame = Gtk.Frame()
        frame.set_shadow_type(Gtk.ShadowType.ETCHED_IN)
        event_box.add(frame)
        box = Gtk.Box(orientation=Gtk.Orientation.VERTICAL, spacing=6)
        box.set_border_width(6)
        box.set_size_request(tile_width + 16, -1)
        frame.add(box)

        image = Gtk.Image()
        image.set_size_request(tile_width, tile_height)
        box.pack_start(image, False, False, 0)

        direct_videos = sum(1 for video in self.videos if video.parent == folder)
        folder_personal = self.folder_personal_for_path(folder)
        folder_status = []
        if folder_personal.get("favorite"):
            folder_status.append("♥")
        folder_rating = int(folder_personal.get("rating") or 0)
        if folder_rating:
            folder_status.append("★" * folder_rating)
        label_text = folder.name
        if folder_status:
            label_text = f"{'  '.join(folder_status)}\n{label_text}"
        if direct_videos:
            label_text += f"\n{direct_videos} Video{'s' if direct_videos != 1 else ''}"
        label = Gtk.Label(label=label_text)
        label.set_line_wrap(True)
        label.set_justify(Gtk.Justification.CENTER)
        label.set_max_width_chars(
            20 if self.tile_size_name == "Klein" else 28 if self.tile_size_name == "Mittel" else 36
        )
        box.pack_start(label, False, False, 0)

        # Normale Unterordner verwenden zuerst ein manuell zugewiesenes
        # Bild, danach lokale Bilder, spezielle Serien-/Staffelposter oder
        # ersatzweise das Vorschaubild einer direkt enthaltenen Videodatei.
        custom_image = self.get_custom_folder_image(folder)
        local_image = self.find_local_folder_image(folder)
        mapping = self.series_folder_mappings.get(str(folder))
        season_context = self.season_folder_context(folder)
        fallback_thumb = self.first_existing_video_thumbnail_in_folder(folder)
        if custom_image:
            self.load_thumbnail(image, custom_image, tile_width, tile_height)
            self.report_thumbnail_finished()
        elif local_image:
            self.load_thumbnail(image, local_image, tile_width, tile_height)
            self.report_thumbnail_finished()
        elif mapping:
            thumb_path = self.series_folder_thumbnail_path(mapping)
            if thumb_path.exists():
                self.load_thumbnail(image, thumb_path, tile_width, tile_height)
                self.report_thumbnail_finished()
            else:
                self.set_scaled_placeholder_icon(image, "folder-videos", tile_width, tile_height)
                self.executor.submit(
                    self.generate_series_folder_thumbnail,
                    folder, mapping, thumb_path, image, tile_width, tile_height,
                )
        elif season_context:
            inherited_mapping, season_number = season_context
            thumb_path = self.season_folder_thumbnail_path(inherited_mapping, season_number)
            if thumb_path.exists():
                self.load_thumbnail(image, thumb_path, tile_width, tile_height)
                self.report_thumbnail_finished()
            else:
                self.set_scaled_placeholder_icon(image, "folder-videos", tile_width, tile_height)
                self.executor.submit(
                    self.generate_season_folder_thumbnail,
                    folder, inherited_mapping, season_number,
                    thumb_path, image, tile_width, tile_height,
                )
        elif fallback_thumb:
            self.load_thumbnail(image, fallback_thumb, tile_width, tile_height)
            self.report_thumbnail_finished()
        else:
            self.set_scaled_placeholder_icon(image, "folder-videos", tile_width, tile_height)
            self.report_thumbnail_finished()

        child = Gtk.FlowBoxChild()
        child.video_path = None
        child.folder_path = folder
        child.add(event_box)
        return child

    def on_folder_tile_clicked(self, widget, event, folder):
        """Behandelt Auswahl, Öffnen und Kontextmenü einer Ordnerkachel."""
        flow_child = widget.get_parent()
        if isinstance(flow_child, Gtk.FlowBoxChild):
            self.select_folder_child(flow_child)

        if event.button == 3:
            # Rechtsklick synchronisiert Auswahl und Detailbereich, bevor das
            # Kontextmenü geöffnet wird.
            self.selected_video = None
            self.selected_tile_folder = Path(folder)
            self.update_film_menu_state()
            if self.detail_panel_visible:
                self.update_detail_panel(folder=Path(folder))
            self.status_label.set_text(
                f"Ordner ausgewählt: {Path(folder).name}"
            )
            self.show_folder_tile_context_menu(event, folder)
            return True

        if event.button != 1:
            return False

        double_event_types = {
            getattr(Gdk.EventType, "_2BUTTON_PRESS", None),
            getattr(Gdk.EventType, "DOUBLE_BUTTON_PRESS", None),
        }
        is_double_click = event.type in double_event_types

        if self.folder_tile_open_mode == "single":
            if event.type == Gdk.EventType.BUTTON_PRESS:
                self.open_folder_in_browser(folder)
                return True
        elif is_double_click:
            self.open_folder_in_browser(folder)
            return True
        return False

    def open_folder_in_browser(self, folder):
        """Öffnet einen Ordner zuverlässig innerhalb von Carbor.

        Die Ansicht wird direkt umgeschaltet. Die Auswahl im linken Baum wird
        anschließend nur noch synchronisiert. Dadurch funktioniert das Öffnen
        auch dann, wenn GTK für eine programmgesteuerte Baumauswahl kein neues
        Auswahlereignis auslöst oder der Ordner im Baum noch nicht sichtbar ist.
        """
        folder = Path(folder)
        if not folder.is_dir():
            self.show_error(
                f"Der Ordner ist nicht erreichbar:\n{folder}"
            )
            return

        if self.search_query:
            self.search_query = ""
        if self.personal_view != "Ordneransicht":
            self.personal_view = "Ordneransicht"
            item = self.personal_view_menu_items.get("Ordneransicht")
            if item and not item.get_active():
                item.set_active(True)

        self.selected_folder = folder
        self.last_selected_folder = folder
        self.selected_video = None
        self.selected_videos = []
        self.selected_tile_folder = None
        self.selection_anchor_child = None
        self.selection_anchor_index = None
        self.selection_cursor_index = None
        self.save_config()

        # Ansicht und Detailbereich werden ausdrücklich aktualisiert; sie sind
        # nicht mehr vom Signal des linken Ordnerbaums abhängig.
        self.refresh_visible_videos()
        self.update_detail_panel(folder=folder)

        # Den Ordnerbaum nach Möglichkeit auf denselben Ordner setzen. Fehlt
        # der Ordner dort, etwa weil er keine Mediendateien enthält, bleibt die
        # direkte Ordneransicht trotzdem vollständig funktionsfähig.
        self.synchronize_tree_to_folder(folder)
        # refresh_visible_videos() setzt bereits die aussagekräftige Anzahl
        # sichtbarer Videos und aktive Filter in die Statuszeile. Diese Angabe
        # darf hier nicht wieder durch eine allgemeinere Meldung ersetzt werden.

    def show_folder_tile_context_menu(self, event, folder):
        folder = Path(folder)
        menu = Gtk.Menu()
        self.add_menu_item(menu, "Ordner öffnen", lambda *_: self.open_folder_in_browser(folder))
        self.add_menu_item(menu, "Im Dateimanager öffnen", lambda *_: self.open_directory(folder))
        menu.append(Gtk.SeparatorMenuItem())

        personal = self.folder_personal_for_path(folder)
        self.add_menu_item(
            menu,
            (
                "Ordner aus Favoriten entfernen"
                if personal.get("favorite")
                else "Ordner zu Favoriten hinzufügen"
            ),
            lambda *_: self.set_folder_favorite(
                folder, not bool(personal.get("favorite"))
            ),
        )

        rating_item = Gtk.MenuItem(label="Ordnerbewertung")
        rating_menu = Gtk.Menu()
        current_rating = int(personal.get("rating") or 0)
        first_rating = None
        for value, label in (
            (0, "Keine Bewertung"),
            (1, "★"),
            (2, "★★"),
            (3, "★★★"),
            (4, "★★★★"),
            (5, "★★★★★"),
        ):
            if first_rating is None:
                item = Gtk.RadioMenuItem.new_with_label(None, label)
                first_rating = item
            else:
                item = Gtk.RadioMenuItem.new_with_label_from_widget(
                    first_rating, label
                )
            item.set_active(value == current_rating)
            item.connect(
                "toggled",
                self.on_folder_rating_toggled,
                folder,
                value,
            )
            rating_menu.append(item)
        rating_item.set_submenu(rating_menu)
        menu.append(rating_item)

        apply_item = Gtk.MenuItem(label="Ordnerwerte auf Videos anwenden")
        apply_menu = Gtk.Menu()
        self.add_menu_item(
            apply_menu,
            "Favoritenstatus auf alle Videos anwenden",
            lambda *_: self.apply_folder_favorite_to_videos(folder),
        )
        self.add_menu_item(
            apply_menu,
            "Bewertung auf alle Videos anwenden",
            lambda *_: self.apply_folder_rating_to_videos(folder),
        )
        apply_item.set_submenu(apply_menu)
        menu.append(apply_item)

        menu.append(Gtk.SeparatorMenuItem())
        self.add_menu_item(menu, "Eigenes Ordnerbild zuweisen …", lambda *_: self.assign_custom_folder_image(folder))
        if self.get_custom_folder_image(folder):
            self.add_menu_item(menu, "Eigenes Ordnerbild entfernen", lambda *_: self.remove_custom_folder_image(folder))
        self.add_menu_item(menu, "Ordnerbilder-Ordner öffnen", lambda *_: self.open_directory(self.folder_images_dir))
        menu.append(Gtk.SeparatorMenuItem())
        mapping = self.series_folder_mappings.get(str(folder))
        self.add_menu_item(
            menu,
            "Ordner einer TMDb-Serie zuordnen …" if not mapping else "TMDb-Serienzuordnung ändern …",
            lambda *_: self.assign_series_folder(folder),
        )
        if mapping:
            self.add_menu_item(
                menu, "TMDb-Serienzuordnung entfernen",
                lambda *_: self.remove_series_folder_mapping(folder),
            )
        menu.show_all()
        menu.popup_at_pointer(event)

    def on_folder_rating_toggled(
        self, menu_item, folder, value
    ):
        if not menu_item.get_active():
            return
        current = int(
            self.folder_personal_for_path(folder).get("rating") or 0
        )
        if current == int(value):
            return
        self.set_folder_rating(folder, value)

    def open_directory(self, folder):
        try:
            subprocess.Popen(["xdg-open", str(folder)])
        except OSError as exc:
            self.show_error(f"Ordner konnte nicht geöffnet werden:\n{exc}")

