    def generate_series_folder_thumbnail(
        self, folder, mapping, thumb_path, image_widget, tile_width, tile_height
    ):
        raw_path = thumb_path.with_suffix(".download")
        tmp_path = thumb_path.with_suffix(".tmp.jpg")
        try:
            poster_url = mapping.get("poster_url")
            if not poster_url and mapping.get("tmdb_id"):
                try:
                    data = self.tmdb_fetch_details(int(mapping["tmdb_id"]), is_series=True)
                    poster_path = data.get("poster_path") if isinstance(data, dict) else None
                    if poster_path:
                        poster_url = f"https://image.tmdb.org/t/p/w500{poster_path}"
                        mapping["poster_url"] = poster_url
                        GLib.idle_add(self.save_config)
                except Exception:
                    poster_url = None
            if poster_url and self.download_binary(poster_url, raw_path):
                if self.scale_image_file(raw_path, tmp_path, tile_width, tile_height):
                    tmp_path.replace(thumb_path)
                    GLib.idle_add(
                        self.apply_generated_thumbnail,
                        image_widget,
                        thumb_path,
                        tile_width,
                        tile_height,
                        "folder-videos",
                    )
        except (OSError, GLib.Error, urllib.error.URLError, socket.timeout, TimeoutError):
            pass
        finally:
            for path in (raw_path, tmp_path):
                try:
                    if path.exists():
                        path.unlink()
                except OSError:
                    pass
            GLib.idle_add(self.report_thumbnail_finished)

