    def tmdb_fetch_season(self, series_id, season_number):
        """Lädt die TMDb-Daten einer einzelnen Staffel."""
        headers, key_part = self.tmdb_headers_and_key()
        url = (
            f"https://api.themoviedb.org/3/tv/{series_id}/season/{season_number}"
            f"?language=de-DE{key_part}"
        )
        return self.request_json(url, headers)

    def generate_season_folder_thumbnail(
        self,
        folder,
        mapping,
        season_number,
        thumb_path,
        image_widget,
        tile_width,
        tile_height,
    ):
        """Lädt bevorzugt das Staffelposter und nutzt sonst das Serienposter."""
        raw_path = thumb_path.with_suffix(".download")
        tmp_path = thumb_path.with_suffix(".tmp.jpg")
        try:
            poster_url = None
            try:
                season_data = self.tmdb_fetch_season(
                    int(mapping["tmdb_id"]), season_number
                )
                poster_path = (
                    season_data.get("poster_path")
                    if isinstance(season_data, dict)
                    else None
                )
                if poster_path:
                    poster_url = f"https://image.tmdb.org/t/p/w500{poster_path}"
            except (
                OSError,
                ValueError,
                KeyError,
                urllib.error.URLError,
                socket.timeout,
                TimeoutError,
                json.JSONDecodeError,
            ):
                poster_url = None

            # Manche Staffeln besitzen bei TMDb kein eigenes Bild. In diesem
            # Fall bleibt die Staffelansicht dennoch bebildert und verwendet
            # das bereits bekannte Serienposter als nachvollziehbaren Fallback.
            if not poster_url:
                poster_url = mapping.get("poster_url")

            if poster_url and self.download_binary(poster_url, raw_path):
                if self.scale_image_file(
                    raw_path, tmp_path, tile_width, tile_height
                ):
                    tmp_path.replace(thumb_path)
                    GLib.idle_add(
                        self.apply_generated_thumbnail,
                        image_widget,
                        thumb_path,
                        tile_width,
                        tile_height,
                        "folder-videos",
                    )
        except (
            OSError,
            GLib.Error,
            urllib.error.URLError,
            socket.timeout,
            TimeoutError,
        ):
            pass
        finally:
            for path in (raw_path, tmp_path):
                try:
                    if path.exists():
                        path.unlink()
                except OSError:
                    pass
            GLib.idle_add(self.report_thumbnail_finished)

    def create_video_tile(self, video_path):
        tile_width, tile_height = TILE_SIZES[self.tile_size_name]
        event_box = Gtk.EventBox()
        technical = self.technical_for_path(video_path)
        resolution = (
            f"{technical.get('width')} × {technical.get('height')}"
            if technical.get("width") and technical.get("height")
            else "Auflösung unbekannt"
        )
        duration = technical.get("duration_seconds")
        duration_text = (
            self.seconds_to_readable_duration(duration)
            if duration else "Laufzeit unbekannt"
        )
        codec = technical.get("video_codec") or "Codec unbekannt"
        play_hint = (
            "Einfachklick zum Abspielen"
            if self.video_tile_play_mode == "single"
            else "Doppelklick zum Abspielen"
        )
        event_box.set_tooltip_text(
            f"{video_path}\n{resolution} · {codec} · {duration_text}\n{play_hint}"
        )
        event_box.connect("button-press-event", self.on_tile_clicked, video_path)

        frame = Gtk.Frame()
        frame.set_shadow_type(Gtk.ShadowType.ETCHED_IN)
        event_box.add(frame)
        box = Gtk.Box(orientation=Gtk.Orientation.VERTICAL, spacing=6)
        box.set_border_width(6)
        box.set_size_request(tile_width + 16, -1)
        frame.add(box)

        image = Gtk.Image()
        image.set_size_request(tile_width, tile_height)
        box.pack_start(image, False, False, 0)

        record = self.library_records.get(str(video_path)) or {}
        personal = record.get("personal") or self.default_personal()
        rating = int(personal.get("rating") or 0)
        status_bits = []
        if personal.get("favorite"):
            status_bits.append("♥")
        if rating:
            status_bits.append("★" * rating)
        title_text = self.pretty_title(video_path)
        if status_bits:
            title_text = f"{'  '.join(status_bits)}\n{title_text}"
        label = Gtk.Label(label=title_text)
        label.set_line_wrap(True)
        label.set_justify(Gtk.Justification.CENTER)
        label.set_max_width_chars(20 if self.tile_size_name == "Klein" else 28 if self.tile_size_name == "Mittel" else 36)
        box.pack_start(label, False, False, 0)

        live_progress = self.live_playback_positions.get(str(video_path))
        known_duration = float(
            (live_progress or {}).get("duration")
            or technical.get("duration_seconds")
            or personal.get("playback_duration_seconds")
            or 0
        )
        last_position = float(
            (live_progress or {}).get("position")
            if live_progress is not None
            else personal.get("last_position_seconds") or 0
        )
        progress = Gtk.ProgressBar()
        progress.set_show_text(False)
        progress.set_size_request(tile_width, 5)
        progress.set_no_show_all(True)
        box.pack_start(progress, False, False, 0)
        if known_duration > 0 and last_position > 0:
            fraction = min(1.0, max(0.0, last_position / known_duration))
            progress.set_fraction(fraction)
            progress.set_tooltip_text(
                f"Wiedergabefortschritt: {int(fraction * 100)} %"
            )
            progress.show()
        else:
            progress.hide()

        thumb_path = self.thumbnail_path(video_path)
        self.visible_video_tiles[str(video_path)] = {
            "image": image,
            "thumb_path": thumb_path,
            "width": tile_width,
            "height": tile_height,
            "progress": progress,
            "loaded": False,
        }
        if thumb_path.exists():
            self.load_thumbnail(image, thumb_path, tile_width, tile_height)
            self.visible_video_tiles[str(video_path)]["loaded"] = True
            self.report_thumbnail_finished()
        else:
            self.set_scaled_placeholder_icon(image, "video-x-generic", tile_width, tile_height)
            video_key = str(video_path)
            if video_key in self.thumbnail_failed_this_session:
                # Der letzte automatische Versuch ist in dieser Sitzung bereits
                # endgültig gescheitert. Die Kachel bleibt bedienbar; ein
                # manueller Bildlauf kann die Datei gezielt erneut prüfen.
                self.report_thumbnail_finished(
                    self.thumbnail_view_generation,
                    False,
                )
            else:
                # Der Hintergrundthread erzeugt nur die Datei. Die sichtbare
                # GTK-Kachel wird anschließend gezielt im Hauptthread aktualisiert.
                self.executor.submit(
                    self.generate_thumbnail,
                    video_path,
                    thumb_path,
                    image,
                    tile_width,
                    tile_height,
                    self.thumbnail_view_generation,
                )

        flow_child = Gtk.FlowBoxChild()
        flow_child.video_path = video_path
        flow_child.folder_path = None
        flow_child.add(event_box)
        return flow_child

    def on_tile_clicked(self, widget, event, video_path):
        """Behandelt Auswahl, Wiedergabe und Kontextmenü einer Videokachel.

        GTK3 bezeichnet einen Doppelklick je nach PyGObject-Version als
        ``_2BUTTON_PRESS``. Die frühere direkte Abfrage von
        ``DOUBLE_BUTTON_PRESS`` konnte daher bereits beim Klick mit einem
        AttributeError abbrechen, bevor VLC gestartet wurde.
        """
        flow_child = widget.get_parent()

        if event.button == 3:
            if isinstance(flow_child, Gtk.FlowBoxChild):
                selected_children = set(
                    self.flowbox.get_selected_children()
                )
                if flow_child not in selected_children:
                    # Rechtsklick auf eine bislang nicht markierte Kachel
                    # macht sie wie im Dateimanager zur alleinigen Auswahl.
                    self.flowbox.unselect_all()
                    self.flowbox.select_child(flow_child)
                    self.selection_anchor_child = flow_child
                    self.selection_anchor_index = (
                        self.flowbox_child_index(flow_child)
                    )
                    self.selection_cursor_index = self.selection_anchor_index

            selected_videos = self.selected_flowbox_videos()
            if len(selected_videos) > 1:
                self.selected_videos = selected_videos
                self.selected_video = None
                self.selected_tile_folder = None
                self.update_film_menu_state()
                self.show_multiple_video_details(selected_videos)
                self.status_label.set_text(
                    f"{len(selected_videos)} Videos ausgewählt"
                )
                self.show_multiple_video_context_menu(
                    event, selected_videos
                )
            else:
                self.selected_videos = [Path(video_path)]
                self.selected_video = Path(video_path)
                self.selected_tile_folder = None
                self.update_film_menu_state()
                if self.detail_panel_visible:
                    self.update_detail_panel(video=Path(video_path))
                self.status_label.set_text(
                    f"Ausgewählt: {self.pretty_title(Path(video_path))}"
                )
                self.show_video_context_menu(
                    event, Path(video_path)
                )
            return True

        if event.button != 1:
            return False

        if isinstance(flow_child, Gtk.FlowBoxChild):
            self.select_video_child_from_event(flow_child, event)

        ctrl = bool(event.state & Gdk.ModifierType.CONTROL_MASK)
        shift = bool(event.state & Gdk.ModifierType.SHIFT_MASK)

        double_event_types = {
            value for value in (
                getattr(Gdk.EventType, "_2BUTTON_PRESS", None),
                getattr(Gdk.EventType, "DOUBLE_BUTTON_PRESS", None),
            )
            if value is not None
        }
        is_double_click = event.type in double_event_types

        if ctrl or shift:
            return True

        if self.video_tile_play_mode == "single":
            if event.type == Gdk.EventType.BUTTON_PRESS:
                self.open_in_vlc(Path(video_path))
                return True
        elif is_double_click:
            self.open_in_vlc(Path(video_path))
            return True
        return False

    def show_multiple_video_context_menu(self, event, videos):
        """Zeigt Sammelaktionen für die markierten Videokacheln."""
        menu = Gtk.Menu()
        heading = Gtk.MenuItem(
            label=f"{len(videos)} Videos ausgewählt"
        )
        heading.set_sensitive(False)
        menu.append(heading)
        menu.append(Gtk.SeparatorMenuItem())

        all_favorites = all(
            bool(self.personal_for_path(video).get("favorite"))
            for video in videos
        )
        self.add_menu_item(
            menu,
            (
                "Alle aus Favoriten entfernen"
                if all_favorites
                else "Alle zu Favoriten hinzufügen"
            ),
            self.on_toggle_selected_favorite,
        )

        rating_item = Gtk.MenuItem(label="Bewertung für alle")
        rating_menu = Gtk.Menu()
        for value, label in (
            (0, "Keine Bewertung"),
            (1, "★"),
            (2, "★★"),
            (3, "★★★"),
            (4, "★★★★"),
            (5, "★★★★★"),
        ):
            item = Gtk.MenuItem(label=label)
            item.connect(
                "activate",
                lambda _item, selected_value=value:
                    self.apply_batch_rating_from_context(
                        selected_value
                    ),
            )
            rating_menu.append(item)
        rating_item.set_submenu(rating_menu)
        menu.append(rating_item)

        self.add_menu_item(
            menu,
            "Alle als gesehen markieren",
            self.on_mark_selected_seen,
        )
        self.add_menu_item(
            menu,
            "Alle als ungesehen markieren",
            self.on_mark_selected_unseen,
        )

        if any(
            float(
                self.personal_for_path(video).get(
                    "last_position_seconds"
                ) or 0
            ) > 0
            for video in videos
        ):
            self.add_menu_item(
                menu,
                "Wiedergabefortschritt aller zurücksetzen",
                self.on_reset_selected_progress,
            )

        menu.append(Gtk.SeparatorMenuItem())
        clear_item = Gtk.MenuItem(label="Auswahl aufheben")
        clear_item.connect(
            "activate", lambda *_: self.flowbox.unselect_all()
        )
        menu.append(clear_item)

        menu.show_all()
        menu.popup_at_pointer(event)

    def apply_batch_rating_from_context(self, value):
        videos = self.selected_action_videos()
        changed = self.apply_personal_batch(videos, rating=value)
        if changed:
            self.status_label.set_text(
                f"Bewertung {value}/5 für {changed} Video(s) gespeichert."
            )

    def show_video_context_menu(self, event, video_path):
        menu = Gtk.Menu()
        self.add_menu_item(menu, "Abspielen / fortsetzen", lambda *_: self.open_in_vlc(video_path))
        personal = self.personal_for_path(video_path)
        self.add_menu_item(
            menu,
            "Aus Favoriten entfernen" if personal.get("favorite") else "Zu Favoriten hinzufügen",
            lambda *_: self.toggle_favorite(video_path),
        )
        rating_item = Gtk.MenuItem(label="Bewertung")
        rating_menu = Gtk.Menu()
        current_rating = int(personal.get("rating") or 0)
        first_rating = None
        for value, label in ((0, "Keine Bewertung"), (1, "★"), (2, "★★"), (3, "★★★"), (4, "★★★★"), (5, "★★★★★")):
            if first_rating is None:
                item = Gtk.RadioMenuItem.new_with_label(None, label)
                first_rating = item
            else:
                item = Gtk.RadioMenuItem.new_with_label_from_widget(first_rating, label)
