        menu.append(rating_item)
        if float(personal.get("last_position_seconds") or 0) > 0:
            self.add_menu_item(menu, "Wiedergabefortschritt zurücksetzen", lambda *_: self.reset_playback_progress(video_path))
        menu.append(Gtk.SeparatorMenuItem())
        self.add_menu_item(
            menu,
            "Im Dateimanager anzeigen",
            lambda *_: self.reveal_video_in_file_manager(video_path),
        )
        self.add_menu_item(
            menu,
            "Enthaltenden Ordner öffnen",
            lambda *_: self.open_video_folder(video_path),
        )
        self.add_menu_item(
            menu,
            "Dateipfad kopieren",
            lambda *_: self.copy_video_path(video_path),
        )
