    def tmdb_poster_url(self, title, year, is_series):
        if not (self.tmdb_api_key or self.tmdb_read_token):
            return None
        query = urllib.parse.quote(title)
        media_type = "tv" if is_series else "movie"
        year_param = "first_air_date_year" if is_series else "year"
        url = (
            f"https://api.themoviedb.org/3/search/{media_type}"
            f"?language=de-DE&query={query}&include_adult=false"
        )
        headers = None
        if self.tmdb_read_token:
            headers = {"Authorization": f"Bearer {self.tmdb_read_token}"}
        else:
            url += f"&api_key={urllib.parse.quote(self.tmdb_api_key)}"
        if year:
            url += f"&{year_param}={urllib.parse.quote(year)}"
        data = self.request_json(url, headers)
        for item in data.get("results", []):
            poster_path = item.get("poster_path")
            if poster_path:
                return f"https://image.tmdb.org/t/p/w500{poster_path}"
        return None

    def tvmaze_poster_url(self, title):
        query = urllib.parse.quote(title)
        url = f"https://api.tvmaze.com/search/shows?q={query}"
        data = self.request_json(url)
        if not isinstance(data, list):
            return None
        for entry in data:
            show = entry.get("show") or {}
            image = show.get("image") or {}
            if image.get("original"):
                return image["original"]
            if image.get("medium"):
                return image["medium"]
        return None

    def itunes_poster_url(self, title, year):
        query = urllib.parse.quote(title)
        url = f"https://itunes.apple.com/search?term={query}&entity=movie&limit=5&country=de"
        data = self.request_json(url)
        results = data.get("results", []) if isinstance(data, dict) else []
        for item in results:
            release = str(item.get("releaseDate", ""))
            if year and release[:4] and release[:4] != year:
                continue
            poster = item.get("artworkUrl100") or item.get("artworkUrl60")
            if poster:
                return poster.replace("100x100bb", "600x600bb").replace("60x60bb", "600x600bb")
        for item in results:
            poster = item.get("artworkUrl100") or item.get("artworkUrl60")
            if poster:
                return poster.replace("100x100bb", "600x600bb").replace("60x60bb", "600x600bb")
        return None

    def omdb_poster_url(self, title, year, is_series):
        if not self.omdb_api_key:
            return None
        params = {
            "apikey": self.omdb_api_key,
            "t": title,
            "type": "series" if is_series else "movie",
        }
        if year:
            params["y"] = year
        url = "https://www.omdbapi.com/?" + urllib.parse.urlencode(params)
        data = self.request_json(url)
        poster = data.get("Poster") if isinstance(data, dict) else None
        if poster and poster != "N/A":
            return poster
        return None

    def find_online_poster_url(self, video_path):
        """
        Liefert für Filme ein Poster. Episoden verwenden dagegen ausschließlich
        ihr eigenes TMDb-Episodenbild; Serien- oder Staffelposter dürfen niemals
        auf einzelne Episodendateien kopiert werden.
        """
        record = self.library_records.get(str(video_path)) or {}
        metadata = record.get("metadata") or {}
        media_type = metadata.get("media_type")

        if media_type == "episode":
            return metadata.get("episode_still_url")
        if media_type == "bonus":
            return None

        title, year = self.guess_title_and_year(video_path)
        is_series = media_type == "series" or (not media_type and self.looks_like_series(video_path))

        providers = []
        if self.tmdb_api_key or self.tmdb_read_token:
            providers.append(lambda: self.tmdb_poster_url(title, year, is_series))
        if is_series:
            providers.append(lambda: self.tvmaze_poster_url(title))
        else:
            providers.append(lambda: self.itunes_poster_url(title, year))
        if self.omdb_api_key:
            providers.append(lambda: self.omdb_poster_url(title, year, is_series))
        if not is_series:
            providers.append(lambda: self.tvmaze_poster_url(title))

        for provider in providers:
            try:
                url = provider()
                if url:
                    return url
            except (
                OSError, ValueError, KeyError, urllib.error.URLError,
                socket.timeout, TimeoutError, json.JSONDecodeError
            ) as exc:
                self.log_error(
                    "Online-Posteranbieter fehlgeschlagen",
                    exc,
                    level=logging.WARNING,
                    details=str(video_path),
                )
                continue
        return None

    def download_online_poster(
        self, video_path, raw_download_path, thumb_path, tile_width, tile_height
    ):
        """
        Lädt ein Filmplakat oder ein echtes Episodenbild. Fehlt bei einer Episode
        ein eigenes Standbild, liefert die Funktion False. Danach versucht der
        Bildlauf die Videomitte und anschließend 10, 6, 2 Minuten sowie 20 Sekunden.
        """
        image_url = self.find_online_poster_url(video_path)
        if not image_url:
            return False
        try:
            if not self.download_binary(image_url, raw_download_path):
                return False
            return self.scale_image_file(
                raw_download_path, thumb_path, tile_width, tile_height
            )
        except (
            OSError, GLib.Error, urllib.error.URLError,
            socket.timeout, TimeoutError
        ) as exc:
            self.log_error(
                "Online-Poster konnte nicht verarbeitet werden",
                exc,
                details=str(video_path),
            )
            return False

    def collect_videos_for_current_folder(self):
        if self.selected_folder is None:
            return []
        return [
            video for video in self.videos
            if video.parent == self.selected_folder or self.selected_folder in video.parents
        ]

    def on_generate_missing_library_thumbnails(self, _widget):
        """Erzeugt seriell alle noch fehlenden Video-Vorschaubilder."""
        self.start_library_thumbnail_scan(rebuild_all=False)

    def on_regenerate_all_library_thumbnails(self, _widget):
        """Fragt nach und erzeugt anschließend sämtliche Videobilder neu."""
        if self.scan_running:
            return
        videos = [path for path in self.videos if path.exists()]
        if not videos:
            self.status_label.set_text("Keine erreichbaren Mediendateien vorhanden.")
            return
        dialog = Gtk.MessageDialog(
            transient_for=self,
            modal=True,
            message_type=Gtk.MessageType.WARNING,
            buttons=Gtk.ButtonsType.OK_CANCEL,
            text="Alle Vorschaubilder neu erzeugen?",
        )
        dialog.format_secondary_text(
            f"Für {len(videos)} Mediendateien werden vorhandene Video-Vorschaubilder "
            "ersetzt. Der Vorgang arbeitet HDD-schonend seriell, kann aber mehrere "
            "Stunden dauern. Serien-, Staffel- und manuelle Ordnerbilder bleiben erhalten."
        )
        response = dialog.run()
        dialog.destroy()
        if response == Gtk.ResponseType.OK:
            self.start_library_thumbnail_scan(rebuild_all=True)

    def start_library_thumbnail_scan(self, rebuild_all=False):
        """Startet einen abbrechbaren, seriellen Lauf über die ganze Bibliothek."""
        videos = [path for path in self.videos if path.exists()]
        for video in videos:
            self.thumbnail_failed_this_session.discard(str(video))
        if not rebuild_all:
            videos = [path for path in videos if not self.thumbnail_path(path).exists()]
        if not videos:
            self.status_label.set_text(
                "Alle Video-Vorschaubilder sind bereits vorhanden."
                if not rebuild_all else "Keine erreichbaren Mediendateien vorhanden."
            )
            self.progress_bar.set_fraction(1.0)
            self.progress_bar.set_text("Keine Vorschaubilder offen")
            return False
        scan_name = (
            "Vorschaubilder vollständig neu erzeugen"
            if rebuild_all else "Fehlende Vorschaubilder erzeugen"
        )
        if not self.begin_scan(scan_name):
            return False
        self.progress_bar.set_fraction(0.0)
        self.update_scan_progress("Vorschaubilder", 0, len(videos))
        self.status_label.set_text(
            f"{len(videos)} Video-Vorschaubilder werden "
            + ("neu erzeugt …" if rebuild_all else "ergänzt …")
        )
        threading.Thread(
            target=self.library_thumbnail_scan_worker,
            args=(videos, rebuild_all),
            daemon=True,
        ).start()
        return True

    def library_thumbnail_scan_worker(self, videos, rebuild_all):
        """Erzeugt Bibliotheksbilder seriell und damit mechanische HDD-schonend."""
        generated = 0
        failed = 0
        skipped = 0
        cancelled = False
        worker_error = False
        tile_width, tile_height = TILE_SIZES[self.tile_size_name]
        total = len(videos)
        try:
            for number, video_path in enumerate(videos, start=1):
                if self.cancel_event.is_set():
                    raise ScanCancelled
                thumb_path = self.thumbnail_path(video_path)
                if not rebuild_all and thumb_path.exists():
                    skipped += 1
                    GLib.idle_add(
                        self.update_library_thumbnail_scan_progress,
                        number, total, generated, failed,
                    )
                    continue

                tmp_path = thumb_path.with_suffix(".tmp.jpg")
                success = False
                try:
                    for seek_time in self.thumbnail_seek_times(video_path):
                        if self.cancel_event.is_set():
                            raise ScanCancelled
                        success = self.run_ffmpeg_thumbnail(
                            video_path,
                            tmp_path,
                            seek_time,
                            tile_width,
                            tile_height,
                        )
                        if success:
                            break
                    if success and tmp_path.exists():
                        tmp_path.replace(thumb_path)
                        generated += 1
                    else:
                        failed += 1
                except ScanCancelled:
                    raise
                except (OSError, GLib.Error, subprocess.SubprocessError) as exc:
                    self.log_error(
                        "Bibliotheksweites Vorschaubild fehlgeschlagen",
                        exc,
                        details=str(video_path),
                    )
                    failed += 1
                finally:
                    try:
                        if tmp_path.exists():
                            tmp_path.unlink()
                    except OSError:
                        pass

                GLib.idle_add(
                    self.update_library_thumbnail_scan_progress,
                    number, total, generated, failed,
                )
                if self.cancel_event.wait(THUMBNAIL_BATCH_PAUSE_SECONDS):
                    raise ScanCancelled
        except ScanCancelled:
            cancelled = True
        except Exception as exc:
            worker_error = True
            failed += 1
            self.log_error(
                "Bibliotheksweiter Vorschaubildlauf unerwartet abgebrochen",
                exc,
            )

        GLib.idle_add(
            self.finish_library_thumbnail_scan,
            total,
            generated,
            failed,
            skipped,
            cancelled,
            rebuild_all,
            worker_error,
        )

    def update_library_thumbnail_scan_progress(self, done, total, generated, failed):
        self.update_scan_progress("Vorschaubilder", done, total)
        self.status_label.set_text(
            f"Bibliotheksweite Vorschaubilder: {generated} erzeugt, {failed} fehlgeschlagen"
        )
        return False

    def finish_library_thumbnail_scan(
        self, total, generated, failed, skipped, cancelled=False,
        rebuild_all=False, worker_error=False
    ):
        if cancelled:
            return self.finish_cancelled_scan(
                "Bibliotheksweiter Vorschaubildlauf",
                save_index=False,
                refresh=True,
            )
        self.end_scan()
        self.progress_bar.set_fraction(1.0)
        self.progress_bar.set_text(
            "Vorschaubilder mit Fehler beendet"
            if worker_error
            else "Vorschaubilder abgeschlossen · 100.0 % · ETA: 0 s"
        )
        prefix = "Vorschaubildlauf vorzeitig beendet" if worker_error else "Vorschaubilder"
        self.status_label.set_text(
            f"{prefix}: {generated} erzeugt, {skipped} übersprungen, "
            f"{failed} fehlgeschlagen; {total} vorgesehen"
        )
        self.refresh_visible_videos()
        return False

    def collect_folder_poster_targets(self, videos):
        """Ermittelt Serien- und Staffelordner für den kombinierten Bildlauf.

        Aus den betroffenen Videodateien werden zugeordnete Serienhauptordner
        und eindeutig erkannte Staffelordner abgeleitet. Doppelte Ziele werden
        entfernt, bevor die Posterphase beginnt.
        """
        series_targets = {}
        season_targets = {}
        for video in videos:
            mapping = self.get_series_folder_mapping(video)
            if not mapping or not mapping.get("tmdb_id"):
                continue
            mapped_root = Path(mapping.get("folder"))
            direct_mapping = self.series_folder_mappings.get(str(mapped_root))
            if not direct_mapping or not direct_mapping.get("tmdb_id"):
                continue
            series_targets[str(mapped_root)] = {
                "kind": "series",
                "folder": mapped_root,
                "mapping": direct_mapping,
            }
            for parent in video.parents:
                if parent == mapped_root.parent:
                    break
                season_number = self.inferred_season_number_for_folder(parent)
                if season_number is not None:
                    season_targets[(str(mapped_root), season_number)] = {
                        "kind": "season",
                        "folder": parent,
                        "mapping": direct_mapping,
                        "season_number": season_number,
                    }
                    break
        return list(series_targets.values()) + list(season_targets.values())

    def ensure_series_folder_thumbnail_file(self, mapping, tile_width, tile_height):
        """Lädt und skaliert das Poster eines zugeordneten Serienordners."""
        thumb_path = self.series_folder_thumbnail_path(mapping)
        raw_path = thumb_path.with_suffix(".download")
        tmp_path = thumb_path.with_suffix(".tmp.jpg")
        try:
            poster_url = mapping.get("poster_url")
            if not poster_url and mapping.get("tmdb_id"):
                details = self.tmdb_fetch_details(
                    int(mapping["tmdb_id"]),
                    is_series=True,
                )
                poster_path = (
                    details.get("poster_path")
                    if isinstance(details, dict)
                    else None
                )
                if poster_path:
                    poster_url = f"https://image.tmdb.org/t/p/w500{poster_path}"
                    mapping["poster_url"] = poster_url
                    self.save_config()
            if not poster_url:
                return False
            if not self.download_binary(poster_url, raw_path):
                return False
            if not self.scale_image_file(
                raw_path, tmp_path, tile_width, tile_height
            ):
                return False
            tmp_path.replace(thumb_path)
            return True
        finally:
            for path in (raw_path, tmp_path):
                try:
                    if path.exists():
                        path.unlink()
                except OSError:
                    pass

    def ensure_season_folder_thumbnail_file(
        self, mapping, season_number, tile_width, tile_height
    ):
        """Lädt ein Staffelposter; das Serienposter dient als letzter Fallback."""
        thumb_path = self.season_folder_thumbnail_path(mapping, season_number)
        raw_path = thumb_path.with_suffix(".download")
        tmp_path = thumb_path.with_suffix(".tmp.jpg")
        try:
            poster_url = None
            try:
                season_data = self.tmdb_fetch_season(
                    int(mapping["tmdb_id"]),
                    season_number,
                )
                poster_path = (
                    season_data.get("poster_path")
                    if isinstance(season_data, dict)
                    else None
                )
                if poster_path:
                    poster_url = f"https://image.tmdb.org/t/p/w500{poster_path}"
            except (
                OSError, ValueError, KeyError, urllib.error.URLError,
                socket.timeout, TimeoutError, json.JSONDecodeError,
            ) as exc:
                self.log_error(
                    "Staffelposter konnte nicht direkt ermittelt werden; Serienposter-Fallback folgt",
                    exc,
                    level=logging.WARNING,
                    details=(
                        f"TMDb-Serie: {mapping.get('tmdb_id')} | "
                        f"Staffel: {season_number}"
                    ),
                )
            if not poster_url:
                poster_url = mapping.get("poster_url")
            if not poster_url:
                return False
            if not self.download_binary(poster_url, raw_path):
                return False
            if not self.scale_image_file(
                raw_path, tmp_path, tile_width, tile_height
            ):
                return False
            tmp_path.replace(thumb_path)
            return True
        finally:
            for path in (raw_path, tmp_path):
                try:
                    if path.exists():
                        path.unlink()
                except OSError:
                    pass

    def fetch_missing_posters_for_videos(self, videos, only_missing=True, *, reason=None):
        """Startet einen kombinierten Bildlauf: zuerst Poster, dann Standbilder.

        Ablauf:
        1. lokale und Online-Poster für Videos, Serien- und Staffelordner
        2. nur für weiterhin bildlose Videos echte ffmpeg-Vorschaubilder

        So werden Online-Bilder bevorzugt und unnötige ffmpeg-Läufe vermieden.
        """
        videos = [Path(video) for video in videos if Path(video).exists()]
        for video in videos:
            self.thumbnail_failed_this_session.discard(str(video))
        folder_targets = self.collect_folder_poster_targets(videos)
        if not videos and not folder_targets:
            self.status_label.set_text(
                "Keine passenden Filme oder Serienordner für den Bildlauf gefunden."
            )
            return False
        scan_name = reason or "Poster und Vorschaubilder"
        if not self.begin_scan(scan_name):
            return False

        poster_total = len(videos) + len(folder_targets)
        self.progress_bar.set_fraction(0.0)
        self.update_scan_fraction(
            "Posterphase",
            0.0,
            f"0 von {poster_total or 0} geprüft",
        )
        self.status_label.set_text(
            f"Automatischer Bildlauf: {len(videos)} Dateien und {len(folder_targets)} "
            "Serien-/Staffelordner werden zuerst auf Poster geprüft …"
        )
        threading.Thread(
            target=self.artwork_fetch_worker,
            args=(videos, folder_targets, only_missing),
            daemon=True,
        ).start()
        return True

    def artwork_phase_progress(self, phase_label, fraction, detail, status_text):
        self.update_scan_fraction(phase_label, fraction, detail)
        if status_text:
            self.status_label.set_text(status_text)
        return False

    def artwork_ffmpeg_heartbeat(
        self,
        fraction,
        index,
        total,
        attempt,
        attempts,
        video_name,
        seek_time,
        mode,
        elapsed,
        timeout,
        paused,
    ):
        """Aktualisiert die Bildlaufanzeige während eines einzelnen ffmpeg-Laufs."""
        elapsed_seconds = max(0, int(elapsed))
        timeout_seconds = int(timeout) if timeout else 0
        state = "Temperaturpause" if paused else "arbeitet"
        detail = (
            f"Phase 2/2 · Datei {index} von {total} · Versuch {attempt} von {attempts} · "
            f"{mode} · {elapsed_seconds} s"
        )
        if timeout_seconds:
            detail += f" von max. {timeout_seconds} s"
        status = (
            f"FFmpeg {state}: {video_name} · Position {seek_time} · "
            f"{mode}-Pfad · Laufzeit {elapsed_seconds} s"
        )
        GLib.idle_add(
            self.artwork_phase_progress,
            "Vorschaubilder",
            fraction,
            detail,
            status,
        )

    def artwork_fetch_worker(self, videos, folder_targets, only_missing):
        poster_processed = 0
        poster_total = max(1, len(videos) + len(folder_targets))
        local_posters = 0
        online_posters = 0
        series_posters = 0
        season_posters = 0
        poster_skipped = 0
        poster_missed = 0
        poster_errors = 0
        thumbnail_generated = 0
        thumbnail_failed = 0
        cancelled = False
        worker_error = False
        tile_width, tile_height = TILE_SIZES[self.tile_size_name]

        def poster_fraction(processed):
            if poster_total <= 0:
                return 0.65
            return 0.65 * min(1.0, processed / poster_total)

        try:
            for index, video in enumerate(videos, start=1):
                if self.cancel_event.is_set():
                    raise ScanCancelled
                thumb_path = self.thumbnail_path(video)
                if only_missing and thumb_path.exists():
                    poster_skipped += 1
                    poster_processed += 1
                    GLib.idle_add(
                        self.artwork_phase_progress,
                        "Posterphase",
                        poster_fraction(poster_processed),
                        f"Phase 1/2 · Datei {index} von {len(videos)}",
                        f"Posterphase: {local_posters + online_posters} Bilder, "
                        f"{poster_skipped} übersprungen, {poster_missed} ohne Poster, "
                        f"{poster_errors} Fehler",
                    )
                    continue

                tmp_path = thumb_path.with_suffix('.tmp.jpg')
                raw_download = thumb_path.with_suffix('.download')
                success = False
                try:
                    local_poster = self.find_local_poster_image(video)
                    if local_poster:
                        success = self.scale_image_file(local_poster, tmp_path, tile_width, tile_height)
                        if success:
                            local_posters += 1

                    if not success and self.online_posters_enabled:
                        success = self.download_online_poster(
                            video, raw_download, tmp_path, tile_width, tile_height
                        )
                        if success:
                            online_posters += 1

                    if success and tmp_path.exists():
                        tmp_path.replace(thumb_path)
                    else:
                        poster_missed += 1
                except ScanCancelled:
                    raise
                except FileNotFoundError as exc:
                    self.log_error(
                        "Posterphase: Datei oder Werkzeug nicht gefunden",
                        exc,
                        details=str(video),
                    )
                    poster_errors += 1
                except (
                    OSError, GLib.Error, subprocess.SubprocessError,
                    urllib.error.URLError, socket.timeout, TimeoutError,
                    json.JSONDecodeError, ValueError, KeyError,
                ) as exc:
                    self.log_error(
                        "Posterphase für Video fehlgeschlagen",
                        exc,
                        details=str(video),
                    )
                    poster_errors += 1
                finally:
                    for leftover in (tmp_path, raw_download):
                        try:
                            if leftover.exists():
                                leftover.unlink()
                        except OSError:
                            pass

                poster_processed += 1
                GLib.idle_add(
                    self.artwork_phase_progress,
                    "Posterphase",
                    poster_fraction(poster_processed),
                    f"Phase 1/2 · Datei {index} von {len(videos)}",
                    f"Posterphase: {local_posters + online_posters} Bilder, "
                    f"{poster_skipped} übersprungen, {poster_missed} ohne Poster, "
                    f"{poster_errors} Fehler",
                )
                if self.cancel_event.wait(THUMBNAIL_BATCH_PAUSE_SECONDS):
                    raise ScanCancelled

            for folder_index, target in enumerate(folder_targets, start=1):
                if self.cancel_event.is_set():
                    raise ScanCancelled
                mapping = target['mapping']
                try:
                    if target['kind'] == 'series':
                        thumb_path = self.series_folder_thumbnail_path(mapping)
                        if only_missing and thumb_path.exists():
                            poster_skipped += 1
                        elif self.ensure_series_folder_thumbnail_file(mapping, tile_width, tile_height):
                            series_posters += 1
                        else:
                            poster_missed += 1
                    else:
                        thumb_path = self.season_folder_thumbnail_path(mapping, target['season_number'])
                        if only_missing and thumb_path.exists():
                            poster_skipped += 1
                        elif self.ensure_season_folder_thumbnail_file(
                            mapping, target['season_number'], tile_width, tile_height
                        ):
                            season_posters += 1
                        else:
                            poster_missed += 1
                except ScanCancelled:
                    raise
                except (
                    OSError, GLib.Error, subprocess.SubprocessError,
                    urllib.error.URLError, socket.timeout, TimeoutError,
                    json.JSONDecodeError, ValueError, KeyError,
                ) as exc:
                    self.log_error(
                        "Posterphase für Serien-/Staffelordner fehlgeschlagen",
                        exc,
                        details=str(target.get("folder")),
                    )
                    poster_errors += 1

                poster_processed += 1
                GLib.idle_add(
                    self.artwork_phase_progress,
                    "Posterphase",
                    poster_fraction(poster_processed),
                    f"Phase 1/2 · Ordner {folder_index} von {len(folder_targets)}",
                    f"Posterphase: {local_posters + online_posters} Videobilder, "
                    f"Serienposter {series_posters}, Staffelposter {season_posters}, "
                    f"{poster_missed} ohne Poster, {poster_errors} Fehler",
                )
                if self.cancel_event.wait(THUMBNAIL_BATCH_PAUSE_SECONDS):
                    raise ScanCancelled

            thumbnail_targets = [video for video in videos if not self.thumbnail_path(video).exists()]
            thumbnail_total = len(thumbnail_targets)

            # Der Wechsel in Phase 2 wird sofort angezeigt. Zuvor blieb die
            # Anzeige bei „Posterphase 40 von 40“ stehen, bis das erste –
            # möglicherweise langsame – ffmpeg-Vorschaubild vollständig fertig war.
            GLib.idle_add(
                self.artwork_phase_progress,
                "Vorschaubilder",
                0.65,
                f"Phase 2/2 · 0 von {thumbnail_total} verarbeitet",
                (
                    f"Vorschaubildphase startet: {thumbnail_total} Dateien ohne Bild."
                    if thumbnail_total
                    else "Keine Videostandbilder erforderlich."
                ),
            )
            if thumbnail_total == 0:
                GLib.idle_add(
                    self.artwork_phase_progress,
                    "Vorschaubilder",
                    1.0,
                    "Phase 2/2 · keine Videostandbilder nötig",
                    "Alle benötigten Bilder wurden bereits in der Posterphase gefunden.",
                )
            else:
                for index, video in enumerate(thumbnail_targets, start=1):
                    if self.cancel_event.is_set():
                        raise ScanCancelled
                    thumb_path = self.thumbnail_path(video)
                    tmp_path = thumb_path.with_suffix('.tmp.jpg')
                    success = False
                    try:
                        seek_times = self.thumbnail_seek_times(video)
                        file_fraction = 0.65 + 0.35 * ((index - 1) / max(1, thumbnail_total))
                        GLib.idle_add(
                            self.artwork_phase_progress,
                            "Vorschaubilder",
                            file_fraction,
                            f"Phase 2/2 · Datei {index} von {thumbnail_total} wird verarbeitet",
                            f"Vorschaubild wird erzeugt: {video.name}",
                        )
                        for attempt, seek_time in enumerate(seek_times, start=1):
                            if self.cancel_event.is_set():
                                raise ScanCancelled
                            GLib.idle_add(
                                self.artwork_phase_progress,
                                "Vorschaubilder",
                                file_fraction,
                                (
                                    f"Phase 2/2 · Datei {index} von {thumbnail_total} · "
                                    f"Versuch {attempt} von {len(seek_times)}"
                                ),
                                (
                                    f"FFmpeg verarbeitet {video.name} bei "
                                    f"{seek_time}"
                                ),
                            )
                            success = self.run_ffmpeg_thumbnail(
                                video,
                                tmp_path,
                                seek_time,
                                tile_width,
                                tile_height,
                                progress_callback=(
                                    lambda mode, elapsed, limit, paused,
                                    fraction=file_fraction,
                                    current_index=index,
                                    current_total=thumbnail_total,
                                    current_attempt=attempt,
                                    attempt_total=len(seek_times),
                                    current_name=video.name,
                                    current_seek=seek_time:
                                    self.artwork_ffmpeg_heartbeat(
                                        fraction,
                                        current_index,
                                        current_total,
                                        current_attempt,
                                        attempt_total,
                                        current_name,
                                        current_seek,
                                        mode,
                                        elapsed,
                                        limit,
                                        paused,
                                    )
                                ),
                            )
                            if success:
                                break
                        if success and tmp_path.exists():
                            tmp_path.replace(thumb_path)
                            thumbnail_generated += 1
                        else:
                            thumbnail_failed += 1
                    except ScanCancelled:
                        raise
                    except FileNotFoundError as exc:
                        self.log_error(
                            "Fallback-Vorschaubild: ffmpeg nicht gefunden",
                            exc,
                            details=str(video),
                        )
                        thumbnail_failed += 1
                        GLib.idle_add(
                            self.status_label.set_text,
                            'ffmpeg fehlt: sudo apt install ffmpeg',
                        )
                    except (
                        OSError, GLib.Error, subprocess.SubprocessError,
                        urllib.error.URLError, socket.timeout, TimeoutError,
                        json.JSONDecodeError, ValueError, KeyError,
                    ) as exc:
                        self.log_error(
                            "Fallback-Vorschaubild fehlgeschlagen",
                            exc,
                            details=str(video),
                        )
                        thumbnail_failed += 1
                    finally:
                        try:
                            if tmp_path.exists():
                                tmp_path.unlink()
                        except OSError:
                            pass

                    fraction = 0.65 + 0.35 * (index / max(1, thumbnail_total))
                    GLib.idle_add(
                        self.artwork_phase_progress,
                        "Vorschaubilder",
                        fraction,
                        f"Phase 2/2 · Datei {index} von {thumbnail_total}",
                        f"Vorschaubilder: {thumbnail_generated} erzeugt, "
                        f"{thumbnail_failed} fehlgeschlagen, "
                        f"{thumbnail_total - index} offen",
                    )
                    if self.cancel_event.wait(THUMBNAIL_BATCH_PAUSE_SECONDS):
                        raise ScanCancelled
        except ScanCancelled:
            cancelled = True
        except Exception as exc:
            worker_error = True
            poster_errors += 1
            self.log_error(
                "Kombinierter Poster-/Vorschaubildlauf unerwartet abgebrochen",
                exc,
            )

        GLib.idle_add(
            self.finish_artwork_fetch,
            {
                'video_total': len(videos),
                'folder_total': len(folder_targets),
                'local_posters': local_posters,
                'online_posters': online_posters,
                'series_posters': series_posters,
                'season_posters': season_posters,
                'poster_skipped': poster_skipped,
                'poster_missed': poster_missed,
                'poster_errors': poster_errors,
                'thumbnail_generated': thumbnail_generated,
                'thumbnail_failed': thumbnail_failed,
            },
            cancelled,
            worker_error,
        )

    def finish_artwork_fetch(
        self, stats, cancelled=False, worker_error=False
    ):
        error_total = (
            int(stats.get("poster_errors", 0))
            + int(stats.get("thumbnail_failed", 0))
        )
        log_level = logging.ERROR if error_total else logging.INFO
        self.logger.log(
            log_level,
            "Bilderlauf beendet | Statistik: %s | abgebrochen=%s",
            stats,
            cancelled,
        )
        if cancelled:
            return self.finish_cancelled_scan(
                "Poster und Vorschaubilder",
                save_index=False,
                refresh=True,
            )
        self.end_scan()
        self.progress_bar.set_fraction(1.0)
        self.progress_bar.set_text(
            "Bilderlauf mit Fehler beendet"
            if worker_error
            else "Poster und Vorschaubilder abgeschlossen · 100.0 % · ETA: 0 s"
        )
        result_prefix = (
            "Bilderlauf vorzeitig beendet"
            if worker_error
            else "Bilderlauf fertig"
        )
        self.status_label.set_text(
            f"{result_prefix}: lokal {stats.get('local_posters', 0)}, "
            f"online {stats.get('online_posters', 0)}, Serienposter {stats.get('series_posters', 0)}, "
            f"Staffelposter {stats.get('season_posters', 0)}, "
            f"Videovorschaubilder {stats.get('thumbnail_generated', 0)}, "
            f"Poster ohne Treffer {stats.get('poster_missed', 0)}, "
            f"Fehler {stats.get('poster_errors', 0) + stats.get('thumbnail_failed', 0)}"
        )
        self.rebuild_folder_tree_preserving_state()
        self.refresh_visible_videos()
        return False

    def test_tmdb_access(self, api_key, read_token):
        url = "https://api.themoviedb.org/3/configuration"
        headers = None
        if read_token:
            headers = {"Authorization": f"Bearer {read_token}"}
        elif api_key:
            url += "?api_key=" + urllib.parse.quote(api_key)
        else:
            return False, "Es wurde weder API-Key noch Read-Token eingegeben."
        try:
            data = self.request_json(url, headers)
            if isinstance(data, dict) and isinstance(data.get("images"), dict):
                return True, "TMDb-Zugang ist gültig und erreichbar."
            return False, "TMDb antwortete, aber nicht mit den erwarteten Konfigurationsdaten."
        except urllib.error.HTTPError as exc:
            if exc.code in (401, 403):
                return False, f"TMDb hat den Zugang abgelehnt (HTTP {exc.code})."
            return False, f"TMDb-Fehler: HTTP {exc.code}."
        except (urllib.error.URLError, socket.timeout, TimeoutError) as exc:
            return False, f"TMDb ist derzeit nicht erreichbar: {exc}"
        except (OSError, ValueError, json.JSONDecodeError) as exc:
            return False, f"TMDb-Test fehlgeschlagen: {exc}"

