    def edit_intelligent_search_data(self, video_path):
        """Bearbeitet Suchalias und startet auf Wunsch die Suchkaskade."""
        video_path = Path(video_path)
        record = self.library_records.get(str(video_path))
        if not record:
            return
        self.normalize_record(record)
        metadata = record["metadata"]
        guessed_title, guessed_year = self.guess_title_and_year(video_path)

        dialog = Gtk.Dialog(
            title="Suchdaten und intelligente Metadatensuche",
            transient_for=self,
            modal=True,
        )
        dialog.add_buttons(
            Gtk.STOCK_CANCEL, Gtk.ResponseType.CANCEL,
            "Nur speichern", Gtk.ResponseType.APPLY,
            "Intelligent suchen", Gtk.ResponseType.OK,
        )
        box = dialog.get_content_area()
        box.set_spacing(9)
        box.set_border_width(12)
        info = Gtk.Label(label=f"Datei:\n{video_path}")
        info.set_xalign(0)
        info.set_line_wrap(True)
        box.pack_start(info, False, False, 0)

        grid = Gtk.Grid(column_spacing=10, row_spacing=8)
        box.pack_start(grid, False, False, 0)
        title_entry = Gtk.Entry()
        title_entry.set_text(str(metadata.get("manual_search_title") or guessed_title or ""))
        original_entry = Gtk.Entry()
        original_entry.set_text(str(metadata.get("manual_original_title") or ""))
        terms_entry = Gtk.Entry()
        stored_terms = metadata.get("manual_search_terms") or []
        if isinstance(stored_terms, str):
            stored_terms = [part.strip() for part in stored_terms.split(";") if part.strip()]
        terms_entry.set_text("; ".join(str(item) for item in stored_terms))
        terms_entry.set_placeholder_text("z. B. Worth; Michael Keaton; Stanley Tucci")
        year_entry = Gtk.Entry()
        year_entry.set_text(str(metadata.get("manual_search_year") or guessed_year or ""))
        type_combo = Gtk.ComboBoxText()
        for key, label in (("auto", "Automatisch"), ("movie", "Film"), ("series", "Serie")):
            type_combo.append(key, label)
        type_combo.set_active_id(str(metadata.get("manual_media_type") or "auto"))

        grid.attach(Gtk.Label(label="Deutscher/Suchtitel:", xalign=0), 0, 0, 1, 1)
        grid.attach(title_entry, 1, 0, 1, 1)
        grid.attach(Gtk.Label(label="Original-/Alternativtitel:", xalign=0), 0, 1, 1, 1)
        grid.attach(original_entry, 1, 1, 1, 1)
        grid.attach(Gtk.Label(label="Weitere Suchbegriffe:", xalign=0), 0, 2, 1, 1)
        grid.attach(terms_entry, 1, 2, 1, 1)
        grid.attach(Gtk.Label(label="Erscheinungsjahr:", xalign=0), 0, 3, 1, 1)
        grid.attach(year_entry, 1, 3, 1, 1)
        grid.attach(Gtk.Label(label="Medientyp:", xalign=0), 0, 4, 1, 1)
        grid.attach(type_combo, 1, 4, 1, 1)

        note = Gtk.Label(
            label=(
                "Beispiel: Für „9/11 – Was ist ein Leben wert?“ kann als Originaltitel „Worth“ "
                "und als Jahr „2020“ eingetragen werden. Leere Felder werden automatisch ergänzt."
            )
        )
        note.set_xalign(0)
        note.set_line_wrap(True)
        note.get_style_context().add_class("dim-label")
        box.pack_start(note, False, False, 0)
        dialog.show_all()
        response = dialog.run()

        if response in (Gtk.ResponseType.APPLY, Gtk.ResponseType.OK):
            metadata["manual_search_title"] = title_entry.get_text().strip() or None
            metadata["manual_original_title"] = original_entry.get_text().strip() or None
            metadata["manual_search_terms"] = [
                part.strip() for part in terms_entry.get_text().split(";") if part.strip()
            ]
            year_text = year_entry.get_text().strip()
            metadata["manual_search_year"] = year_text if re.fullmatch(r"\d{4}", year_text) else None
            metadata["manual_media_type"] = type_combo.get_active_id() or "auto"
            metadata["manual_fields"] = [
                field for field, value in (
                    ("search_title", metadata["manual_search_title"]),
                    ("original_title", metadata["manual_original_title"]),
                    ("search_terms", metadata["manual_search_terms"]),
                    ("year", metadata["manual_search_year"]),
                    ("media_type", metadata["manual_media_type"] != "auto"),
                ) if value
            ]
            self.save_index(show_errors=False)
        dialog.destroy()

        if response == Gtk.ResponseType.OK:
            self.start_intelligent_single_lookup(video_path)
        elif response == Gtk.ResponseType.APPLY:
            self.status_label.set_text(f"Suchdaten gespeichert: {self.pretty_title(video_path)}")
            self.update_detail_panel(video=video_path)

    @staticmethod
    def clean_wikipedia_value(value):
        """Entfernt einfache MediaWiki-Auszeichnung aus Infoboxwerten."""
        value = str(value or "")
        value = re.sub(r"<!--.*?-->", " ", value, flags=re.DOTALL)
        value = re.sub(r"<ref[^>]*>.*?</ref>", " ", value, flags=re.DOTALL | re.IGNORECASE)
        value = re.sub(r"<ref[^>]*/>", " ", value, flags=re.IGNORECASE)
        value = re.sub(r"\{\{[^{}]*\}\}", " ", value)
        value = re.sub(r"\[\[(?:[^]|]+\|)?([^]]+)\]\]", r"\1", value)
        value = re.sub(r"'{2,}", "", value)
        value = re.sub(r"<[^>]+>", " ", value)
        return re.sub(r"\s+", " ", value).strip(" |,;–-")

    @staticmethod
    def is_generic_library_folder_name(value):
        """Erkennt Genre- und Sammelordner, die niemals als Filmtitel dienen sollen."""
        normalized = CarborApp.normalize_title_for_match(str(value or ""))
        return normalized in GENERIC_LIBRARY_FOLDER_NAMES

    @staticmethod
    def wikipedia_query_variants(query):
        """Erzeugt robuste Wikipedia-Suchen für abweichende Titelzeichen.

        Dateinamen verwenden häufig einfache Bindestriche statt Gedankenstrichen
        oder schreiben Datumsformen wie »9-11« statt »9/11«. Deshalb entstehen
        zuerst mehrere normalisierte Titelvarianten. Erst danach folgen
        intitle- und vorsichtige Wildcard-Suchen.
        """
        query = re.sub(r"\s+", " ", str(query or "")).strip()
        if not query:
            return []

        title_forms = [query]
        punctuation_normalized = re.sub(r"\s*[-–—]\s*", " – ", query)
        slash_normalized = re.sub(r"\b(\d{1,2})\s*[-–—]\s*(\d{1,2})\b", r"\1/\2", query)
        slash_and_punctuation = re.sub(
            r"\s*[-–—]\s*", " – ",
            re.sub(r"\b(\d{1,2})\s*[-–—]\s*(\d{1,2})\b", r"\1/\2", query),
        )
        plain = re.sub(r"[\[\](){}]", " ", slash_and_punctuation)
        plain = re.sub(r"\s+", " ", plain).strip(" -–—:;,.!")

        for value in (punctuation_normalized, slash_normalized, slash_and_punctuation, plain):
            value = re.sub(r"\s+", " ", value).strip()
            if value and value.casefold() not in {item.casefold() for item in title_forms}:
                title_forms.append(value)

        variants = []
        for title in title_forms[:4]:
            variants.append(f'"{title}" film')
            variants.append(f'intitle:"{title}"')

        words = [
            word for word in re.findall(r"[\wÄÖÜäöüß0-9/’]+", plain)
            if len(word) > 1
        ]
        if words:
            tail = " ".join(words[-6:])
            if tail.casefold() not in {item.casefold() for item in title_forms}:
                variants.extend([f'"{tail}" film', f'intitle:"{tail}"'])
            if len(words[-1]) >= 4:
                variants.append(" ".join(words[:-1] + [words[-1] + "*", "film"]))

        result = []
        seen = set()
        for value in variants:
            key = value.casefold()
            if key not in seen:
                seen.add(key)
                result.append(value)
        return result[:12]

    def wikipedia_page_details(self, language, page_title):
        """Liest Filmangaben aus Wikipedia-Infobox und Wikidata strukturiert aus."""
        params = urllib.parse.urlencode({
            "action": "parse", "page": page_title, "prop": "wikitext|properties",
            "format": "json", "formatversion": 2, "redirects": 1,
        })
        try:
            data = self.request_json(f"https://{language}.wikipedia.org/w/api.php?{params}")
        except Exception:
            return None
        parsed = data.get("parse") or {}
        if not isinstance(parsed, dict):
            return None
        wikitext = str(parsed.get("wikitext") or "")
        properties = parsed.get("properties") or []
        if isinstance(properties, dict):
            properties = [properties]
        elif not isinstance(properties, list):
            properties = []

        wikidata_id = None
        for item in properties:
            if not isinstance(item, dict):
                continue
            if item.get("name") != "wikibase_item":
                continue
            wikidata_id = item.get("*") or item.get("value")
            if wikidata_id:
                break

        def infobox_field(*names):
            for name in names:
                match = re.search(
                    rf"(?im)^\s*\|\s*{re.escape(name)}\s*=\s*(.+?)(?=\n\s*\||\n\s*\}}\}})",
                    wikitext, flags=re.DOTALL,
                )
                if match:
                    value = self.clean_wikipedia_value(match.group(1))
                    if value:
                        return value
            return None

        # Die deutschsprachige Vorlage „Infobox Film“ verwendet überwiegend
        # kurze Parameternamen: OT, PJ, LEN, REG und DS. Ausgeschriebene Namen
        # bleiben als Fallback für andere Vorlagen und Sprachversionen erhalten.
        original_title = infobox_field(
            "OT", "Originaltitel", "original_title", "original title"
        )
        year_text = infobox_field(
            "PJ", "Erscheinungsjahr", "released", "release_date", "releasedate"
        )
        runtime_text = infobox_field("LEN", "Länge", "runtime")
        director_text = infobox_field("REG", "Regie", "director")
        cast_text = infobox_field(
            "DS", "Darsteller", "Besetzung", "starring", "cast"
        )
        genre_text = infobox_field("GEN", "Genre", "genre")
        year_match = YEAR_PATTERN.search(year_text or "")
        year = year_match.group(1) if year_match else ""
        runtime_match = re.search(r"(\d{2,3})", runtime_text or "")
        runtime = int(runtime_match.group(1)) if runtime_match else None

        def split_people(value):
            if not value:
                return []
            parts = re.split(r"[,;•·]|\s{2,}|\n", value)
            return [part.strip() for part in parts if 2 < len(part.strip()) < 80][:12]

        wikidata = None
        if wikidata_id:
            wb_params = urllib.parse.urlencode({
                "action": "wbgetentities", "ids": wikidata_id,
                "props": "labels|aliases|claims", "languages": "de|en",
                "languagefallback": 1, "format": "json",
            })
            try:
                wb_data = self.request_json(f"https://www.wikidata.org/w/api.php?{wb_params}")
                entities = wb_data.get("entities") if isinstance(wb_data, dict) else {}
                if not isinstance(entities, dict):
                    entities = {}
                wikidata = entities.get(wikidata_id) or {}
                if not isinstance(wikidata, dict):
                    wikidata = {}
            except Exception:
                wikidata = None

        if isinstance(wikidata, dict) and wikidata:
            claims = wikidata.get("claims") or {}
            if not isinstance(claims, dict):
                claims = {}
            if not original_title:
                for statement in claims.get("P1476", []) if isinstance(claims.get("P1476", []), list) else []:
                    if not isinstance(statement, dict):
                        continue
                    mainsnak = statement.get("mainsnak") or {}
                    if not isinstance(mainsnak, dict):
                        continue
                    datavalue = mainsnak.get("datavalue") or {}
                    if not isinstance(datavalue, dict):
                        continue
                    value = datavalue.get("value")
                    if isinstance(value, dict) and value.get("text"):
                        original_title = str(value["text"]).strip(); break
            if not year:
                for statement in claims.get("P577", []) if isinstance(claims.get("P577", []), list) else []:
                    if not isinstance(statement, dict):
                        continue
                    mainsnak = statement.get("mainsnak") or {}
                    if not isinstance(mainsnak, dict):
                        continue
                    datavalue = mainsnak.get("datavalue") or {}
                    if not isinstance(datavalue, dict):
                        continue
                    value = datavalue.get("value")
                    if isinstance(value, dict):
                        match = re.search(r"[+-](\d{4})-", str(value.get("time") or ""))
                        if match:
                            year = match.group(1); break
            if runtime is None:
                for statement in claims.get("P2047", []) if isinstance(claims.get("P2047", []), list) else []:
                    if not isinstance(statement, dict):
                        continue
                    mainsnak = statement.get("mainsnak") or {}
                    if not isinstance(mainsnak, dict):
                        continue
                    datavalue = mainsnak.get("datavalue") or {}
                    if not isinstance(datavalue, dict):
                        continue
                    value = datavalue.get("value")
                    if isinstance(value, dict):
                        try: runtime = int(round(float(value.get("amount"))))
                        except (TypeError, ValueError): pass
                        if runtime: break

        return {
            "original_title": original_title, "year": year, "runtime": runtime,
            "director": split_people(director_text), "cast": split_people(cast_text),
            "genres": split_people(genre_text), "wikidata_id": wikidata_id,
        }

    def set_intelligent_search_status(self, stage, detail="", fraction=None):
        """Aktualisiert Statuszeile und Fortschrittsbalken einer intelligenten Suche."""
        text = f"Intelligente Suche: {stage}"
        if detail:
            text += f" – {detail}"
        GLib.idle_add(self.status_label.set_text, text)
        if fraction is not None:
            value = max(0.0, min(1.0, float(fraction)))
            GLib.idle_add(self.progress_bar.set_fraction, value)
            GLib.idle_add(self.progress_bar.set_text, f"{stage} · {value * 100:.1f} %")

    @staticmethod
    def wikipedia_direct_title_forms(query):
        """Erzeugt wahrscheinliche Artikeltitel ohne CirrusSearch-Syntax."""
        query = re.sub(r"\s+", " ", str(query or "")).strip()
        if not query:
            return []
        forms = [query]
        slash = re.sub(r"\b(\d{1,2})\s*[-–—]\s*(\d{1,2})\b", r"\1/\2", query)
        dash = re.sub(r"\s*[-–—]\s*", " – ", slash)
        plain = re.sub(r"[\[\](){}]", " ", dash)
        plain = re.sub(r"\s+", " ", plain).strip(" -–—:;,.!")
        for value in (slash, dash, plain):
            if value and value.casefold() not in {item.casefold() for item in forms}:
                forms.append(value)

        # Viele deutsche Filmtitel enden als Frage. Dateinamen verlieren dieses
        # Zeichen häufig, Wikipedia-Artikeltitel enthalten es aber weiterhin.
        for value in list(forms):
            if value and not value.endswith("?"):
                question_form = value + "?"
                if question_form.casefold() not in {
                    item.casefold() for item in forms
                }:
                    forms.append(question_form)
        return forms[:10]

    def wikipedia_direct_page_hints(self, query, video_path=None):
        """Prüft wahrscheinliche Wikipedia-Artikeltitel vor der Volltextsuche."""
        if not self.intelligent_web_search_enabled or not query:
            return []
        hints = []
        video_runtime = None
        if video_path:
            duration = self.get_video_duration_seconds(video_path)
            if duration:
                try:
                    video_runtime = float(duration) / 60.0
                except (TypeError, ValueError):
                    video_runtime = None
        normalized_query = self.normalize_title_for_match(query)
        for language in ("de", "en"):
            for title_form in self.wikipedia_direct_title_forms(query):
                params = urllib.parse.urlencode({
                    "action": "query", "titles": title_form,
                    "redirects": 1, "prop": "info|pageprops",
                    "format": "json", "formatversion": 2,
                })
                try:
                    data = self.request_json(f"https://{language}.wikipedia.org/w/api.php?{params}")
                except Exception:
                    continue
                query_data = data.get("query") if isinstance(data, dict) else {}
                if not isinstance(query_data, dict):
                    query_data = {}
                pages = query_data.get("pages") or []
                if isinstance(pages, dict):
                    pages = list(pages.values())
                elif not isinstance(pages, list):
                    pages = []
                for page in pages:
                    if not isinstance(page, dict):
                        continue
                    if page.get("missing") is not None:
                        continue
                    page_title = str(page.get("title") or "").strip()
                    if not page_title:
                        continue
                    details = self.wikipedia_page_details(language, page_title) or {}
                    if not details:
                        continue
                    title_score = difflib.SequenceMatcher(
                        None,
                        normalized_query,
                        self.normalize_title_for_match(page_title),
                    ).ratio()
                    runtime_bonus = 0.0
                    if video_runtime and details.get("runtime"):
                        try:
                            difference = abs(video_runtime - float(details["runtime"]))
                            runtime_bonus = max(-0.10, 0.12 - difference / 90.0)
                        except (TypeError, ValueError):
                            runtime_bonus = 0.0
                    has_film_fields = bool(
                        details.get("original_title")
                        or details.get("year")
                        or details.get("runtime")
                        or details.get("director")
                        or details.get("cast")
                    )
                    if has_film_fields:
                        confidence = max(
                            0.0,
                            min(0.99, 0.70 + title_score * 0.20 + runtime_bonus),
                        )
                    else:
                        # Ein gleichnamiger Wikipedia-Artikel ohne erkennbare
                        # Filmdaten ist kein starker Beleg. Das verhindert,
                        # dass Begriffsklärungen oder allgemeine Artikel eine
                        # exakte Filmzuordnung vortäuschen.
                        confidence = max(0.0, min(0.62, 0.30 + title_score * 0.25))
                    hint = {
                        "source": f"wikipedia-direct-{language}",
                        "search_query": title_form,
                        "title": page_title,
                        "localized_title": page_title,
                        "original_title": details.get("original_title"),
                        "year": details.get("year"),
                        "runtime": details.get("runtime"),
                        "director": details.get("director") or [],
                        "cast": details.get("cast") or [],
                        "genres": details.get("genres") or [],
                        "media_type": "movie" if details.get("original_title") or details.get("runtime") else None,
                        "confidence": confidence,
                        "wikidata_id": details.get("wikidata_id"),
                        "text": "Direkter Wikipedia-Artikeltreffer",
                    }
                    hints.append(hint)
                    extracted = []
                    if hint.get("original_title"):
                        extracted.append(f"OT: {hint['original_title']}")
                    if hint.get("year"):
                        extracted.append(str(hint["year"]))
                    if hint.get("runtime"):
                        extracted.append(f"{hint['runtime']} min")
                    self.set_intelligent_search_status(
                        "Wikipedia-Artikel gefunden",
                        page_title + (
                            " · " + " · ".join(extracted)
                            if extracted else " · keine Filmfelder erkannt"
                        ),
                        0.28,
                    )
        hints.sort(key=lambda item: item.get("confidence", 0), reverse=True)
        return hints[:6]

    def wikipedia_search_hints(self, query, video_path=None):
        """Sucht über mehrere CirrusSearch-Varianten und bewertet Artikelbelege."""
        if not self.intelligent_web_search_enabled or not query:
            return []
        hints = []
        seen_pages = set()
        normalized_query = self.normalize_title_for_match(query)
        video_runtime = None
        if video_path:
            duration_seconds = self.get_video_duration_seconds(video_path)
            if duration_seconds:
                try:
                    video_runtime = float(duration_seconds) / 60.0
                except (TypeError, ValueError, ZeroDivisionError):
                    video_runtime = None
        for language in ("de", "en"):
            for search_query in self.wikipedia_query_variants(query):
                params = urllib.parse.urlencode({
                    "action": "query", "list": "search", "srsearch": search_query,
                    "srlimit": 5, "format": "json", "utf8": 1,
                })
                try:
                    data = self.request_json(f"https://{language}.wikipedia.org/w/api.php?{params}")
                except Exception:
                    continue
                query_data = data.get("query") if isinstance(data, dict) else {}
                if not isinstance(query_data, dict):
                    query_data = {}
                search_items = query_data.get("search") or []
                if not isinstance(search_items, list):
                    search_items = []
                for item in search_items:
                    try:
                        if not isinstance(item, dict):
                            continue
                        title = str(item.get("title") or "").strip()
                        page_key = (language, title.casefold())
                        if not title or page_key in seen_pages:
                            continue
                        seen_pages.add(page_key)

                        snippet = self.clean_wikipedia_value(item.get("snippet"))
                        details = self.wikipedia_page_details(language, title) or {}
                        normalized_title = self.normalize_title_for_match(title)
                        title_score = difflib.SequenceMatcher(
                            None, normalized_query, normalized_title
                        ).ratio()
                        original_title = details.get("original_title")
                        original_score = (
                            difflib.SequenceMatcher(
                                None,
                                normalized_query,
                                self.normalize_title_for_match(original_title),
                            ).ratio()
                            if original_title else 0.0
                        )
                        film_signal = (
                            "film" in snippet.casefold()
                            or bool(original_title)
                            or bool(details.get("runtime"))
                        )
                        runtime_score = 0.0
                        if video_runtime and details.get("runtime"):
                            try:
                                difference = abs(
                                    video_runtime - float(details["runtime"])
                                )
                                runtime_score = max(
                                    -0.18, 0.12 - difference / 120.0
                                )
                            except (TypeError, ValueError):
                                runtime_score = 0.0

                        confidence = (
                            0.42
                            + max(title_score, original_score) * 0.38
                            + (0.10 if film_signal else -0.12)
                            + runtime_score
                        )
                        confidence = max(0.0, min(0.98, confidence))
                        hint = {
                            "source": f"wikipedia-{language}",
                            "search_query": search_query,
                            "title": title,
                            "localized_title": title,
                            "original_title": original_title,
                            "year": details.get("year"),
                            "runtime": details.get("runtime"),
                            "director": details.get("director") or [],
                            "cast": details.get("cast") or [],
                            "genres": details.get("genres") or [],
                            "media_type": "movie" if film_signal else None,
                            "confidence": confidence,
                            "wikidata_id": details.get("wikidata_id"),
                            "text": snippet,
                        }
                        hints.append(hint)
                        if original_title or details.get("year") or details.get("runtime"):
                            extracted = []
                            if original_title:
                                extracted.append(f"OT: {original_title}")
                            if details.get("year"):
                                extracted.append(str(details["year"]))
                            if details.get("runtime"):
                                extracted.append(f"{details['runtime']} min")
                            self.set_intelligent_search_status(
                                "Wikipedia-Daten gelesen",
                                f"{title} · " + " · ".join(extracted),
                                0.48,
                            )
                    except (TypeError, ValueError, KeyError, AttributeError):
                        # Ein einzelner ungewöhnlicher Wikipedia-Treffer darf
                        # die gesamte intelligente Suche nicht abbrechen.
                        continue
        hints.sort(key=lambda item: item.get("confidence", 0), reverse=True)
        return hints[:10]

    def omdb_title_hint(self, title, year=""):
        """Fragt OMDb nach einem exakten Titel; Fehler bleiben folgenlos."""
        if not self.omdb_api_key or not title:
            return None
        params = {"apikey": self.omdb_api_key, "t": title, "plot": "short", "r": "json"}
        if year:
            params["y"] = str(year)
        try:
            data = self.request_json(f"https://www.omdbapi.com/?{urllib.parse.urlencode(params)}")
        except Exception:
            return None
        if str(data.get("Response", "")).lower() != "true":
            return None
        return {
            "source": "omdb",
            "title": data.get("Title"),
            "year": str(data.get("Year") or "")[:4],
            "original_title": data.get("Title"),
            "imdb_id": data.get("imdbID"),
            "type": data.get("Type"),
            "director": data.get("Director"),
            "plot": data.get("Plot"),
        }

    @staticmethod
    def extract_openai_output_text(payload):
        direct = payload.get("output_text") if isinstance(payload, dict) else None
        if isinstance(direct, str) and direct.strip():
            return direct.strip()
        parts = []
        for item in (payload.get("output") or []) if isinstance(payload, dict) else []:
            if item.get("type") != "message":
                continue
            for content in item.get("content") or []:
                if content.get("type") == "output_text" and content.get("text"):
                    parts.append(str(content["text"]))
        return "\n".join(parts).strip()

    def openai_title_hint(self, video_path, title, year, evidence):
        """Nutzt optional die Responses API und deren Websuche für einen Titelvorschlag."""
        if not (self.intelligent_ai_enabled and self.openai_api_key):
            return None
        evidence_text = json.dumps(evidence, ensure_ascii=False)[:8000]
        prompt = (
            "Bestimme den wahrscheinlichsten Film- oder Serientitel zu einer lokalen Videodatei. "
            "Nutze die Websuche, prüfe deutsche Verleihtitel, Originaltitel, Jahr und Laufzeit. "
            "Antworte ausschließlich als JSON-Objekt mit den Schlüsseln original_title, localized_title, "
            "year, media_type (movie oder series), confidence (0 bis 1), reason. Keine Markdown-Zeichen.\n\n"
            f"Datei: {video_path.name}\nVermuteter Titel: {title}\nVermutetes Jahr: {year or 'unbekannt'}\n"
            f"Laufzeit Sekunden: {self.get_video_duration_seconds(video_path) or 'unbekannt'}\n"
            f"Bisherige Hinweise: {evidence_text}"
        )
        body = {
            "model": self.openai_model,
            "input": prompt,
            "tools": [{"type": "web_search", "search_context_size": "low"}],
            "max_output_tokens": 500,
            "store": False,
        }
        request = urllib.request.Request(
            "https://api.openai.com/v1/responses",
            data=json.dumps(body).encode("utf-8"),
            headers={
                "Authorization": f"Bearer {self.openai_api_key}",
                "Content-Type": "application/json",
                "User-Agent": f"{APP_NAME}/{APP_VERSION}",
            },
            method="POST",
        )
        try:
            with urllib.request.urlopen(request, timeout=max(30, self.online_timeout)) as response:
                payload = json.loads(response.read().decode("utf-8", errors="replace"))
            raw = self.extract_openai_output_text(payload)
            match = re.search(r"\{.*\}", raw, re.DOTALL)
            result = json.loads(match.group(0) if match else raw)
        except Exception:
            return None
        if not isinstance(result, dict):
            return None
        result["source"] = "openai-web"
        try:
            result["confidence"] = max(0.0, min(1.0, float(result.get("confidence") or 0)))
        except (TypeError, ValueError):
            result["confidence"] = 0.0
        return result

    def intelligent_title_candidates(self, video_path):
        """Sammelt lokale, öffentliche und optionale KI-Hinweise ohne Genreordner als Titel."""
        record = self.library_records.get(str(video_path)) or {}
        metadata = record.get("metadata") or self.default_metadata()
        guessed_title, guessed_year = self.guess_title_and_year(video_path)
        filename_hints = self.analyze_filename_search_hints(video_path)
        manual_title = metadata.get("manual_search_title")
        manual_original = metadata.get("manual_original_title")
        manual_terms = metadata.get("manual_search_terms") or []
        if isinstance(manual_terms, str):
            manual_terms = [part.strip() for part in manual_terms.split(";") if part.strip()]
        year = str(metadata.get("manual_search_year") or guessed_year or "")
        base_titles = []
        for value in (manual_original, manual_title, *manual_terms, guessed_title):
            value = str(value or "").strip()
            if value and value.casefold() not in {item.casefold() for item in base_titles}:
                base_titles.append(value)
        parent_name = video_path.parent.name
        if not self.is_generic_library_folder_name(parent_name):
            normalized_parent = self.normalize_title_for_match(parent_name)
            normalized_file = self.normalize_title_for_match(guessed_title)
            if normalized_parent and normalized_parent != normalized_file and parent_name.casefold() not in {item.casefold() for item in base_titles}:
                base_titles.append(parent_name)

        evidence = []
        if filename_hints.get("creators"):
            evidence.append({
                "source": "filename-creator-hint",
                "search_query": filename_hints.get("raw_title"),
                "title": guessed_title,
                "localized_title": guessed_title,
                "original_title": guessed_title,
                "year": year or None,
                "runtime": None,
                "director": filename_hints["creators"],
                "cast": [],
                "genres": ["Kunstfilm"],
                "media_type": "movie",
                "confidence": 0.93,
                "text": "Urheber und Werkjahr aus strukturiertem Dateinamen",
                "is_excerpt": bool(filename_hints.get("is_excerpt")),
            })
        if filename_hints.get("cast"):
            evidence.append({
                "source": "filename-cast-hint",
                "search_query": filename_hints.get("raw_title"),
                "title": guessed_title,
                "localized_title": guessed_title,
                "original_title": None,
                "year": year or None,
                "runtime": None,
                "director": [],
                "cast": filename_hints["cast"],
                "genres": [],
                "media_type": "movie",
                "confidence": 0.88,
                "text": "Besetzungshinweis aus dem Dateinamen",
            })
            self.set_intelligent_search_status(
                "Dateiname analysiert",
                (
                    f"Titel: {guessed_title} · "
                    f"Darstellerhinweis: {', '.join(filename_hints['cast'])}"
                ),
                0.07,
            )
        else:
            details = [f"Titel: {guessed_title}"]
            if filename_hints.get("creators"):
                details.append(
                    "Urheber: " + ", ".join(filename_hints["creators"])
                )
            if year:
                details.append(f"Jahr: {year}")
            if filename_hints.get("is_excerpt"):
                details.append("Ausschnitt erkannt")
            self.set_intelligent_search_status(
                "Dateiname analysiert",
                " · ".join(details),
                0.07,
            )

        total_titles = max(1, len(base_titles[:5]))
        for index, title in enumerate(base_titles[:5], start=1):
            self.set_intelligent_search_status(
                "Wikipedia-Direktprüfung",
                f"{index}/{total_titles}: {title}",
                0.10 + (index - 1) / total_titles * 0.20,
            )
            direct_hints = self.wikipedia_direct_page_hints(title, video_path)
            evidence.extend(direct_hints)

            strongest_direct = max(
                (item.get("confidence", 0) for item in direct_hints),
                default=0,
            )
            if strongest_direct < 0.90:
                self.set_intelligent_search_status(
                    "Wikipedia-Suche",
                    f"Varianten für: {title}",
                    0.30 + (index - 1) / total_titles * 0.20,
                )
                evidence.extend(self.wikipedia_search_hints(title, video_path))

            self.set_intelligent_search_status(
                "OMDb-Prüfung",
                title,
                0.52 + (index - 1) / total_titles * 0.08,
            )
            omdb = self.omdb_title_hint(title, year)
            if omdb:
                evidence.append(omdb)

        if evidence:
            best_evidence = max(evidence, key=lambda item: item.get("confidence", 0))
            self.set_intelligent_search_status(
                "Quellen ausgewertet",
                (
                    f"bester Hinweis: "
                    f"{best_evidence.get('original_title') or best_evidence.get('title') or 'unbekannt'}"
                    f"{' · ' + str(best_evidence.get('year')) if best_evidence.get('year') else ''}"
                    f"{' · ' + str(best_evidence.get('runtime')) + ' min' if best_evidence.get('runtime') else ''}"
                ),
                0.62,
            )

        strongest_evidence = max(
            (item.get("confidence", 0) for item in evidence),
            default=0,
        )
        ai_hint = None
        if strongest_evidence < 0.94:
            self.set_intelligent_search_status(
                "KI-/Webprüfung",
                "öffentliche Quellen noch nicht eindeutig",
                0.68,
            )
            ai_hint = self.openai_title_hint(
                video_path,
                base_titles[0] if base_titles else guessed_title,
                year,
                evidence,
            )
        if ai_hint:
            evidence.append(ai_hint)

        candidates = []
        def add_candidate(value, source, confidence=0.5, candidate_year=None, media_type=None, evidence_item=None):
            value = str(value or "").strip()
            key = self.normalize_title_for_match(value)
            if not key: return
            existing = next((item for item in candidates if item["key"] == key), None)
            if existing:
                existing["confidence"] = max(existing["confidence"], float(confidence or 0))
                existing["sources"].add(source)
                if evidence_item: existing["evidence"].append(evidence_item)
                return
            candidates.append({
                "key": key, "title": value, "year": str(candidate_year or year or "")[:4],
                "media_type": media_type, "confidence": float(confidence or 0),
                "sources": {source}, "evidence": [evidence_item] if evidence_item else [],
            })

        for index, title in enumerate(base_titles):
            manual = title in {manual_original, manual_title, *manual_terms}
            add_candidate(title, "manual/local" if manual else "filename", 0.94 if manual else 0.72)
        for item in evidence:
            source = item.get("source") or "web"
            confidence = item.get("confidence", 0.72 if source == "omdb" else 0.55)
            for value in (item.get("original_title"), item.get("localized_title"), item.get("title")):
                add_candidate(value, source, confidence, item.get("year"), item.get("media_type") or item.get("type"), item)
        candidates.sort(key=lambda item: item["confidence"], reverse=True)
        return candidates[:16], evidence

    @staticmethod
    def evidence_people(evidence_items, field):
        values = []
        for item in evidence_items or []:
            raw = item.get(field) or []
            if isinstance(raw, str): raw = re.split(r"[,;]", raw)
            for value in raw:
                normalized = CarborApp.normalize_title_for_match(value)
                if normalized and normalized not in values: values.append(normalized)
        return values

    def score_intelligent_tmdb_result(self, video_path, hint, item, is_series, details=None):
        """Bewertet TMDb ohne vorzeitige Sättigung auf 1,0.

        Gleichnamige Werke erhalten oft denselben perfekten Titelwert. Deshalb
        bleiben Zusatzpunkte für Jahr, Laufzeit, Regie, Besetzung und Medientyp
        intern erhalten. Erst für die Anzeige wird später normalisiert.
        """
        search_year = hint.get("year") or ""
        tmdb_score = self.score_tmdb_candidate(
            hint["title"], search_year, item, is_series
        )
        guessed_title, _ = self.guess_title_and_year(video_path)
        result_title = item.get("name" if is_series else "title") or ""
        original_title = item.get(
            "original_name" if is_series else "original_title"
        ) or ""
        normalized_file = self.normalize_title_for_match(guessed_title)
        filename_similarity = max(
            difflib.SequenceMatcher(
                None,
                normalized_file,
                self.normalize_title_for_match(result_title),
            ).ratio(),
            difflib.SequenceMatcher(
                None,
                normalized_file,
                self.normalize_title_for_match(original_title),
            ).ratio(),
        )

        score = (
            tmdb_score * 0.48
            + float(hint.get("confidence") or 0) * 0.22
            + filename_similarity * 0.30
        )

        if filename_similarity < 0.25 and "manual/local" not in hint["sources"]:
            score -= 0.28

        # Eine einzelne lange Videodatei ohne Episodenmuster ist mit hoher
        # Wahrscheinlichkeit ein Film. Eine Serie mit identischem Titel darf
        # deshalb nicht allein wegen perfekter Titelgleichheit gleichziehen.
        episode_info = self.parse_series_episode(video_path)
        if is_series and episode_info is None:
            score -= 0.20
        elif not is_series and episode_info is not None:
            score -= 0.25

        if details:
            video_minutes = (
                float(self.get_video_duration_seconds(video_path) or 0) / 60.0
            )
            runtime = details.get("runtime")
            if is_series and not runtime:
                episode_times = details.get("episode_run_time") or []
                runtime = episode_times[0] if episode_times else None

            is_excerpt = any(
                isinstance(evidence_item, dict)
                and evidence_item.get("is_excerpt")
                for evidence_item in (hint.get("evidence") or [])
            )
            if video_minutes and runtime and not is_excerpt:
                try:
                    difference = abs(video_minutes - float(runtime))
                    if difference <= 8:
                        score += 0.18
                    elif difference <= 20:
                        score += 0.09
                    elif difference <= 45:
                        score += 0.01
                    else:
                        score -= min(0.22, difference / 300.0)
                except (TypeError, ValueError):
                    pass

            details_date = details.get(
                "first_air_date" if is_series else "release_date"
            ) or ""
            details_year = details_date[:4]
            if search_year and details_year:
                if str(search_year)[:4] == details_year:
                    score += 0.16
                else:
                    try:
                        distance = abs(int(str(search_year)[:4]) - int(details_year))
                        score -= min(0.20, distance * 0.035)
                    except ValueError:
                        pass

            credits = details.get("credits") or {}
            tmdb_cast = [
                self.normalize_title_for_match(person.get("name"))
                for person in credits.get("cast", [])[:20]
                if isinstance(person, dict) and person.get("name")
            ]
            tmdb_directors = [
                self.normalize_title_for_match(person.get("name"))
                for person in credits.get("crew", [])
                if (
                    isinstance(person, dict)
                    and person.get("job") == "Director"
                    and person.get("name")
                )
            ]
            expected_cast = self.evidence_people(
                hint.get("evidence"), "cast"
            )
            expected_directors = self.evidence_people(
                hint.get("evidence"), "director"
            )
            if expected_cast:
                overlap = len(set(expected_cast) & set(tmdb_cast))
                if overlap:
                    score += min(0.30, overlap * 0.14)
                else:
                    # Ein explizites »mit Person« im Dateinamen ist ein starker
                    # Gegenbeleg, wenn die Person im TMDb-Kandidaten fehlt.
                    has_filename_cast_hint = any(
                        item.get("source") == "filename-cast-hint"
                        for item in (hint.get("evidence") or [])
                        if isinstance(item, dict)
                    )
                    if has_filename_cast_hint:
                        score -= 0.22
            if expected_directors:
                overlap_directors = set(expected_directors) & set(tmdb_directors)
                if overlap_directors:
                    score += min(0.34, len(overlap_directors) * 0.18)
                else:
                    has_creator_hint = any(
                        isinstance(evidence_item, dict)
                        and evidence_item.get("source") == "filename-creator-hint"
                        for evidence_item in (hint.get("evidence") or [])
                    )
                    if has_creator_hint:
                        score -= 0.20

        # Nicht auf 1,0 begrenzen: Der Abstand zwischen gleichnamigen Werken
        # muss bis zur endgültigen Auswahl erhalten bleiben.
        return max(0.0, score), tmdb_score

    def intelligent_lookup_metadata(self, video_path):
        """Ermittelt einen TMDb-Treffer mit Belegprüfung und strenger Fehlertoleranz."""
        self.set_intelligent_search_status(
            "Lokale Analyse", self.pretty_title(video_path), 0.03
        )
        candidates, evidence = self.intelligent_title_candidates(video_path)
        self.set_intelligent_search_status(
            "TMDb-Kandidaten suchen",
            f"{len(candidates)} Titelvarianten",
            0.74,
        )
        record = self.library_records.get(str(video_path)) or {}
        old_metadata = record.get("metadata") or self.default_metadata()
        guessed_title, guessed_year = self.guess_title_and_year(video_path)
        forced = old_metadata.get("manual_media_type") or "auto"
        preliminary = {}
        for hint in candidates:
            possible_types = [forced] if forced in {"movie", "series"} else ["movie", "series"]
            if hint.get("media_type") in {"movie", "series"}: possible_types = [hint["media_type"]]
            for media_type in possible_types:
                is_series = media_type == "series"
                try: results = self.tmdb_search_candidates(hint["title"], hint.get("year") or "", is_series)
                except Exception: continue
                for item in results[:5]:
                    key = (is_series, int(item.get("id") or 0))
                    if not key[1]: continue
                    base_score, tmdb_score = self.score_intelligent_tmdb_result(video_path, hint, item, is_series)
                    current = preliminary.get(key)
                    if current is None or base_score > current[0]:
                        preliminary[key] = (base_score, tmdb_score, hint, item, is_series)

        self.set_intelligent_search_status(
            "TMDb-Treffer prüfen",
            f"{len(preliminary)} Kandidaten",
            0.84,
        )
        ranked = []
        for row in sorted(preliminary.values(), key=lambda value: value[0], reverse=True)[:10]:
            _base, _tmdb, hint, item, is_series = row
            try: details = self.tmdb_fetch_details(item.get("id"), is_series)
            except Exception: details = None
            final_score, tmdb_score = self.score_intelligent_tmdb_result(video_path, hint, item, is_series, details)
            ranked.append((final_score, tmdb_score, hint, item, is_series, details))
        ranked.sort(key=lambda row: row[0], reverse=True)
        self.set_intelligent_search_status(
            "Bewertung abgeschlossen",
            f"{len(ranked)} geprüfte TMDb-Treffer",
            0.96,
        )
        if not ranked:
            wikipedia_candidates = [
                item for item in evidence
                if (
                    isinstance(item, dict)
                    and str(item.get("source", "")).startswith("wikipedia")
                    and float(item.get("confidence") or 0) >= 0.82
                )
            ]
            if wikipedia_candidates:
                best_wikipedia = max(
                    wikipedia_candidates,
                    key=lambda item: float(item.get("confidence") or 0),
                )
                metadata = self.default_metadata()
                metadata.update({
                    "status": "found",
                    "source": best_wikipedia.get("source") or "wikipedia",
                    "media_type": best_wikipedia.get("media_type") or "movie",
                    "title": (
                        best_wikipedia.get("localized_title")
                        or best_wikipedia.get("title")
                    ),
                    "original_title": best_wikipedia.get("original_title"),
                    "year": best_wikipedia.get("year"),
                    "runtime": best_wikipedia.get("runtime"),
                    "genres": best_wikipedia.get("genres") or [],
                    "overview": best_wikipedia.get("text") or None,
                    "director": best_wikipedia.get("director") or [],
                    "cast": best_wikipedia.get("cast") or [],
                    "search_title": guessed_title,
                    "search_year": guessed_year or None,
                    "match_score": round(
                        min(1.0, float(best_wikipedia.get("confidence") or 0)),
                        3,
                    ),
                    "discovery_source": best_wikipedia.get("source"),
                    "discovery_confidence": round(
                        min(1.0, float(best_wikipedia.get("confidence") or 0)),
                        3,
                    ),
                    "discovery_notes": (
                        "Kein geeigneter TMDb-Treffer; belastbare "
                        "Wikipedia-Daten wurden direkt übernommen."
                    ),
                    "last_updated": GLib.DateTime.new_now_local().format_iso8601(),
                })
                return metadata

            metadata = dict(old_metadata)
            metadata.update({
                "status": "not_found",
                "source": "intelligent-search",
                "discovery_source": "OMDb/Wikipedia/OpenAI" if evidence else "local",
                "discovery_confidence": 0.0,
                "discovery_notes": "Keine verwertbaren TMDb- oder Wikipedia-Kandidaten gefunden.",
                "last_updated": GLib.DateTime.new_now_local().format_iso8601(),
            })
            return metadata

        best_score, tmdb_score, hint, item, is_series, details = ranked[0]
        second_score = ranked[1][0] if len(ranked) > 1 else 0.0
        candidate_list = []
        for row in ranked[:self.intelligent_candidate_limit]:
            score_value, _tmdb_value, _hint, candidate, candidate_is_series, candidate_details = row
            candidate_details = candidate_details or {}
            credits = candidate_details.get("credits") or {}

            if candidate_is_series:
                directors = [
                    person.get("name")
                    for person in candidate_details.get("created_by", [])
                    if isinstance(person, dict) and person.get("name")
                ]
                runtime = (
                    (candidate_details.get("episode_run_time") or [None])[0]
                )
            else:
                directors = [
                    person.get("name")
                    for person in credits.get("crew", [])
                    if (
                        isinstance(person, dict)
                        and person.get("job") == "Director"
                        and person.get("name")
                    )
                ]
                runtime = candidate_details.get("runtime")

            cast = [
                person.get("name")
                for person in credits.get("cast", [])[:8]
                if isinstance(person, dict) and person.get("name")
            ]
            poster_path = candidate_details.get("poster_path") or candidate.get("poster_path")
            candidate_list.append({
                "id": candidate.get("id"),
                "title": candidate.get("name" if candidate_is_series else "title") or "–",
                "original_title": candidate.get(
                    "original_name" if candidate_is_series else "original_title"
                ) or candidate_details.get(
                    "original_name" if candidate_is_series else "original_title"
                ),
                "media_type": "series" if candidate_is_series else "movie",
                "year": (
                    candidate.get(
                        "first_air_date" if candidate_is_series else "release_date"
                    ) or ""
                )[:4],
                "runtime": runtime,
                "director": directors[:3],
                "cast": cast,
                "overview": candidate_details.get("overview") or "",
                "poster_url": (
                    f"https://image.tmdb.org/t/p/w342{poster_path}"
                    if poster_path else None
                ),
                # Für die Anzeige auf 0–1 begrenzen; intern bleibt der volle
                # Abstand der Bewertungswerte erhalten.
                "score": round(min(1.0, score_value), 3),
            })
        if (
            best_score < self.intelligent_auto_accept_threshold
            or best_score - second_score < self.intelligent_min_gap
        ):
            metadata = dict(old_metadata)
            metadata.update({
                "status": "ambiguous", "source": "intelligent-search",
                "search_title": hint["title"], "search_year": hint.get("year") or None,
                "match_score": round(min(1.0, best_score), 3), "candidates": candidate_list,
                "discovery_source": ", ".join(sorted(hint["sources"])),
                "discovery_confidence": round(min(1.0, best_score), 3),
                "discovery_notes": (
                    "Vorschlag nicht automatisch übernommen; Bestätigung erforderlich. "
                    + (
                        "Wikipedia lieferte: "
                        + "; ".join(
                            filter(
                                None,
                                [
                                    str(hint.get("original_title") or ""),
                                    str(hint.get("year") or ""),
                                    (
                                        f"{hint.get('runtime')} min"
                                        if hint.get("runtime") else ""
                                    ),
                                ],
                            )
                        )
                        + ". TMDb-Zuordnung blieb dennoch unsicher."
                        if any(
                            str(item.get("source", "")).startswith("wikipedia")
                            for item in evidence
                        )
                        else "Keine eindeutige Wikipedia-Zuordnung gefunden."
                    )
                ),
                "last_updated": GLib.DateTime.new_now_local().format_iso8601(),
            })
            return metadata

        details = details or self.tmdb_fetch_details(item.get("id"), is_series)
        metadata = self.build_metadata_from_tmdb(details, tmdb_score, hint["title"], hint.get("year") or "", is_series)
        metadata["source"] = "tmdb+intelligent-search"
        metadata["discovery_source"] = ", ".join(sorted(hint["sources"]))
        metadata["discovery_confidence"] = round(min(1.0, best_score), 3)
        metadata["discovery_notes"] = "Automatisch über Titel, Jahr, Laufzeit, Regie und Besetzung geprüft."
        for field in ("manual_search_title", "manual_original_title", "manual_search_terms", "manual_search_year", "manual_media_type", "manual_fields"):
            metadata[field] = old_metadata.get(field)
        return metadata

    def start_intelligent_single_lookup(self, video_path):
        """Startet die Einzelsuche und meldet jeden Abbruchgrund sichtbar."""
        video_path = Path(video_path)
        self.status_label.set_text(
            f"Intelligente Suche wird vorbereitet: {self.pretty_title(video_path)}"
        )
        while Gtk.events_pending():
            Gtk.main_iteration_do(False)

        if not (self.tmdb_api_key or self.tmdb_read_token):
            message = "Für die intelligente Suche ist ein TMDb-Zugang erforderlich."
            self.logger.warning("%s | %s", message, video_path)
            self.show_error(message)
            self.status_label.set_text("Intelligente Suche nicht gestartet: TMDb-Zugang fehlt.")
            return

        if self.scan_running:
            active = self.active_scan_name or "unbekannter Hintergrundlauf"
            message = (
                f"Die intelligente Suche kann noch nicht starten, weil bereits "
                f"„{active}“ läuft."
            )
            self.logger.warning("%s | %s", message, video_path)
            self.status_label.set_text(message)
            dialog = Gtk.MessageDialog(
                transient_for=self,
                modal=True,
                message_type=Gtk.MessageType.INFO,
                buttons=Gtk.ButtonsType.OK,
                text="Intelligente Suche wartet",
            )
            dialog.format_secondary_text(
                f"Zurzeit läuft noch: {active}\n\n"
                "Beende oder brich diesen Vorgang im Scan-Center ab und starte "
                "die intelligente Suche anschließend erneut."
            )
            dialog.run()
            dialog.destroy()
            return

        if not self.begin_scan("Intelligente Einzelsuche"):
            message = "Die intelligente Suche konnte den Scanstatus nicht übernehmen."
            self.logger.warning("%s | %s", message, video_path)
            self.show_error(message)
            return

        self.logger.info("Intelligente Einzelsuche gestartet | %s", video_path)
        self.progress_bar.set_fraction(0.0)
        self.progress_bar.set_text("Intelligente Suche · 0.0 % · ETA: wird berechnet")
        self.status_label.set_text(f"Suchquellen werden geprüft: {self.pretty_title(video_path)}")
        while Gtk.events_pending():
            Gtk.main_iteration_do(False)

        try:
            worker = threading.Thread(
                target=self.intelligent_single_worker,
                args=(video_path,),
                daemon=True,
                name="Carbor-Intelligente-Einzelsuche",
            )
            worker.start()
        except Exception as exc:
            self.end_scan()
            self.log_error(
                "Intelligente Einzelsuche konnte nicht gestartet werden",
                exc,
                details=str(video_path),
            )
            self.show_error(
                f"Die intelligente Suche konnte nicht gestartet werden:\n"
                f"{type(exc).__name__}: {exc}"
            )

    def intelligent_single_worker(self, video_path):
        cancelled = False
        try:
            metadata = self.intelligent_lookup_metadata(video_path)
        except ScanCancelled:
            cancelled = True
            metadata = None
        except Exception as exc:
            self.log_error(
                "Intelligente Einzelsuche fehlgeschlagen",
                exc,
                details=str(video_path),
            )
            metadata = self.default_metadata()
            metadata.update({
                "status": "error",
                "source": "intelligent-search",
                "search_title": self.guess_title_and_year(video_path)[0],
                "error_message": f"{type(exc).__name__}: {exc}",
                "last_updated": GLib.DateTime.new_now_local().format_iso8601(),
            })
        if not cancelled and metadata is not None:
            record = self.library_records.get(str(video_path))
            if record:
                record["metadata"] = metadata
                self.save_index(show_errors=False)
        GLib.idle_add(self.finish_intelligent_single_lookup, video_path, metadata, cancelled)

    def finish_intelligent_single_lookup(self, video_path, metadata, cancelled=False):
        """Schließt die Einzelsuche ab und öffnet bei Mehrdeutigkeit die Auswahl.

        Eine bloße Textliste wäre unnötig umständlich: Sobald mehrere plausible
        TMDb-Kandidaten vorhanden sind, kann der Benutzer sie unmittelbar anhand
        von Jahr, Typ, Laufzeit, Regie, Besetzung und lokalem Vorschaubild wählen.
        """
        if cancelled:
            return self.finish_cancelled_scan(
                "Intelligente Einzelsuche",
                save_index=False,
                refresh=False,
            )
        self.end_scan()
        self.progress_bar.set_fraction(1.0)
        self.progress_bar.set_text("Intelligente Suche · 100.0 % · ETA: 0 s")
        status = metadata.get("status") if isinstance(metadata, dict) else "error"
        self.status_label.set_text(
            f"Intelligente Suche abgeschlossen: "
            f"{self.pretty_title(video_path)} – {status}"
        )
        self.refresh_visible_videos()
        self.update_detail_panel(video=video_path)

        if (
            status == "ambiguous"
            and isinstance(metadata.get("candidates"), list)
            and metadata.get("candidates")
        ):
            self.status_label.set_text(
                f"Mehrere plausible Treffer – bitte auswählen: "
                f"{self.pretty_title(video_path)}"
            )
            self.choose_ambiguous_candidate(Path(video_path))
        else:
            self.show_metadata_info(video_path)
        return False

    def on_intelligent_metadata_scan(self, _widget):
        if not (self.tmdb_api_key or self.tmdb_read_token):
            self.show_error("Für die abschließende Zuordnung ist ein TMDb-Zugang erforderlich.")
            return
        pending = [
            path for path in self.videos
            if (self.library_records.get(str(path), {}).get("metadata") or {}).get("status")
            in {None, "not_checked", "not_found", "ambiguous", "error"}
        ]
        if not pending:
            self.status_label.set_text("Es gibt keine unklaren Metadateneinträge.")
            return
        dialog = Gtk.MessageDialog(
            transient_for=self,
            modal=True,
            message_type=Gtk.MessageType.WARNING,
            buttons=Gtk.ButtonsType.OK_CANCEL,
            text="Intelligente Metadatensuche starten?",
        )
        dialog.format_secondary_text(
            f"{len(pending)} unklare Einträge werden geprüft. Öffentliche Webquellen und optionale API-Dienste "
            "können Netzwerkverkehr und API-Kosten verursachen. Nur ausreichend sichere Treffer werden automatisch übernommen."
        )
        response = dialog.run()
        dialog.destroy()
        if response != Gtk.ResponseType.OK or not self.begin_scan("Intelligenter Metadatenscan"):
            return
        self.progress_bar.set_fraction(0.0)
        self.update_scan_progress("Intelligente Metadaten", 0, len(pending))
        threading.Thread(target=self.intelligent_metadata_worker, args=(pending,), daemon=True).start()

    def intelligent_metadata_worker(self, videos):
        counts = {"found": 0, "ambiguous": 0, "not_found": 0, "error": 0}
        cancelled = False
        try:
            for number, video_path in enumerate(videos, 1):
                if self.cancel_event.is_set():
                    raise ScanCancelled
                try:
                    metadata = self.intelligent_lookup_metadata(video_path)
                except ScanCancelled:
                    raise
                except Exception as exc:
                    self.log_error(
                        "Intelligenter Metadatenscan fehlgeschlagen",
                        exc,
                        details=str(video_path),
                    )
                    metadata = self.default_metadata()
                    metadata.update({"status": "error", "source": "intelligent-search", "error_message": str(exc)})
                record = self.library_records.get(str(video_path))
                if record:
                    record["metadata"] = metadata
                status = metadata.get("status") or "error"
                counts[status] = counts.get(status, 0) + 1
                GLib.idle_add(self.update_scan_progress, "Intelligente Metadaten", number, len(videos))
                GLib.idle_add(
                    self.status_label.set_text,
                    f"Intelligente Suche: {number}/{len(videos)} · sicher {counts.get('found', 0)} · prüfbar {counts.get('ambiguous', 0)}",
                )
                if number % METADATA_CHECKPOINT_INTERVAL == 0:
                    self.save_index(show_errors=False)
        except ScanCancelled:
            cancelled = True
        self.save_index(show_errors=False)
        GLib.idle_add(self.finish_intelligent_metadata_scan, counts, cancelled)

    def finish_intelligent_metadata_scan(self, counts, cancelled=False):
        if cancelled:
            return self.finish_cancelled_scan("Intelligenter Metadatenscan", save_index=False, refresh=False)
        self.end_scan()
        self.progress_bar.set_fraction(1.0)
        self.progress_bar.set_text("Intelligente Metadaten · 100.0 % · ETA: 0 s")
        self.status_label.set_text(
            f"Intelligente Suche: {counts.get('found', 0)} sicher übernommen, "
            f"{counts.get('ambiguous', 0)} zur Prüfung, {counts.get('not_found', 0)} ohne Treffer, "
            f"{counts.get('error', 0)} Fehler"
        )
        self.refresh_visible_videos()
        return False

    def on_configure_tmdb(self, _widget):
        dialog = Gtk.Dialog(
            title="TMDb-Zugang einrichten",
            transient_for=self,
            modal=True,
        )
        dialog.add_buttons(
            Gtk.STOCK_CANCEL, Gtk.ResponseType.CANCEL,
            "Testen und speichern", Gtk.ResponseType.OK,
        )
        box = dialog.get_content_area()
        box.set_spacing(8)
        box.set_border_width(12)

        info = Gtk.Label(
            label=(
                "Trage den TMDb API-Key (v3) oder den Read Access Token ein. "
                "Der Token wird bevorzugt verwendet. Die Daten werden nur lokal "
                "in ~/.config/film-browser/config.json gespeichert."
            )
        )
        info.set_line_wrap(True)
        info.set_xalign(0)
        box.pack_start(info, False, False, 0)

        grid = Gtk.Grid(column_spacing=10, row_spacing=8)
        box.pack_start(grid, False, False, 0)

        key_entry = Gtk.Entry()
        key_entry.set_text(self.tmdb_api_key)
        key_entry.set_visibility(False)
        token_entry = Gtk.Entry()
        token_entry.set_text(self.tmdb_read_token)
        token_entry.set_visibility(False)

        grid.attach(Gtk.Label(label="API-Key (v3):", xalign=0), 0, 0, 1, 1)
        grid.attach(key_entry, 1, 0, 1, 1)
        grid.attach(Gtk.Label(label="Read Access Token:", xalign=0), 0, 1, 1, 1)
        grid.attach(token_entry, 1, 1, 1, 1)

        show_box = Gtk.CheckButton(label="Zugangsdaten anzeigen")
        show_box.connect(
            "toggled",
            lambda button: (
                key_entry.set_visibility(button.get_active()),
                token_entry.set_visibility(button.get_active()),
            ),
        )
        box.pack_start(show_box, False, False, 0)
        dialog.show_all()

        while True:
            response = dialog.run()
            if response != Gtk.ResponseType.OK:
                dialog.destroy()
                return

            api_key = key_entry.get_text().strip()
            read_token = token_entry.get_text().strip()
            ok, message = self.test_tmdb_access(api_key, read_token)
            result = Gtk.MessageDialog(
                transient_for=dialog,
                message_type=Gtk.MessageType.INFO if ok else Gtk.MessageType.ERROR,
                buttons=Gtk.ButtonsType.OK,
                text="TMDb-Test erfolgreich" if ok else "TMDb-Test fehlgeschlagen",
            )
            result.format_secondary_text(message)
            result.run()
            result.destroy()
            if ok:
                self.tmdb_api_key = api_key
                self.tmdb_read_token = read_token
                self.save_config()
                self.status_label.set_text("TMDb-Zugang wurde getestet und lokal gespeichert.")
                dialog.destroy()
                return

