    def cleanup_orphan_thumbnails(self):
        expected = {
            record["thumbnail"]
            for record in self.library_records.values()
            if record.get("thumbnail")
        }
        expected.update(
            f"series-{mapping.get('tmdb_id')}.jpg"
            for mapping in self.series_folder_mappings.values()
            if mapping.get("tmdb_id")
        )

        # Staffelbilder gehören ebenfalls zum gültigen Cache. Die erwarteten
        # Namen werden aus den tatsächlich vorhandenen Staffelordnern der
        # Bibliothek abgeleitet, damit veraltete Bilder später bereinigt werden.
        season_images = set()
        for video in self.videos:
            mapping = self.get_series_folder_mapping(video)
            if not mapping or not mapping.get("tmdb_id"):
                continue
            mapped_root = Path(mapping["folder"])
            for parent in video.parents:
                if parent == mapped_root.parent:
                    break
                season_number = self.inferred_season_number_for_folder(parent)
                if season_number is not None:
                    season_images.add(
                        f"season-{mapping.get('tmdb_id')}-{season_number}.jpg"
                    )
                    break
        expected.update(season_images)
        removed = 0
        try:
            for path in self.thumb_cache.iterdir():
                if not path.is_file():
                    continue
                if path.suffix == ".jpg" and path.name not in expected:
                    path.unlink()
                    removed += 1
                elif path.name.endswith(".tmp.jpg"):
                    path.unlink()
                    removed += 1
        except OSError:
            pass
        if removed:
            self.pixbuf_cache.clear()
        return removed

    def on_cleanup_cache(self, _widget):
        removed = self.cleanup_orphan_thumbnails()
        self.status_label.set_text(
            f"{removed} verwaiste Vorschaubilder wurden entfernt."
            if removed else "Keine verwaisten Vorschaubilder gefunden."
        )
        self.progress_bar.set_fraction(1.0)
        self.progress_bar.set_text("Cache geprüft")

    def on_clear_cache(self, _widget):
        dialog = Gtk.MessageDialog(
            transient_for=self,
            message_type=Gtk.MessageType.QUESTION,
            buttons=Gtk.ButtonsType.YES_NO,
            text="Vorschaubilder-Cache vollständig leeren?",
        )
        dialog.format_secondary_text(
            "Die Videodateien und der Bibliotheksindex bleiben unverändert. "
            "Vorschaubilder werden bei der nächsten Anzeige neu erzeugt."
        )
        response = dialog.run()
        dialog.destroy()
        if response != Gtk.ResponseType.YES:
            return
        try:
            shutil.rmtree(self.thumb_cache)
            self.thumb_cache.mkdir(parents=True, exist_ok=True)
            self.pixbuf_cache.clear()
            self.status_label.set_text("Vorschaubilder-Cache wurde vollständig geleert.")
            self.progress_bar.set_fraction(0.0)
            self.progress_bar.set_text("Cache geleert")
            self.refresh_visible_videos()
        except OSError as exc:
            self.show_error(f"Cache konnte nicht geleert werden:\n{exc}")

