    def on_show_last_scan_report(self, _widget):
        if not self.last_scan_report:
            text = "In dieser Sitzung wurde noch kein Bibliotheksabgleich durchgeführt."
        else:
            report = self.last_scan_report
            lines = [
                f"Neu: {len(report['new'])}",
                f"Verschoben/umbenannt: {len(report['moved'])}",
                f"Geändert: {len(report['changed'])}",
                f"Entfernt: {len(report['removed'])}",
                f"Unverändert: {len(report['unchanged'])}",
            ]
            details = []
            for old, new in report["moved"][:10]:
                details.append(f"{old}\n→ {new}")
            if details:
                lines.extend(["", "Erkannte Verschiebungen/Umbenennungen:", *details])
            text = "\n".join(lines)

        dialog = Gtk.MessageDialog(
            transient_for=self,
            message_type=Gtk.MessageType.INFO,
            buttons=Gtk.ButtonsType.OK,
            text="Letzter Bibliotheksabgleich",
        )
        dialog.format_secondary_text(text)
        dialog.run()
        dialog.destroy()

    def find_bundled_help_file(self):
        """Findet die mit Skript, DEB oder AppImage ausgelieferte HTML-Hilfe."""
        relative_candidates = (
            Path(HELP_FILE_NAME),
            Path("help") / HELP_FILE_NAME,
            Path("share") / APP_SLUG / "help" / HELP_FILE_NAME,
        )
        for relative_path in relative_candidates:
            for candidate in self.package_resource_candidates(relative_path):
                if candidate.is_file():
                    return candidate
        return None

    def ensure_help_file(self):
        """Übernimmt die paketierte Hilfe atomar ins Benutzerprofil."""
        bundled_help = self.find_bundled_help_file()
        temp_file = self.help_file.with_suffix(".html.tmp")
        try:
            if bundled_help is not None:
                html_text = (
                    bundled_help.read_text(encoding="utf-8")
                    .replace("{{APP_VERSION}}", APP_VERSION)
                    .replace("{{APP_ICON_DATA_URI}}", APP_ICON_DATA_URI)
                    .replace("{{COPYRIGHT_HOLDER}}", COPYRIGHT_HOLDER)
                )
            else:
                # Eingebetteter Fallback hält F1 selbst bei einer unvollständigen
                # manuellen Kopie der Python-Datei funktionsfähig.
                html_text = (
                    HELP_HTML_TEMPLATE
                    .replace("{{APP_VERSION}}", APP_VERSION)
                    .replace("{{APP_ICON_DATA_URI}}", APP_ICON_DATA_URI)
                    .replace("{{COPYRIGHT_HOLDER}}", COPYRIGHT_HOLDER)
                )

            current = (
                self.help_file.read_text(encoding="utf-8")
                if self.help_file.exists()
                else None
            )
            if current != html_text:
                temp_file.write_text(html_text, encoding="utf-8")
                temp_file.replace(self.help_file)
                self.protect_private_file(self.help_file)
            return self.help_file
        except OSError as exc:
            self.log_error("Hilfedatei konnte nicht bereitgestellt werden", exc)
            try:
                temp_file.unlink(missing_ok=True)
            except OSError:
                pass
            return None

    def on_open_help(self, _widget=None):
        """Öffnet die vollständige lokale Hilfe im Standardbrowser."""
        help_file = self.ensure_help_file()
        if help_file is None:
            self.show_error("Die Hilfedatei konnte nicht erzeugt werden.")
            return
        try:
            subprocess.Popen(
                ["xdg-open", str(help_file)],
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                start_new_session=True,
            )
            self.status_label.set_text(f"Hilfe geöffnet: {help_file}")
        except OSError as exc:
            self.show_error(f"Hilfe konnte nicht geöffnet werden:\n{exc}")

