    @staticmethod
    def pretty_title(video_path):
        title = Path(video_path).stem.replace(".", " ").replace("_", " ")
        return re.sub(r"\s+", " ", title).strip()

    def clear_flowbox(self):
        for child in self.flowbox.get_children():
            self.flowbox.remove(child)

    def show_error(self, message):
        self.log_error("Benutzer sichtbarer Fehler", details=str(message))
        dialog = Gtk.MessageDialog(
            transient_for=self,
            message_type=Gtk.MessageType.ERROR,
            buttons=Gtk.ButtonsType.OK,
            text="Fehler",
        )
        dialog.format_secondary_text(message)
        dialog.run()
        dialog.destroy()
        return False

    def on_configure_event(self, _widget, _event):
        self.window_width, self.window_height = self.get_size()
        return False

    def on_destroy(self, _widget):
        self.logger.info("Anwendung wird beendet.")
        if self.config_save_source_id is not None:
            try:
                GLib.source_remove(self.config_save_source_id)
            except GLib.Error:
                pass
            self.config_save_source_id = None
        self.cancel_event.set()
        with self.active_process_lock:
            process = self.active_process
        if process is not None and process.poll() is None:
            try:
                os.killpg(process.pid, signal.SIGKILL)
            except (ProcessLookupError, PermissionError):
                pass
        self.save_config()
        self.save_index(show_errors=False)
        self.executor.shutdown(wait=False, cancel_futures=True)
        self.pixbuf_cache.clear()
        Gtk.main_quit()


