_INSTANCE_LOCK_HANDLE = None


def acquire_single_instance_lock():
    """Verhindert zuverlässig einen zweiten parallelen Carbor-Prozess."""
    global _INSTANCE_LOCK_HANDLE
    data_home = Path(
        os.environ.get(
            "XDG_DATA_HOME",
            Path.home() / ".local" / "share",
        )
    ).expanduser()
    lock_dir = data_home / "film-browser"
    lock_dir.mkdir(parents=True, exist_ok=True)
    lock_path = lock_dir / "film-browser.lock"
    handle = lock_path.open("a+", encoding="utf-8")
    try:
        fcntl.flock(handle.fileno(), fcntl.LOCK_EX | fcntl.LOCK_NB)
    except BlockingIOError:
        handle.close()
        return False
    handle.seek(0)
    handle.truncate()
    handle.write(str(os.getpid()))
    handle.flush()
    _INSTANCE_LOCK_HANDLE = handle
    return True


def main():
    # Programmnamen früh setzen, damit Fenstermanager und Desktop-Umgebung
    # bereits beim ersten sichtbaren Fenster den richtigen Namen verwenden.
    try:
        GLib.set_prgname(APP_SLUG)
        GLib.set_application_name(APP_NAME)
    except (AttributeError, TypeError):
        pass

    if not acquire_single_instance_lock():
        dialog = Gtk.MessageDialog(
            transient_for=None,
            message_type=Gtk.MessageType.INFO,
            buttons=Gtk.ButtonsType.OK,
            text="Carbor kann nur in einer Instanz laufen",
        )
        dialog.format_secondary_text(
            "Carbor kann nur in einer Instanz laufen."
        )
        dialog.run()
        dialog.destroy()
        return
    window = CarborApp()
    window.show_all()
    window.update_film_menu_state()
    try:
        Gtk.main()
    except KeyboardInterrupt:
        window.save_config()
        window.save_index(show_errors=False)


if __name__ == "__main__":
    main()
